/// Immutable, compiler-resolved contract for one command execution. Dynamic
/// commands are never resolved by scanning the whole graph: the selected
/// source, argv, ticket scope, filesystem inputs, and dynamic result
/// requirements are captured together and compared before and after spawn.
#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
struct ResolvedCheckExecution {
    schema_version: String,
    profile_hash: String,
    check_id: String,
    source_kind: String,
    source_role: String,
    source_id: String,
    source_node_type: Option<String>,
    source_field: String,
    source_semantic_hash: String,
    cwd: String,
    argv: Vec<String>,
    command_hash: String,
    environment_policy_hash: String,
    environment_bindings: BTreeMap<String, String>,
    executable: ExecutableBinding,
    sandbox_executable: Option<ExecutableBinding>,
    sandbox_profile_hash: Option<String>,
    private_temp_required: bool,
    target_bindings: BTreeMap<String, SemanticCommandBinding>,
    read_scope_bindings: BTreeMap<String, SemanticCommandBinding>,
    read_path_manifest: Vec<Value>,
    read_path_exclusions: Vec<CommandPathExclusion>,
    produced_path_roots: Vec<String>,
    argv_input_rows: Vec<Value>,
    dynamic_requirements: Value,
    result_path: Option<String>,
    gate_policy_binding: Option<GatePolicyBinding>,
    binding_hash: String,
}

