/// Aggregate Codex usage for every completed model turn owned by one run.
///
/// Cached input and reasoning output are retained as useful breakdowns, but
/// they are already included in `input_tokens` and `output_tokens`. Therefore
/// `total_tokens` is deliberately input plus output, without double counting
/// either nested category.
#[derive(Debug, Clone, Copy, Default, Serialize, Deserialize, PartialEq, Eq)]
pub struct RunTokenUsage {
    pub input_tokens: u64,
    pub cached_input_tokens: u64,
    pub output_tokens: u64,
    pub reasoning_output_tokens: u64,
    pub total_tokens: u64,
    pub completed_turns: u64,
}

