const QUESTION_PAUSES_EXTENSION: &str = "question_pauses";
const QUESTION_RESUME_STATUS_KEY: &str = "__resume_status";
const LEAD_SLICE_TOKEN_ENV: &str = "KONI_LEAD_SLICE_TOKEN";
const LEAD_SLICE_GENERATION_ENV: &str = "KONI_LEAD_SLICE_GENERATION";
const AGENT_MCP_SERVER_ID: &str = "koni_runtime";
const AGENT_MCP_TOOL_TIMEOUT_SECONDS: u64 = 3_660;
const DEFAULT_BROKER_WORKER_PROMPT: &str =
    "Continue the next dependency-ready ticket step from the compiled context.";
const LEAD_BROKER_PROTOCOL: &str = "This is one compiler-enforced fresh Lead slice. Use only the enabled `koni_runtime` MCP tools named by the compiler-issued Lead packet. Do not call `inspect`, scan configuration, invoke Koni through the shell, resume an earlier Codex transcript, ask a question in this release, or perform a second broker boundary. Do not use ambient collaboration/subagent tools. A dispatch batch consists only of `koni_runtime.start` then `koni_runtime.spawn_worker` for every listed ticket. A wait boundary consists only of `koni_runtime.wait_worker`; ordinary timeouts may repeat that same wait. Recovery uses only `koni_runtime.recover`. Ticket review is compiler-owned and synchronous through `koni_runtime.review`; never supply a verdict. When the packet boundary is complete, call `koni_runtime.yield_lead` with reason `boundary-complete` and stop. If scheduling is paused, use reason `paused`. Missing, stale, forged, premature, duplicate, or question-shaped yield is rejected, and a zero exit without an accepted yield blocks supervision after any question session is resolved.";

thread_local! {
    static BROKER_LEAD_CAPABILITY: RefCell<Option<LeadIngressCapability>> = const { RefCell::new(None) };
}

#[derive(Debug, Clone)]
enum LeadIngressCapability {
    LegacyToken {
        token: String,
        generation: u64,
    },
    BrokerGrant {
        grant_id: String,
        agent_id: String,
        generation: u64,
    },
}

struct BrokerLeadCapabilityGuard;

impl Drop for BrokerLeadCapabilityGuard {
    fn drop(&mut self) {
        BROKER_LEAD_CAPABILITY.with(|capability| *capability.borrow_mut() = None);
    }
}

fn with_broker_lead_capability<T>(
    grant_id: &str,
    agent_id: &str,
    generation: u64,
    operation: impl FnOnce() -> Result<T>,
) -> Result<T> {
    BROKER_LEAD_CAPABILITY.with(|capability| {
        let mut capability = capability.borrow_mut();
        if capability.is_some() {
            return Err(KoniError::Process(
                "nested runtime MCP Lead capability is forbidden".to_owned(),
            ));
        }
        *capability = Some(LeadIngressCapability::BrokerGrant {
            grant_id: grant_id.to_owned(),
            agent_id: agent_id.to_owned(),
            generation,
        });
        Ok(())
    })?;
    let _guard = BrokerLeadCapabilityGuard;
    operation()
}

fn lead_slice_ingress() -> Result<Option<LeadIngressCapability>> {
    if let Some(capability) = BROKER_LEAD_CAPABILITY.with(|value| value.borrow().clone()) {
        return Ok(Some(capability));
    }
    let token = std::env::var(LEAD_SLICE_TOKEN_ENV).ok();
    let generation = std::env::var(LEAD_SLICE_GENERATION_ENV).ok();
    match (token, generation) {
        (None, None) => Ok(None),
        (Some(token), Some(generation)) => {
            let generation = generation.parse::<u64>().map_err(|_| {
                KoniError::Action("invalid compiler-owned Lead slice environment".to_owned())
            })?;
            Ok(Some(LeadIngressCapability::LegacyToken {
                token,
                generation,
            }))
        }
        _ => Err(KoniError::Action(
            "incomplete compiler-owned Lead slice environment".to_owned(),
        )),
    }
}

fn process_parent(pid: u32) -> Option<u32> {
    let output = Command::new("/bin/ps")
        .args(["-o", "ppid=", "-p", &pid.to_string()])
        .stdin(Stdio::null())
        .stderr(Stdio::null())
        .output()
        .ok()?;
    output
        .status
        .success()
        .then_some(output.stdout)
        .and_then(|bytes| String::from_utf8(bytes).ok())?
        .trim()
        .parse()
        .ok()
}

fn caller_descends_from(expected: &AgentProcessIdentity) -> bool {
    if !owned_agent_process_is_alive(expected) {
        return false;
    }
    let mut pid = std::process::id();
    for _ in 0..32 {
        if pid == expected.pid {
            return true;
        }
        let Some(parent) = process_parent(pid) else {
            return false;
        };
        if parent == 0 || parent == pid {
            return false;
        }
        pid = parent;
    }
    false
}

fn validate_lead_slice_ingress(
    state: &LeadSliceState,
    capability: &LeadIngressCapability,
    caller_is_descendant: bool,
) -> Result<()> {
    let (generation, credential_matches) = match capability {
        LeadIngressCapability::LegacyToken { token, generation } => {
            (*generation, state.token_hash == normalized_hash(token))
        }
        LeadIngressCapability::BrokerGrant {
            grant_id,
            agent_id,
            generation,
        } => (
            *generation,
            !grant_id.is_empty() && state.raw_agent_id.as_deref() == Some(agent_id.as_str()),
        ),
    };
    if state.status != LeadSliceStatus::Active
        || state.generation != generation
        || !credential_matches
        || state.process_identity.is_none()
        || !caller_is_descendant
    {
        return Err(KoniError::Action(
            "Lead slice ingress rejected a stale, forged, or unowned lease".to_owned(),
        ));
    }
    Ok(())
}

fn validate_lead_yield_reason(
    state: &LeadSliceState,
    reason: &str,
    orchestration_running: bool,
    _has_bound_question: bool,
) -> Result<()> {
    match reason {
        "boundary-complete" if state.boundaries_completed > 0 => Ok(()),
        "paused" if !orchestration_running => Ok(()),
        "boundary-complete" => Err(KoniError::Action(
            "Lead cannot yield before its compiler-counted boundary completes".to_owned(),
        )),
        "paused" => Err(KoniError::Action(
            "Lead cannot claim a pause while automatic scheduling is running".to_owned(),
        )),
        "question" => Err(KoniError::Action(
            "a structured question is resumable session state and cannot masquerade as a Lead yield"
                .to_owned(),
        )),
        _ => Err(KoniError::Action(
            "yield reason must be boundary-complete or paused".to_owned(),
        )),
    }
}

fn lead_slice_exit_allows_respawn(
    slice: &LeadSliceState,
    raw: Option<&AgentSessionRecord>,
) -> bool {
    slice.status == LeadSliceStatus::Yielded
        && raw.is_some_and(|raw| {
            raw.status == "completed" && raw.exit_code.is_none_or(|exit_code| exit_code == 0)
        })
}

fn action_matches(engine: &Engine, action: &ActionDef, alias: &str) -> bool {
    engine
        .profile
        .action(alias)
        .map(|resolved| resolved.id.as_str())
        == Some(action.id.as_str())
}

fn lead_action_key(action: &str, ticket: Option<&str>) -> String {
    ticket.map_or_else(|| action.to_owned(), |ticket| format!("{action}:{ticket}"))
}

fn authorize_lead_slice_action(
    engine: &Engine,
    state: &mut LeadSliceState,
    action: &ActionDef,
    ticket: Option<&str>,
) -> Result<()> {
    let operation = if action_matches(engine, action, "start") {
        "start"
    } else if action_matches(engine, action, "spawn-worker") {
        "spawn-worker"
    } else if action_matches(engine, action, "recover") {
        "recover"
    } else if action_matches(engine, action, "finish") {
        "finish"
    } else {
        return Err(KoniError::Action(format!(
            "action {} is outside this compiler-issued Lead boundary",
            action.id
        )));
    };
    authorize_lead_slice_operation(state, operation, ticket)
}

fn authorize_lead_slice_operation(
    state: &mut LeadSliceState,
    operation: &str,
    ticket: Option<&str>,
) -> Result<()> {
    if state.boundaries_completed >= state.max_boundaries {
        return Err(KoniError::Action(
            "this Lead slice already completed its compiler-counted boundary; yield now".to_owned(),
        ));
    }
    let key = lead_action_key(operation, ticket);
    if state.actions.contains(&key) {
        return Err(KoniError::Action(format!(
            "Lead slice action {key} was already consumed"
        )));
    }
    let completed = match &state.boundary {
        LeadSliceBoundary::DispatchBatch { tickets } => {
            let ticket = ticket.ok_or_else(|| {
                KoniError::Action("dispatch action requires its issued ticket".to_owned())
            })?;
            if !tickets.iter().any(|issued| issued == ticket) {
                return Err(KoniError::Action(format!(
                    "ticket {ticket} is outside this compiler-issued dispatch batch"
                )));
            }
            let next = tickets.iter().find(|issued| {
                !state
                    .actions
                    .contains(&lead_action_key("spawn-worker", Some(issued)))
            });
            if next.map(String::as_str) != Some(ticket) {
                return Err(KoniError::Action(format!(
                    "ticket {ticket} is out of compiler-issued dispatch order"
                )));
            }
            if key.starts_with("spawn-worker:")
                && !state
                    .actions
                    .contains(&lead_action_key("start", Some(ticket)))
            {
                return Err(KoniError::Action(format!(
                    "ticket {ticket} must be started before its worker is spawned"
                )));
            }
            if !key.starts_with("start:") && !key.starts_with("spawn-worker:") {
                return Err(KoniError::Action(
                    "only start and spawn-worker are allowed in a dispatch batch".to_owned(),
                ));
            }
            state.actions.push(key);
            tickets.iter().all(|issued| {
                state
                    .actions
                    .contains(&lead_action_key("spawn-worker", Some(issued)))
            })
        }
        LeadSliceBoundary::Recover if key == "recover" => {
            state.actions.push(key);
            true
        }
        LeadSliceBoundary::SpawnWorker { ticket: issued }
            if ticket == Some(issued.as_str()) && key.starts_with("spawn-worker:") =>
        {
            state.actions.push(key);
            true
        }
        LeadSliceBoundary::Finish { ticket: issued }
            if ticket == Some(issued.as_str()) && key.starts_with("finish:") =>
        {
            state.actions.push(key);
            true
        }
        LeadSliceBoundary::Review { ticket: issued }
            if ticket == Some(issued.as_str()) && key.starts_with("review:") =>
        {
            state.actions.push(key);
            true
        }
        _ => {
            return Err(KoniError::Action(
                "this action does not match the compiler-issued Lead boundary".to_owned(),
            ));
        }
    };
    if completed {
        state.boundaries_completed += 1;
    }
    state.updated_at = Utc::now();
    Ok(())
}

#[allow(dead_code)]
fn attach_question_process_log(command: &mut Command, path: &Path) -> Result<()> {
    let stdout = fs::OpenOptions::new()
        .create(true)
        .append(true)
        .open(path)
        .map_err(|error| io_error(path, error))?;
    let stderr = stdout.try_clone().map_err(|error| io_error(path, error))?;
    command
        .stdout(Stdio::from(stdout))
        .stderr(Stdio::from(stderr));
    Ok(())
}

#[allow(dead_code)]
fn launch_question_process(
    mut command: Command,
) -> std::result::Result<(std::process::Child, Option<i32>), String> {
    let mut child = command.spawn().map_err(|error| error.to_string())?;
    // Catch command-line/session failures that Codex reports immediately while
    // keeping the actual resumed turn asynchronous.
    std::thread::sleep(Duration::from_millis(75));
    match child.try_wait().map_err(|error| error.to_string())? {
        Some(status) if status.success() => Ok((child, status.code().or(Some(0)))),
        Some(status) => Err(format!("process exited during startup with {status}")),
        None => Ok((child, None)),
    }
}

#[allow(dead_code)]
fn reap_question_resume_process(
    mut child: std::process::Child,
    control: RunControlStore,
    agent_id: String,
    attempt: u32,
    identity: AgentProcessIdentity,
    authority: Option<(PathBuf, String)>,
) {
    thread::spawn(move || {
        let waited = child.wait();
        let _authority_barrier = if let Some((project_root, run_id)) = authority {
            let Ok(barrier) = acquire_registered_run_barrier(&project_root, &run_id) else {
                return;
            };
            Some(barrier)
        } else {
            None
        };
        let now = Utc::now();
        let Ok(Some(mut agent)) = control.agent(&agent_id) else {
            return;
        };
        // A newer idempotent attempt owns the same record. Never let an older
        // waiter overwrite it when its process eventually exits.
        if agent.attempt != attempt || agent.process_identity.as_ref() != Some(&identity) {
            return;
        }
        match waited {
            Ok(status) => {
                agent.exit_code = status.code();
                agent.status = if status.success() {
                    "completed".to_owned()
                } else {
                    "failed".to_owned()
                };
                merge_question_resume_result(
                    &mut agent,
                    "exit_code",
                    status.code().map_or(Value::Null, Value::from),
                );
            }
            Err(error) => {
                agent.status = "supervision_failed".to_owned();
                merge_question_resume_result(
                    &mut agent,
                    "supervision_error",
                    Value::String(error.to_string()),
                );
            }
        }
        agent.finished_at = Some(now);
        agent.updated_at = now;
        let _ = control.write_agent(&agent);
    });
}

#[allow(dead_code)]
fn merge_question_resume_result(agent: &mut AgentSessionRecord, key: &str, value: Value) {
    let mut result = agent
        .result
        .take()
        .and_then(|value| value.as_object().cloned())
        .unwrap_or_default();
    result.insert(key.to_owned(), value);
    agent.result = Some(Value::Object(result));
}

#[allow(dead_code)]
fn question_originating_stage_id(
    control: &RunControlStore,
    question: &QuestionRecord,
) -> Result<Option<String>> {
    let explicit = question
        .session_resume
        .agent_id
        .as_deref()
        .map(|origin| control.agent(origin))
        .transpose()?
        .flatten()
        .and_then(|agent| agent.stage_id);
    if explicit.is_some() {
        return Ok(explicit);
    }
    Ok(control.pipeline()?.and_then(|pipeline| {
        pipeline
            .current()
            .filter(|stage| {
                stage.definition.kind == crate::pipeline::PipelineStageKind::Orchestration
            })
            .map(|stage| stage.definition.id.clone())
    }))
}

fn launch_and_persist_question_resume(
    _control: &RunControlStore,
    _project_root: &Path,
    _run_id: &str,
    question: &QuestionRecord,
) -> Result<AnsweredQuestion> {
    Err(KoniError::Action(format!(
        "question {} belongs to the retired unbrokered Lead-question protocol; Koni refuses to resume it because that would relaunch Codex outside the compiler-owned MCP authority boundary",
        question.id
    )))
}

fn answered_question_from_agent(
    question: &QuestionRecord,
    agent: &AgentSessionRecord,
) -> Result<AnsweredQuestion> {
    Ok(AnsweredQuestion {
        directive: resume_directive(question)?,
        worker_pid: Some(agent.pid.ok_or_else(|| {
            KoniError::Workflow(format!("question {} resume worker has no PID", question.id))
        })?),
        resumed_same_session: agent
            .result
            .as_ref()
            .and_then(|value| value.get("resumed_same_session"))
            .and_then(Value::as_bool)
            .unwrap_or(false),
        resume_deferred: false,
        remaining_questions: 0,
    })
}

fn ensure_question_answer_matches(
    question: &QuestionRecord,
    option_id: Option<&str>,
    custom_answer: Option<&str>,
) -> Result<()> {
    let answer = question.answer.as_ref().ok_or_else(|| {
        KoniError::Workflow(format!(
            "question {} has resume-pending status without an answer",
            question.id
        ))
    })?;
    if answer.option_id.as_deref() != option_id || answer.custom.as_deref() != custom_answer {
        return Err(KoniError::Workflow(format!(
            "question {} already has a different durable answer",
            question.id
        )));
    }
    Ok(())
}

fn apply_ticket_question_pause(
    project_root: &Path,
    run_id: &str,
    ticket_id: &str,
    question_id: &str,
) -> Result<()> {
    let engine = Engine::open_run(project_root, run_id)?;
    let store = engine.store()?.clone();
    let mut ticket = store.ticket(ticket_id)?;
    let previous = ticket.status.clone();
    let pauses = ticket
        .extensions
        .entry(QUESTION_PAUSES_EXTENSION.to_owned())
        .or_insert_with(|| Value::Object(Map::new()))
        .as_object_mut()
        .ok_or_else(|| {
            KoniError::Workflow("ticket question_pauses extension is not an object".to_owned())
        })?;
    if !pauses.contains_key(QUESTION_RESUME_STATUS_KEY) {
        let resume_status = if previous == "awaiting_input" && !pauses.is_empty() {
            pauses
                .values()
                .filter_map(Value::as_str)
                .find(|status| *status != "awaiting_input")
                .unwrap_or("awaiting_input")
                .to_owned()
        } else {
            previous
        };
        pauses.insert(
            QUESTION_RESUME_STATUS_KEY.to_owned(),
            Value::String(resume_status),
        );
    }
    pauses.insert(question_id.to_owned(), Value::Bool(true));
    ticket.status = "awaiting_input".to_owned();
    store.write_ticket(&ticket)
}

fn release_question_pause(
    project_root: &Path,
    run_id: &str,
    question: &QuestionRecord,
) -> Result<()> {
    let QuestionPauseScope::Ticket { ticket_id, .. } = &question.pause_scope else {
        return Ok(());
    };
    let engine = Engine::open_run(project_root, run_id)?;
    let store = engine.store()?.clone();
    let control = run_control_store(project_root, run_id)?;
    let remaining = control.questions()?.into_iter().any(|candidate| {
        candidate.id != question.id
            && candidate.is_pause_active()
            && candidate.pause_scope.ticket_id() == Some(ticket_id.as_str())
    });
    let mut ticket = store.ticket(ticket_id)?;
    let resume_status = ticket
        .extensions
        .get_mut(QUESTION_PAUSES_EXTENSION)
        .and_then(Value::as_object_mut)
        .and_then(|pauses| {
            pauses.remove(&question.id);
            pauses
                .get(QUESTION_RESUME_STATUS_KEY)
                .and_then(Value::as_str)
                .map(ToOwned::to_owned)
                .or_else(|| {
                    pauses
                        .values()
                        .filter_map(Value::as_str)
                        .find(|status| *status != "awaiting_input")
                        .map(ToOwned::to_owned)
                })
        })
        .unwrap_or_else(|| "in_progress".to_owned());
    if remaining {
        ticket.status = "awaiting_input".to_owned();
    } else {
        ticket.extensions.remove(QUESTION_PAUSES_EXTENSION);
        ticket.status = resume_status;
    }
    store.write_ticket(&ticket)
}

fn ensure_no_run_question_pause(control: &RunControlStore, run_id: &str) -> Result<()> {
    if let Some(question) = control.questions()?.into_iter().find(|question| {
        question.is_pause_active()
            && matches!(&question.pause_scope, QuestionPauseScope::Run { run_id: owner } if owner == run_id)
    }) {
        return Err(KoniError::Action(format!(
            "run {run_id} is paused awaiting answer to question {}",
            question.id
        )));
    }
    Ok(())
}

