struct ApprovedPlanningStage {
    stage_id: String,
    title: String,
    output: String,
    output_hash: String,
    original_bytes: usize,
    truncated: bool,
}

#[derive(Debug, Clone, Serialize, Deserialize, PartialEq, Eq)]
struct ApprovedPlanningDecision {
    prompt: String,
    context: String,
    answer: String,
    source: String,
    truncated: bool,
}

#[derive(Debug, Clone, Serialize, Deserialize, PartialEq, Eq)]
struct ApprovedPlanningContext {
    schema_version: String,
    stages: Vec<ApprovedPlanningStage>,
    decisions: Vec<ApprovedPlanningDecision>,
    omitted_decisions: usize,
    context_hash: String,
}

impl ApprovedPlanningContext {
    fn new(
        stages: Vec<ApprovedPlanningStage>,
        decisions: Vec<ApprovedPlanningDecision>,
        omitted_decisions: usize,
    ) -> Self {
        let context_hash = normalized_hash(&json!({
            "schema_version": "1.0",
            "stages": &stages,
            "decisions": &decisions,
            "omitted_decisions": omitted_decisions,
        }));
        Self {
            schema_version: "1.0".to_owned(),
            stages,
            decisions,
            omitted_decisions,
            context_hash,
        }
    }
}

impl PlanningQuestionRequest {
    fn validate(&self) -> Result<()> {
        if self.prompt.trim().is_empty() {
            return Err(KoniError::Process(
                "planning question prompt must not be blank".to_owned(),
            ));
        }
        if self.context.trim().is_empty() {
            return Err(KoniError::Process(
                "planning question context must not be blank".to_owned(),
            ));
        }
        if !(2..=4).contains(&self.options.len()) {
            return Err(KoniError::Process(
                "planning question requires between two and four options".to_owned(),
            ));
        }
        for option in &self.options {
            if option.label.trim().is_empty() || option.description.trim().is_empty() {
                return Err(KoniError::Process(
                    "planning question option labels and descriptions must not be blank".to_owned(),
                ));
            }
        }
        if self
            .options
            .iter()
            .filter(|option| option.recommended)
            .count()
            != 1
        {
            return Err(KoniError::Process(
                "planning question must recommend exactly one option".to_owned(),
            ));
        }
        Ok(())
    }
}

fn normalized_planning_question_prompt(prompt: &str) -> String {
    prompt
        .split_whitespace()
        .collect::<Vec<_>>()
        .join(" ")
        .to_lowercase()
}

fn validate_planning_question_batch(questions: &[PlanningQuestionRequest]) -> Result<()> {
    if !(1..=3).contains(&questions.len()) {
        return Err(KoniError::Process(
            "planning question batch requires between one and three questions".to_owned(),
        ));
    }
    let mut prompts = BTreeSet::new();
    for question in questions {
        question.validate()?;
        let normalized = normalized_planning_question_prompt(&question.prompt);
        if !prompts.insert(normalized) {
            return Err(KoniError::Process(
                "planning question batch contains duplicate normalized prompts".to_owned(),
            ));
        }
    }
    Ok(())
}

fn planning_question_schema() -> Value {
    json!({
        "type": "object",
        "additionalProperties": false,
        "required": ["prompt", "context", "impact", "options"],
        "properties": {
            "prompt": {"type": "string"},
            "context": {"type": "string"},
            "impact": {"enum": ["routine", "high"]},
            "options": {
                "type": "array",
                "items": {
                    "type": "object",
                    "additionalProperties": false,
                    "required": ["label", "description", "recommended"],
                    "properties": {
                        "label": {"type": "string"},
                        "description": {"type": "string"},
                        "recommended": {"type": "boolean"}
                    }
                }
            }
        }
    })
}

fn planning_agent_output_schema() -> Value {
    let question = planning_question_schema();
    json!({
        "$schema": "https://json-schema.org/draft/2020-12/schema",
        "type": "object",
        "additionalProperties": false,
        "required": ["kind", "plan", "prompt", "context", "impact", "options", "questions"],
        "properties": {
            "kind": {"enum": ["plan", "question", "questions"]},
            "plan": {"type": ["string", "null"]},
            "prompt": {"type": ["string", "null"]},
            "context": {"type": ["string", "null"]},
            "impact": {"enum": ["routine", "high", null]},
            "options": {
                "type": ["array", "null"],
                "items": {
                    "type": "object",
                    "additionalProperties": false,
                    "required": ["label", "description", "recommended"],
                    "properties": {
                        "label": {"type": "string"},
                        "description": {"type": "string"},
                        "recommended": {"type": "boolean"}
                    }
                }
            },
            "questions": {
                "type": ["array", "null"],
                "minItems": 1,
                "maxItems": 3,
                "items": question
            }
        }
    })
}

fn parse_planning_agent_output(output: &str) -> Result<PlanningAgentOutputEnvelope> {
    #[derive(Deserialize)]
    #[serde(deny_unknown_fields)]
    struct WireOutput {
        kind: String,
        #[serde(default)]
        plan: Option<String>,
        #[serde(default)]
        prompt: Option<String>,
        #[serde(default)]
        context: Option<String>,
        #[serde(default)]
        impact: Option<QuestionImpact>,
        #[serde(default)]
        options: Option<Vec<PlanningQuestionOption>>,
        #[serde(default)]
        questions: Option<Vec<PlanningQuestionRequest>>,
    }

    let wire: WireOutput = serde_json::from_str(output.trim()).map_err(|error| {
        KoniError::Process(format!(
            "planning agent returned invalid structured output: {error}"
        ))
    })?;
    let envelope = match wire.kind.as_str() {
        "plan" => {
            if wire.prompt.is_some()
                || wire.context.is_some()
                || wire.impact.is_some()
                || wire.options.is_some()
                || wire.questions.is_some()
            {
                return Err(KoniError::Process(
                    "completed planning output contains question fields".to_owned(),
                ));
            }
            PlanningAgentOutputEnvelope::Plan {
                plan: wire.plan.ok_or_else(|| {
                    KoniError::Process("completed planning output is missing its plan".to_owned())
                })?,
            }
        }
        "question" => {
            if wire.plan.is_some() || wire.questions.is_some() {
                return Err(KoniError::Process(
                    "planning question output contains fields for another output kind".to_owned(),
                ));
            }
            PlanningAgentOutputEnvelope::Question(PlanningQuestionRequest {
                prompt: wire.prompt.ok_or_else(|| {
                    KoniError::Process("planning question output is missing its prompt".to_owned())
                })?,
                context: wire.context.ok_or_else(|| {
                    KoniError::Process("planning question output is missing its context".to_owned())
                })?,
                impact: wire.impact.ok_or_else(|| {
                    KoniError::Process("planning question output is missing its impact".to_owned())
                })?,
                options: wire.options.ok_or_else(|| {
                    KoniError::Process("planning question output is missing its options".to_owned())
                })?,
            })
        }
        "questions" => {
            if wire.plan.is_some()
                || wire.prompt.is_some()
                || wire.context.is_some()
                || wire.impact.is_some()
                || wire.options.is_some()
            {
                return Err(KoniError::Process(
                    "planning question batch contains fields for another output kind".to_owned(),
                ));
            }
            PlanningAgentOutputEnvelope::Questions {
                questions: wire.questions.ok_or_else(|| {
                    KoniError::Process(
                        "planning question batch is missing its questions".to_owned(),
                    )
                })?,
            }
        }
        other => {
            return Err(KoniError::Process(format!(
                "planning agent returned unknown output kind {other:?}"
            )));
        }
    };
    match &envelope {
        PlanningAgentOutputEnvelope::Plan { plan } if plan.trim().is_empty() => {
            return Err(KoniError::Process(
                "planning agent returned a blank completed plan".to_owned(),
            ));
        }
        PlanningAgentOutputEnvelope::Question(question) => question.validate()?,
        PlanningAgentOutputEnvelope::Questions { questions } => {
            validate_planning_question_batch(questions)?;
        }
        PlanningAgentOutputEnvelope::Plan { .. } => {}
    }
    Ok(envelope)
}

fn planning_question_records(
    requests: &[PlanningQuestionRequest],
    bind_batch: bool,
    run_id: &str,
    agent: &AgentSessionRecord,
    policy: CatalogQuestionPolicy,
) -> Result<Vec<(QuestionRecord, bool)>> {
    validate_planning_question_batch(requests)?;
    let session_id = agent.codex_session_id.clone().ok_or_else(|| {
        KoniError::Process(
            "planning question cannot be bound without a Codex session ID".to_owned(),
        )
    })?;
    let now = Utc::now();
    let batch_id = bind_batch.then(|| Uuid::now_v7().to_string());
    let context_hash = normalized_hash(&json!({
        "run_id": run_id,
        "stage_id": agent.stage_id,
        "agent_id": agent.id,
        "agent_input_hash": agent.input_hash,
        "session_id": session_id,
        "requests": requests,
    }));
    requests
        .iter()
        .enumerate()
        .map(|(index, request)| {
            let options = request
                .options
                .iter()
                .enumerate()
                .map(|(index, option)| QuestionOption {
                    id: format!("choice-{}", index + 1),
                    label: option.label.trim().to_owned(),
                    description: option.description.trim().to_owned(),
                    recommended: option.recommended,
                })
                .collect::<Vec<_>>();
            let recommended = options
                .iter()
                .find(|option| option.recommended)
                .expect("request validation requires one recommendation")
                .id
                .clone();
            let requires_human = match policy {
                CatalogQuestionPolicy::Interactive => true,
                CatalogQuestionPolicy::HighImpactOnly => request.impact == QuestionImpact::High,
                CatalogQuestionPolicy::Autonomous => false,
            };
            let auto_resolution = (!requires_human).then(|| QuestionAutoResolution {
                option_id: recommended,
                resolve_at: now + chrono::Duration::milliseconds(1),
            });
            let mut question = QuestionRecord::new(
                Uuid::now_v7().to_string(),
                request.prompt.trim(),
                request.context.trim(),
                options,
                true,
                QuestionPauseScope::Run {
                    run_id: run_id.to_owned(),
                },
                policy,
                request.impact,
                auto_resolution,
                QuestionSessionResume {
                    session_id: session_id.clone(),
                    agent_id: Some(agent.id.clone()),
                    turn_id: None,
                    working_directory: agent.working_directory.clone(),
                    context_hash: context_hash.clone(),
                    captured_at: now,
                },
                now,
            )?;
            if let Some(batch_id) = &batch_id {
                question = question.with_batch_binding(QuestionBatchBinding::new(
                    batch_id,
                    index + 1,
                    requests.len(),
                )?)?;
            }
            if !requires_human {
                let resolve_at = question
                    .auto_resolution
                    .as_ref()
                    .expect("automatic planning question has a deadline")
                    .resolve_at;
                question.prepare_auto_resolve(resolve_at)?;
            }
            Ok((question, requires_human))
        })
        .collect()
}

fn planning_question_batch(
    control: &RunControlStore,
    anchor: &QuestionRecord,
) -> Result<Vec<QuestionRecord>> {
    let Some(binding) = &anchor.batch else {
        return Ok(vec![anchor.clone()]);
    };
    let mut questions = control
        .questions()?
        .into_iter()
        .filter(|question| {
            question
                .batch
                .as_ref()
                .is_some_and(|candidate| candidate.id == binding.id)
        })
        .collect::<Vec<_>>();
    questions.sort_by_key(|question| {
        question
            .batch
            .as_ref()
            .map_or(usize::MAX, |batch| batch.ordinal)
    });
    if questions.len() != binding.size {
        return Err(KoniError::Workflow(format!(
            "planning question batch {} contains {}, expected {}",
            binding.id,
            questions.len(),
            binding.size
        )));
    }
    for (index, question) in questions.iter().enumerate() {
        let candidate = question.batch.as_ref().ok_or_else(|| {
            KoniError::Workflow(format!(
                "planning question {} lost its batch binding",
                question.id
            ))
        })?;
        if candidate.size != binding.size
            || candidate.ordinal != index + 1
            || question.pause_scope != anchor.pause_scope
            || question.policy != anchor.policy
            || question.session_resume != anchor.session_resume
        {
            return Err(KoniError::Workflow(format!(
                "planning question batch {} has inconsistent member {}",
                binding.id, question.id
            )));
        }
    }
    Ok(questions)
}

fn question_answer_text(question: &QuestionRecord) -> Result<String> {
    let answer = question
        .answer
        .as_ref()
        .ok_or_else(|| KoniError::Workflow("question answer was not recorded".to_owned()))?;
    answer
        .custom
        .clone()
        .or_else(|| {
            answer.option_id.as_deref().and_then(|id| {
                question
                    .options
                    .iter()
                    .find(|option| option.id == id)
                    .map(|option| option.label.clone())
            })
        })
        .filter(|answer| !answer.trim().is_empty())
        .ok_or_else(|| {
            KoniError::Workflow(format!(
                "question {} has no resumable answer text",
                question.id
            ))
        })
}

fn planning_question_batch_resume_directive(
    questions: &[QuestionRecord],
) -> Result<ResumeDirective> {
    let first = questions
        .first()
        .ok_or_else(|| KoniError::Workflow("planning question batch is empty".to_owned()))?;
    if first.batch.is_none() {
        return resume_directive(first);
    }
    let binding = first.batch.as_ref().expect("checked above");
    if questions.len() != binding.size {
        return Err(KoniError::Workflow(format!(
            "planning question batch {} is incomplete",
            binding.id
        )));
    }
    let decisions = questions
        .iter()
        .enumerate()
        .map(|(index, question)| {
            Ok(format!(
                "{}. {} — {}",
                index + 1,
                question.prompt.trim(),
                question_answer_text(question)?
            ))
        })
        .collect::<Result<Vec<_>>>()?
        .join("\n");
    Ok(ResumeDirective {
        question_id: binding.id.clone(),
        session_id: first.session_resume.session_id.clone(),
        working_directory: first.session_resume.working_directory.clone(),
        prompt: format!(
            "The user resolved this planning question batch:\n{decisions}\nContinue from the safe checkpoint using these decisions."
        ),
        context_hash: first.session_resume.context_hash.clone(),
    })
}

fn unanswered_batch_members(questions: &[QuestionRecord]) -> usize {
    questions
        .iter()
        .filter(|question| question.answer.is_none())
        .count()
}

fn ready_planning_question_resume_anchor(control: &RunControlStore) -> Result<Option<String>> {
    for question in control.open_questions()?.into_iter().filter(|question| {
        question.answer.is_some()
            && question
                .session_resume
                .agent_id
                .as_deref()
                .is_some_and(|agent_id| agent_id.starts_with("planning-"))
    }) {
        let questions = planning_question_batch(control, &question)?;
        if unanswered_batch_members(&questions) == 0 {
            return Ok(questions.first().map(|question| question.id.clone()));
        }
    }
    Ok(None)
}

