fn report_source_row_sort_key(row: &Value) -> String {
    let node_type = row
        .get("type")
        .or_else(|| row.get("node_type"))
        .and_then(Value::as_str)
        .unwrap_or_default();
    let status = row
        .get("status")
        .and_then(Value::as_str)
        .unwrap_or_default();
    let id = row
        .get("id")
        .or_else(|| row.get("ticket_id"))
        .or_else(|| row.get("receipt_id"))
        .and_then(Value::as_str)
        .unwrap_or_default();
    let fallback = serde_json::to_string(row).unwrap_or_default();
    if !node_type.is_empty() {
        return format!("node\u{0}{node_type}\u{0}{id}\u{0}{fallback}");
    }
    if row.get("operation").is_some() && row.get("steps").is_some() {
        return format!("ticket\u{0}{status}\u{0}{id}\u{0}{fallback}");
    }
    format!("row\u{0}{id}\u{0}{status}\u{0}{fallback}")
}

fn report_output_path(base: &Path, format: crate::config::ReportFormat) -> PathBuf {
    match format {
        crate::config::ReportFormat::Json => base.with_extension("json"),
        crate::config::ReportFormat::Markdown => base.with_extension("md"),
        crate::config::ReportFormat::Yaml => base.with_extension("yaml"),
        crate::config::ReportFormat::Csv => base.with_extension("csv"),
    }
}

fn render_report_output(
    report: &crate::config::ReportDef,
    format: crate::config::ReportFormat,
    data: &Value,
) -> Result<Vec<u8>> {
    match format {
        crate::config::ReportFormat::Json => {
            let mut bytes = serde_json::to_vec_pretty(data).map_err(|source| KoniError::Json {
                path: PathBuf::from("<report output>"),
                source,
            })?;
            bytes.push(b'\n');
            Ok(bytes)
        }
        crate::config::ReportFormat::Markdown => {
            Ok(render_ledger_markdown(&report.title, &report.columns, &data["rows"]).into_bytes())
        }
        crate::config::ReportFormat::Yaml => serde_yaml::to_string(data)
            .map(String::into_bytes)
            .map_err(|source| KoniError::Yaml {
                path: PathBuf::from("<report output>"),
                source,
            }),
        crate::config::ReportFormat::Csv => Ok(render_csv_report(&data["rows"]).into_bytes()),
    }
}

#[allow(clippy::too_many_arguments)]
fn prepare_report_publication_plan(
    store: &StateStore,
    manifest_state: &RunManifest,
    report_id: String,
    bundle_hash: String,
    source_hashes: Value,
    manifest: Value,
    report_files: BTreeMap<PathBuf, Vec<u8>>,
) -> Result<ReportPublicationPlan> {
    let reports_dir = store.reports_dir();
    let store_root = store.root().to_path_buf();
    let manifest_bytes = serde_yaml::to_string(&manifest)
        .map(String::into_bytes)
        .map_err(|source| KoniError::Yaml {
            path: reports_dir.join("report-manifest.yaml"),
            source,
        })?;
    let manifest_hash = raw_sha256(&manifest_bytes);
    let transaction_hash = normalized_hash(&json!({
        "schema_version": "1.0",
        "run_id": manifest_state.id,
        "profile_hash": manifest_state.profile_hash,
        "report_id": report_id,
        "bundle_hash": bundle_hash,
        "source_hashes": source_hashes,
        "manifest_hash": manifest_hash,
    }));
    let receipt_id = stable_report_id("report-manifest", &[&transaction_hash]);
    let mut receipt = json!({
        "schema_version": "1.0",
        "id": receipt_id,
        "receipt_type": "report.manifest",
        "producer": "compiler.report",
        "run_id": manifest_state.id,
        "profile_hash": manifest_state.profile_hash,
        "report_id": report_id,
        "bundle_hash": bundle_hash,
        "transaction_hash": transaction_hash,
        "source_hashes": source_hashes,
        "manifest_hash": manifest_hash,
        "outputs": manifest["outputs"],
    });
    rehash_durable_receipt(&mut receipt);
    let receipt_bytes = serde_yaml::to_string(&receipt)
        .map(String::into_bytes)
        .map_err(|source| KoniError::Yaml {
            path: store.receipts_dir().join(format!("{receipt_id}.yaml")),
            source,
        })?;
    let snapshot_id = stable_report_id("S", &["report", &transaction_hash]);
    let snapshot = json!({
        "schema_version": "1.0",
        "id": snapshot_id,
        "kind": "report",
        "run_id": manifest_state.id,
        "profile_hash": manifest_state.profile_hash,
        "report_id": report_id,
        "bundle_hash": bundle_hash,
        "transaction_hash": transaction_hash,
        "source_hashes": source_hashes,
        "manifest_hash": manifest_hash,
    });
    let snapshot_path = store_root
        .join("snapshots")
        .join(format!("{snapshot_id}.yaml"));
    let snapshot_bytes = serde_yaml::to_string(&snapshot)
        .map(String::into_bytes)
        .map_err(|source| KoniError::Yaml {
            path: snapshot_path.clone(),
            source,
        })?;
    let event_data = json!({
        "run_id": manifest_state.id,
        "report_id": report_id,
        "kind": manifest["kind"],
        "bundle_hash": bundle_hash,
        "transaction_hash": transaction_hash,
        "source_hashes": source_hashes,
        "manifest_hash": manifest_hash,
        "ledger_count": manifest["ledger_counts"].as_object().map_or(0, Map::len),
        "snapshot_id": snapshot_id,
        "receipt_id": receipt_id,
    });
    Ok(ReportPublicationPlan {
        reports_dir: reports_dir.to_path_buf(),
        store_root: store_root.clone(),
        receipt_path: store.receipts_dir().join(format!("{receipt_id}.yaml")),
        snapshot_path,
        events_path: store_root.join("events.jsonl"),
        report_id,
        bundle_hash,
        transaction_hash,
        source_hashes,
        manifest,
        manifest_bytes,
        report_files,
        receipt_bytes,
        snapshot_bytes,
        event_data,
    })
}

fn stable_report_id(prefix: &str, parts: &[&str]) -> String {
    let digest = raw_sha256(parts.join("|").as_bytes());
    let digest = digest.strip_prefix("sha256:").unwrap_or(&digest);
    format!("{prefix}-{}", &digest[..digest.len().min(12)])
}

fn report_publication_is_current(plan: &ReportPublicationPlan) -> Result<bool> {
    if fs::read(plan.reports_dir.join("report-manifest.yaml"))
        .ok()
        .as_deref()
        != Some(plan.manifest_bytes.as_slice())
        || fs::read(&plan.receipt_path).ok().as_deref() != Some(plan.receipt_bytes.as_slice())
        || fs::read(&plan.snapshot_path).ok().as_deref() != Some(plan.snapshot_bytes.as_slice())
    {
        return Ok(false);
    }
    let mut expected = plan.report_files.keys().cloned().collect::<BTreeSet<_>>();
    expected.insert(PathBuf::from("report-manifest.yaml"));
    let actual = report_directory_files(&plan.reports_dir)?;
    if actual != expected {
        return Ok(false);
    }
    for (relative, expected) in &plan.report_files {
        if fs::read(plan.reports_dir.join(relative)).ok().as_deref() != Some(expected.as_slice()) {
            return Ok(false);
        }
    }
    Ok(read_report_compiled_event(plan)?.is_some())
}

fn report_directory_files(root: &Path) -> Result<BTreeSet<PathBuf>> {
    if !root.exists() {
        return Ok(BTreeSet::new());
    }
    let mut files = BTreeSet::new();
    for entry in WalkDir::new(root).follow_links(false) {
        let entry = entry.map_err(|error| KoniError::Action(error.to_string()))?;
        if entry.file_type().is_symlink() {
            return Err(KoniError::Action(format!(
                "report bundle contains a symlink: {}",
                entry.path().display()
            )));
        }
        if entry.file_type().is_file() {
            files.insert(
                entry
                    .path()
                    .strip_prefix(root)
                    .expect("walked report file is below report root")
                    .to_path_buf(),
            );
        }
    }
    Ok(files)
}

fn read_report_compiled_event(plan: &ReportPublicationPlan) -> Result<Option<Event>> {
    if !plan.events_path.exists() {
        return Ok(None);
    }
    let file =
        fs::File::open(&plan.events_path).map_err(|error| io_error(&plan.events_path, error))?;
    let expected_event_id = stable_report_id("report-event", &[&plan.transaction_hash]);
    let mut matched = None;
    for line in BufReader::new(file).lines() {
        let line = line.map_err(|error| io_error(&plan.events_path, error))?;
        if line.trim().is_empty() {
            continue;
        }
        let event: Event = serde_json::from_str(&line).map_err(|source| KoniError::Json {
            path: plan.events_path.clone(),
            source,
        })?;
        if event.event_type == "compiler.report.compiled"
            && event.data.get("transaction_hash").and_then(Value::as_str)
                == Some(plan.transaction_hash.as_str())
        {
            if event.id != expected_event_id || event.data != plan.event_data {
                return Err(KoniError::Action(format!(
                    "report transaction {} has a conflicting compiled event",
                    plan.transaction_hash
                )));
            }
            if matched.replace(event).is_some() {
                return Err(KoniError::Action(format!(
                    "report transaction {} has duplicate compiled events",
                    plan.transaction_hash
                )));
            }
        }
    }
    Ok(matched)
}

fn publish_report_transaction(plan: &ReportPublicationPlan) -> Result<()> {
    let transaction_root = report_publication_transaction_root(&plan.store_root);
    validate_report_publication_namespace(
        &plan.store_root,
        [
            transaction_root.as_path(),
            plan.reports_dir.as_path(),
            plan.receipt_path.as_path(),
            plan.snapshot_path.as_path(),
            plan.events_path.as_path(),
        ],
    )?;
    if transaction_root.exists() {
        return Err(KoniError::Action(format!(
            "a report publication journal already exists at {}; reopen the report action so recovery can reconcile it",
            transaction_root.display()
        )));
    }
    let result = stage_and_publish_report_transaction(plan, &transaction_root);
    if result.is_err()
        && !transaction_root.join("journal.yaml").exists()
        && transaction_root.exists()
    {
        let _ = fs::remove_dir_all(&transaction_root);
        let _ = sync_report_directory(&plan.store_root);
    }
    result
}

fn stage_and_publish_report_transaction(
    plan: &ReportPublicationPlan,
    transaction_root: &Path,
) -> Result<()> {
    let staged_reports = transaction_root.join("next-reports");
    for (relative, bytes) in &plan.report_files {
        let path = staged_reports.join(relative);
        write_report_durable_file(&path, bytes)?;
    }
    report_publication_failpoint("after_stage_outputs")?;
    fs::create_dir_all(&staged_reports).map_err(|error| io_error(&staged_reports, error))?;
    let staged_manifest = staged_reports.join("report-manifest.yaml");
    write_report_durable_file(&staged_manifest, &plan.manifest_bytes)?;

    let staged_receipt = transaction_root.join("support/receipt.yaml");
    let staged_snapshot = transaction_root.join("support/snapshot.yaml");
    let staged_event_append = transaction_root.join("support/event-append.bin");
    write_report_durable_file(&staged_receipt, &plan.receipt_bytes)?;
    write_report_durable_file(&staged_snapshot, &plan.snapshot_bytes)?;
    let events_base = match fs::read(&plan.events_path) {
        Ok(events) => events,
        Err(error) if error.kind() == std::io::ErrorKind::NotFound => Vec::new(),
        Err(error) => return Err(io_error(&plan.events_path, error)),
    };
    let event_id = stable_report_id("report-event", &[&plan.transaction_hash]);
    let event = Event {
        schema_version: "1.0".to_owned(),
        id: event_id.clone(),
        event_type: "compiler.report.compiled".to_owned(),
        at: Utc::now(),
        run_id: plan.event_data["run_id"]
            .as_str()
            .unwrap_or_default()
            .to_owned(),
        ticket_id: None,
        actor: "compiler".to_owned(),
        data: plan.event_data.clone(),
    };
    let mut event_append = Vec::new();
    if !events_base.is_empty() && !events_base.ends_with(b"\n") {
        event_append.push(b'\n');
    }
    serde_json::to_writer(&mut event_append, &event).map_err(|source| KoniError::Json {
        path: staged_event_append.clone(),
        source,
    })?;
    event_append.push(b'\n');
    write_report_durable_file(&staged_event_append, &event_append)?;
    report_publication_failpoint("after_stage_manifest")?;

    validate_staged_report_transaction(plan, &staged_reports, &staged_receipt, &staged_snapshot)?;
    report_publication_failpoint("after_support_publish")?;

    let mut report_files = plan
        .report_files
        .iter()
        .map(|(path, bytes)| (normalized_project_path(path), raw_sha256(bytes)))
        .collect::<BTreeMap<_, _>>();
    report_files.insert(
        "report-manifest.yaml".to_owned(),
        raw_sha256(&plan.manifest_bytes),
    );
    let mut journal = ReportPublicationJournal {
        schema_version: "1.0".to_owned(),
        kind: "report-publication".to_owned(),
        transaction_hash: plan.transaction_hash.clone(),
        run_id: plan.event_data["run_id"]
            .as_str()
            .unwrap_or_default()
            .to_owned(),
        profile_hash: plan.manifest["profile_hash"]
            .as_str()
            .unwrap_or_default()
            .to_owned(),
        report_id: plan.report_id.clone(),
        bundle_hash: plan.bundle_hash.clone(),
        reports_path: report_publication_relative_target(&plan.store_root, &plan.reports_dir)?,
        receipt_path: report_publication_relative_target(&plan.store_root, &plan.receipt_path)?,
        snapshot_path: report_publication_relative_target(&plan.store_root, &plan.snapshot_path)?,
        events_path: report_publication_relative_target(&plan.store_root, &plan.events_path)?,
        receipt_hash: raw_sha256(&plan.receipt_bytes),
        snapshot_hash: raw_sha256(&plan.snapshot_bytes),
        event_id,
        event_append_hash: raw_sha256(&event_append),
        events_base_len: events_base.len() as u64,
        events_base_hash: raw_sha256(&events_base),
        report_tree_hash: normalized_hash(&report_files),
        report_files,
        journal_hash: String::new(),
    };
    rehash_report_publication_journal(&mut journal);
    durable_atomic_write_yaml(&transaction_root.join("journal.yaml"), &journal)?;
    sync_report_directory(&plan.store_root)?;
    report_publication_crashpoint("after_journal");
    recover_report_publication_root(&plan.store_root)
}

fn validate_staged_report_transaction(
    plan: &ReportPublicationPlan,
    staged_reports: &Path,
    staged_receipt: &Path,
    staged_snapshot: &Path,
) -> Result<()> {
    let mut expected_files = plan.report_files.keys().cloned().collect::<BTreeSet<_>>();
    expected_files.insert(PathBuf::from("report-manifest.yaml"));
    let actual_files = report_directory_files(staged_reports)?;
    if actual_files != expected_files {
        return Err(KoniError::Action(format!(
            "staged report bundle has an unexpected file set: expected {expected_files:?}, found {actual_files:?}"
        )));
    }
    if fs::read(staged_reports.join("report-manifest.yaml"))
        .map_err(|error| io_error(staged_reports.join("report-manifest.yaml"), error))?
        != plan.manifest_bytes
        || fs::read(staged_receipt).map_err(|error| io_error(staged_receipt, error))?
            != plan.receipt_bytes
        || fs::read(staged_snapshot).map_err(|error| io_error(staged_snapshot, error))?
            != plan.snapshot_bytes
    {
        return Err(KoniError::Action(
            "staged report transaction differs from its validated plan".to_owned(),
        ));
    }
    let staged_manifest: Value =
        serde_yaml::from_slice(&plan.manifest_bytes).map_err(|source| KoniError::Yaml {
            path: staged_reports.join("report-manifest.yaml"),
            source,
        })?;
    if staged_manifest != plan.manifest {
        return Err(KoniError::Action(
            "staged report manifest does not decode to its validated contract".to_owned(),
        ));
    }
    for (relative, expected) in &plan.report_files {
        let actual = fs::read(staged_reports.join(relative))
            .map_err(|error| io_error(staged_reports.join(relative), error))?;
        if actual != *expected {
            return Err(KoniError::Action(format!(
                "staged report output {} differs from its validated bytes",
                relative.display()
            )));
        }
        match relative
            .extension()
            .and_then(|extension| extension.to_str())
        {
            Some("json") => {
                serde_json::from_slice::<Value>(&actual).map_err(|source| KoniError::Json {
                    path: staged_reports.join(relative),
                    source,
                })?;
            }
            Some("yaml" | "yml") => {
                serde_yaml::from_slice::<Value>(&actual).map_err(|source| KoniError::Yaml {
                    path: staged_reports.join(relative),
                    source,
                })?;
            }
            Some("md" | "csv") | None => {
                std::str::from_utf8(&actual).map_err(|error| {
                    KoniError::Action(format!(
                        "staged report output {} is not UTF-8: {error}",
                        relative.display()
                    ))
                })?;
            }
            Some(extension) => {
                return Err(KoniError::Action(format!(
                    "staged report output {} has unsupported extension {extension}",
                    relative.display()
                )));
            }
        }
    }
    Ok(())
}

fn report_publication_transaction_root(store_root: &Path) -> PathBuf {
    store_root.join(".report-publication")
}

fn validate_report_publication_namespace<'a>(
    store_root: &Path,
    targets: impl IntoIterator<Item = &'a Path>,
) -> Result<()> {
    let root_metadata =
        fs::symlink_metadata(store_root).map_err(|error| io_error(store_root, error))?;
    if root_metadata.file_type().is_symlink() || !root_metadata.is_dir() {
        return Err(KoniError::Action(format!(
            "report publication state root is redirected: {}",
            store_root.display()
        )));
    }
    for target in targets {
        let relative = target.strip_prefix(store_root).map_err(|_| {
            KoniError::Action(format!(
                "report publication target {} is outside state root {}",
                target.display(),
                store_root.display()
            ))
        })?;
        let mut current = store_root.to_path_buf();
        let components = relative.components().collect::<Vec<_>>();
        for (index, component) in components.iter().enumerate() {
            if !matches!(component, std::path::Component::Normal(_)) {
                return Err(KoniError::Action(format!(
                    "report publication target has an unsafe component: {}",
                    target.display()
                )));
            }
            current.push(component.as_os_str());
            match fs::symlink_metadata(&current) {
                Ok(metadata) if metadata.file_type().is_symlink() => {
                    return Err(KoniError::Action(format!(
                        "report publication rejects symlink component: {}",
                        current.display()
                    )));
                }
                Ok(metadata) if index + 1 < components.len() && !metadata.is_dir() => {
                    return Err(KoniError::Action(format!(
                        "report publication path component is not a directory: {}",
                        current.display()
                    )));
                }
                Ok(_) => {}
                Err(error) if error.kind() == std::io::ErrorKind::NotFound => break,
                Err(error) => return Err(io_error(&current, error)),
            }
        }
    }
    Ok(())
}

fn report_publication_relative_target(store_root: &Path, target: &Path) -> Result<String> {
    let relative = target.strip_prefix(store_root).map_err(|_| {
        KoniError::Action(format!(
            "report publication target {} is outside state root {}",
            target.display(),
            store_root.display()
        ))
    })?;
    validate_report_publication_relative_path(relative)?;
    Ok(normalized_project_path(relative))
}

fn validate_report_publication_relative_path(path: &Path) -> Result<()> {
    if path.as_os_str().is_empty()
        || path.is_absolute()
        || path
            .components()
            .any(|component| !matches!(component, std::path::Component::Normal(_)))
    {
        return Err(KoniError::Action(format!(
            "report publication journal contains an unsafe relative path: {}",
            path.display()
        )));
    }
    Ok(())
}

fn report_publication_target(store_root: &Path, relative: &str) -> Result<PathBuf> {
    let relative = Path::new(relative);
    validate_report_publication_relative_path(relative)?;
    Ok(store_root.join(relative))
}

fn rehash_report_publication_journal(journal: &mut ReportPublicationJournal) {
    journal.journal_hash.clear();
    journal.journal_hash = normalized_hash(journal);
}

fn validate_report_publication_journal(journal: &ReportPublicationJournal) -> Result<()> {
    if journal.schema_version != "1.0" || journal.kind != "report-publication" {
        return Err(KoniError::Action(
            "report publication journal has an unsupported contract".to_owned(),
        ));
    }
    let mut expected = journal.clone();
    let actual_hash = expected.journal_hash.clone();
    rehash_report_publication_journal(&mut expected);
    if actual_hash.is_empty() || expected.journal_hash != actual_hash {
        return Err(KoniError::Action(
            "report publication journal integrity failed".to_owned(),
        ));
    }
    for path in [
        &journal.reports_path,
        &journal.receipt_path,
        &journal.snapshot_path,
        &journal.events_path,
    ] {
        validate_report_publication_relative_path(Path::new(path))?;
    }
    if journal.transaction_hash.trim().is_empty()
        || journal.event_id != stable_report_id("report-event", &[&journal.transaction_hash])
        || !journal.report_files.contains_key("report-manifest.yaml")
        || normalized_hash(&journal.report_files) != journal.report_tree_hash
    {
        return Err(KoniError::Action(
            "report publication journal identity binding failed".to_owned(),
        ));
    }
    for path in journal.report_files.keys() {
        validate_report_publication_relative_path(Path::new(path))?;
    }
    Ok(())
}

fn recover_report_publication(store: &StateStore) -> Result<()> {
    let transaction_root = report_publication_transaction_root(store.root());
    validate_report_publication_namespace(store.root(), [transaction_root.as_path()])?;
    if !transaction_root.exists() {
        return Ok(());
    }
    let journal_path = transaction_root.join("journal.yaml");
    if !journal_path.exists() {
        fs::remove_dir_all(&transaction_root)
            .map_err(|error| io_error(&transaction_root, error))?;
        sync_report_directory(store.root())?;
        return Ok(());
    }
    let journal: ReportPublicationJournal = serde_yaml::from_slice(
        &fs::read(&journal_path).map_err(|error| io_error(&journal_path, error))?,
    )
    .map_err(|source| KoniError::Yaml {
        path: journal_path,
        source,
    })?;
    validate_report_publication_journal(&journal)?;
    let manifest = store.manifest()?;
    if journal.run_id != manifest.id || journal.profile_hash != manifest.profile_hash {
        return Err(KoniError::Action(format!(
            "report publication journal belongs to run {} / profile {}, not {} / {}",
            journal.run_id, journal.profile_hash, manifest.id, manifest.profile_hash
        )));
    }
    recover_report_publication_root(store.root())
}

fn recover_report_publication_root(store_root: &Path) -> Result<()> {
    let transaction_root = report_publication_transaction_root(store_root);
    let journal_path = transaction_root.join("journal.yaml");
    validate_report_publication_namespace(
        store_root,
        [transaction_root.as_path(), journal_path.as_path()],
    )?;
    let journal: ReportPublicationJournal = serde_yaml::from_slice(
        &fs::read(&journal_path).map_err(|error| io_error(&journal_path, error))?,
    )
    .map_err(|source| KoniError::Yaml {
        path: journal_path.clone(),
        source,
    })?;
    validate_report_publication_journal(&journal)?;

    let staged_receipt = transaction_root.join("support/receipt.yaml");
    let staged_snapshot = transaction_root.join("support/snapshot.yaml");
    let staged_event_append = transaction_root.join("support/event-append.bin");
    validate_report_publication_file(&staged_receipt, &journal.receipt_hash)?;
    validate_report_publication_file(&staged_snapshot, &journal.snapshot_hash)?;
    validate_report_publication_file(&staged_event_append, &journal.event_append_hash)?;

    let receipt_path = report_publication_target(store_root, &journal.receipt_path)?;
    let snapshot_path = report_publication_target(store_root, &journal.snapshot_path)?;
    let events_path = report_publication_target(store_root, &journal.events_path)?;
    let reports_path = report_publication_target(store_root, &journal.reports_path)?;
    let next_reports = transaction_root.join("next-reports");
    let previous_reports = transaction_root.join("previous-reports");
    validate_report_publication_namespace(
        store_root,
        [
            staged_receipt.as_path(),
            staged_snapshot.as_path(),
            staged_event_append.as_path(),
            receipt_path.as_path(),
            snapshot_path.as_path(),
            events_path.as_path(),
            reports_path.as_path(),
            next_reports.as_path(),
            previous_reports.as_path(),
        ],
    )?;

    install_immutable_report_file(
        &staged_receipt,
        &receipt_path,
        &journal.receipt_hash,
        &journal.transaction_hash,
    )?;
    report_publication_crashpoint("after_receipt_install");
    install_immutable_report_file(
        &staged_snapshot,
        &snapshot_path,
        &journal.snapshot_hash,
        &journal.transaction_hash,
    )?;
    report_publication_crashpoint("after_snapshot_install");
    append_report_event_idempotently(&events_path, &staged_event_append, &journal)?;
    report_publication_crashpoint("after_event_append");

    let live_is_new = report_generation_matches(&reports_path, &journal.report_files)?;
    if !live_is_new && reports_path.exists() {
        if previous_reports.exists() {
            return Err(KoniError::Action(
                "report publication recovery found both a live old generation and a previous-generation backup"
                    .to_owned(),
            ));
        }
        fs::rename(&reports_path, &previous_reports)
            .map_err(|error| io_error(&reports_path, error))?;
        sync_report_directory(
            reports_path
                .parent()
                .expect("report directory has a parent"),
        )?;
        sync_report_directory(&transaction_root)?;
        report_publication_crashpoint("after_report_backup");
    }

    if !report_generation_matches(&reports_path, &journal.report_files)? {
        if !next_reports.exists() {
            if previous_reports.exists() && !reports_path.exists() {
                fs::rename(&previous_reports, &reports_path)
                    .map_err(|error| io_error(&reports_path, error))?;
                sync_report_directory(
                    reports_path
                        .parent()
                        .expect("report directory has a parent"),
                )?;
            }
            return Err(KoniError::Action(
                "staged report generation disappeared before publication; the previous generation was restored"
                    .to_owned(),
            ));
        }
        if !report_generation_matches(&next_reports, &journal.report_files)? {
            return Err(KoniError::Action(
                "staged report generation no longer matches its durable journal".to_owned(),
            ));
        }
        fs::rename(&next_reports, &reports_path).map_err(|error| io_error(&reports_path, error))?;
        sync_report_directory(
            reports_path
                .parent()
                .expect("report directory has a parent"),
        )?;
        sync_report_directory(&transaction_root)?;
    }
    if !report_generation_matches(&reports_path, &journal.report_files)? {
        return Err(KoniError::Action(
            "published report generation failed its durable journal validation".to_owned(),
        ));
    }
    report_publication_crashpoint("after_report_install");

    if previous_reports.exists() {
        fs::remove_dir_all(&previous_reports)
            .map_err(|error| io_error(&previous_reports, error))?;
        sync_report_directory(&transaction_root)?;
    }
    report_publication_crashpoint("after_previous_cleanup");
    fs::remove_dir_all(&transaction_root).map_err(|error| io_error(&transaction_root, error))?;
    sync_report_directory(store_root)
}

fn validate_report_publication_file(path: &Path, expected_hash: &str) -> Result<()> {
    let bytes = fs::read(path).map_err(|error| io_error(path, error))?;
    if raw_sha256(&bytes) != expected_hash {
        return Err(KoniError::Action(format!(
            "report publication file {} differs from its durable journal",
            path.display()
        )));
    }
    Ok(())
}

fn install_immutable_report_file(
    staged: &Path,
    target: &Path,
    expected_hash: &str,
    transaction_hash: &str,
) -> Result<()> {
    let bytes = fs::read(staged).map_err(|error| io_error(staged, error))?;
    if raw_sha256(&bytes) != expected_hash {
        return Err(KoniError::Action(format!(
            "staged immutable report support {} failed integrity validation",
            staged.display()
        )));
    }
    match fs::read(target) {
        Ok(existing) if existing == bytes => return Ok(()),
        Ok(_) => {
            return Err(KoniError::Action(format!(
                "immutable report support target {} already has conflicting content",
                target.display()
            )));
        }
        Err(error) if error.kind() == std::io::ErrorKind::NotFound => {}
        Err(error) => return Err(io_error(target, error)),
    }
    let parent = target
        .parent()
        .ok_or_else(|| KoniError::Action("report support target has no parent".to_owned()))?;
    fs::create_dir_all(parent).map_err(|error| io_error(parent, error))?;
    let temp = parent.join(format!(
        ".{}.{}.tmp",
        target
            .file_name()
            .and_then(|name| name.to_str())
            .unwrap_or("report-support"),
        stable_report_id("txn", &[transaction_hash])
    ));
    if fs::symlink_metadata(&temp).is_ok_and(|metadata| metadata.file_type().is_symlink()) {
        return Err(KoniError::Action(format!(
            "report publication rejects symlink support temp: {}",
            temp.display()
        )));
    }
    if temp.exists() {
        let existing = fs::read(&temp).map_err(|error| io_error(&temp, error))?;
        if existing != bytes {
            fs::remove_file(&temp).map_err(|error| io_error(&temp, error))?;
        }
    }
    if !temp.exists() {
        write_report_durable_file(&temp, &bytes)?;
    }
    fs::rename(&temp, target).map_err(|error| io_error(target, error))?;
    sync_report_directory(parent)
}

fn append_report_event_idempotently(
    events_path: &Path,
    staged_append: &Path,
    journal: &ReportPublicationJournal,
) -> Result<()> {
    let append = fs::read(staged_append).map_err(|error| io_error(staged_append, error))?;
    if raw_sha256(&append) != journal.event_append_hash || append.is_empty() {
        return Err(KoniError::Action(
            "staged report event append failed integrity validation".to_owned(),
        ));
    }
    let mut current = match fs::read(events_path) {
        Ok(bytes) => bytes,
        Err(error) if error.kind() == std::io::ErrorKind::NotFound => Vec::new(),
        Err(error) => return Err(io_error(events_path, error)),
    };
    let base_len = usize::try_from(journal.events_base_len).map_err(|_| {
        KoniError::Action("report event base length does not fit this platform".to_owned())
    })?;
    if current.len() < base_len || raw_sha256(&current[..base_len]) != journal.events_base_hash {
        return Err(KoniError::Action(
            "historical events changed while recovering report publication".to_owned(),
        ));
    }
    let suffix = &current[base_len..];
    if suffix == append.as_slice() {
        return Ok(());
    }
    if !append.starts_with(suffix) {
        return Err(KoniError::Action(
            "events contain data beyond the journal-bound report append; refusing to rewrite history"
                .to_owned(),
        ));
    }
    if !suffix.is_empty() {
        let file = fs::OpenOptions::new()
            .write(true)
            .open(events_path)
            .map_err(|error| io_error(events_path, error))?;
        file.set_len(journal.events_base_len)
            .map_err(|error| io_error(events_path, error))?;
        file.sync_all()
            .map_err(|error| io_error(events_path, error))?;
        current.truncate(base_len);
    }
    if let Some(parent) = events_path.parent() {
        fs::create_dir_all(parent).map_err(|error| io_error(parent, error))?;
    }
    let mut file = fs::OpenOptions::new()
        .create(true)
        .append(true)
        .open(events_path)
        .map_err(|error| io_error(events_path, error))?;
    if report_publication_crashpoint_enabled("during_event_append") {
        let split = (append.len() / 2).max(1);
        file.write_all(&append[..split])
            .map_err(|error| io_error(events_path, error))?;
        file.sync_all()
            .map_err(|error| io_error(events_path, error))?;
        report_publication_crashpoint("during_event_append");
    }
    file.write_all(&append)
        .map_err(|error| io_error(events_path, error))?;
    file.sync_all()
        .map_err(|error| io_error(events_path, error))?;
    drop(file);
    if let Some(parent) = events_path.parent() {
        sync_report_directory(parent)?;
    }
    Ok(())
}

fn report_generation_matches(
    root: &Path,
    expected_hashes: &BTreeMap<String, String>,
) -> Result<bool> {
    if !root.exists() {
        return Ok(false);
    }
    let actual_files = report_directory_files(root)?;
    let expected_files = expected_hashes
        .keys()
        .map(PathBuf::from)
        .collect::<BTreeSet<_>>();
    if actual_files != expected_files {
        return Ok(false);
    }
    for (relative, expected_hash) in expected_hashes {
        let bytes =
            fs::read(root.join(relative)).map_err(|error| io_error(root.join(relative), error))?;
        if raw_sha256(&bytes) != *expected_hash {
            return Ok(false);
        }
    }
    Ok(true)
}

fn write_report_durable_file(path: &Path, bytes: &[u8]) -> Result<()> {
    let parent = path
        .parent()
        .ok_or_else(|| KoniError::Action("report file has no parent".to_owned()))?;
    fs::create_dir_all(parent).map_err(|error| io_error(parent, error))?;
    let mut file = fs::OpenOptions::new()
        .create(true)
        .truncate(true)
        .write(true)
        .open(path)
        .map_err(|error| io_error(path, error))?;
    file.write_all(bytes)
        .map_err(|error| io_error(path, error))?;
    file.sync_all().map_err(|error| io_error(path, error))?;
    drop(file);
    sync_report_directory(parent)
}

fn sync_report_directory(path: &Path) -> Result<()> {
    fs::File::open(path)
        .and_then(|directory| directory.sync_all())
        .map_err(|error| io_error(path, error))
}

#[cfg(not(test))]
fn report_publication_failpoint(_phase: &str) -> Result<()> {
    Ok(())
}

#[cfg(test)]
static REPORT_PUBLICATION_FAILPOINT: std::sync::Mutex<Option<String>> = std::sync::Mutex::new(None);

#[cfg(test)]
fn report_publication_failpoint(phase: &str) -> Result<()> {
    let mut configured = REPORT_PUBLICATION_FAILPOINT
        .lock()
        .expect("report failpoint mutex is not poisoned");
    if configured.as_deref() == Some(phase) {
        *configured = None;
        return Err(KoniError::Process(format!(
            "injected report publication failure at {phase}"
        )));
    }
    Ok(())
}

#[cfg(not(test))]
fn report_publication_crashpoint_enabled(_phase: &str) -> bool {
    false
}

#[cfg(test)]
fn report_publication_crashpoint_enabled(phase: &str) -> bool {
    std::env::var("KONI_REPORT_HARD_CRASH_PHASE").as_deref() == Ok(phase)
}

#[cfg(not(test))]
fn report_publication_crashpoint(_phase: &str) {}

#[cfg(test)]
fn report_publication_crashpoint(phase: &str) {
    if !report_publication_crashpoint_enabled(phase) {
        return;
    }
    let status = Command::new("/bin/kill")
        .args(["-9", &std::process::id().to_string()])
        .status();
    panic!("hard report crashpoint {phase} failed to SIGKILL the process: {status:?}");
}

fn render_ledger_markdown(
    title: &str,
    configured_columns: &[crate::config::ReportColumnDef],
    rows: &Value,
) -> String {
    let rows = rows.as_array().cloned().unwrap_or_default();
    let columns = if configured_columns.is_empty() {
        let mut columns = BTreeSet::new();
        for row in &rows {
            if let Some(object) = row.as_object() {
                columns.extend(object.keys().cloned());
            }
        }
        columns
            .into_iter()
            .map(|id| (id.clone(), id))
            .collect::<Vec<_>>()
    } else {
        configured_columns
            .iter()
            .map(|column| {
                (
                    column.id.clone(),
                    if column.title.trim().is_empty() {
                        column.id.clone()
                    } else {
                        column.title.clone()
                    },
                )
            })
            .collect::<Vec<_>>()
    };
    let mut output = format!("# {title}\n\n");
    if columns.is_empty() {
        output.push_str("No rows.\n");
    } else {
        output.push_str(&format!(
            "| {} |\n",
            columns
                .iter()
                .map(|(_, title)| title.as_str())
                .collect::<Vec<_>>()
                .join(" | ")
        ));
        output.push_str(&format!(
            "| {} |\n",
            columns
                .iter()
                .map(|_| "---")
                .collect::<Vec<_>>()
                .join(" | ")
        ));
        if rows.is_empty() {
            output.push_str(&format!(
                "| {} |\n",
                columns
                    .iter()
                    .enumerate()
                    .map(|(index, _)| if index == 0 { "no rows" } else { "-" })
                    .collect::<Vec<_>>()
                    .join(" | ")
            ));
        }
        for row in &rows {
            let values = columns
                .iter()
                .map(|(column, _)| report_markdown_cell(row.get(column).unwrap_or(&Value::Null)))
                .collect::<Vec<_>>();
            output.push_str(&format!("| {} |\n", values.join(" | ")));
        }
    }
    output
}

fn report_markdown_cell(value: &Value) -> String {
    let text = match value {
        Value::Null => "-".to_owned(),
        Value::String(value) if value.is_empty() => "-".to_owned(),
        Value::String(value) => value.clone(),
        Value::Array(values) => {
            let rendered = values
                .iter()
                .map(report_markdown_cell)
                .collect::<Vec<_>>()
                .join(", ");
            if rendered.is_empty() {
                "-".to_owned()
            } else {
                rendered
            }
        }
        other => other.to_string(),
    };
    text.replace('|', "\\|").replace('\n', " ")
}

fn markdown_cell(value: &Value) -> String {
    let text = match value {
        Value::Null => String::new(),
        Value::String(value) => value.clone(),
        other => other.to_string(),
    };
    text.replace('|', "\\|").replace('\n', " ")
}

fn render_csv_report(rows: &Value) -> String {
    let rows = rows.as_array().cloned().unwrap_or_default();
    let mut columns = BTreeSet::new();
    for row in &rows {
        if let Some(object) = row.as_object() {
            columns.extend(object.keys().cloned());
        }
    }
    let columns: Vec<_> = columns.into_iter().collect();
    let mut output = format!(
        "{}\n",
        columns
            .iter()
            .map(|value| csv_cell(value))
            .collect::<Vec<_>>()
            .join(",")
    );
    for row in rows {
        output.push_str(
            &columns
                .iter()
                .map(|column| csv_cell(&markdown_cell(row.get(column).unwrap_or(&Value::Null))))
                .collect::<Vec<_>>()
                .join(","),
        );
        output.push('\n');
    }
    output
}

fn csv_cell(value: &str) -> String {
    if value.contains([',', '"', '\n']) {
        format!("\"{}\"", value.replace('"', "\"\""))
    } else {
        value.to_owned()
    }
}

fn field_present(node: &Node, path: &str) -> bool {
    node.field_owned(path)
        .or_else(|| node.field_owned(&format!("spec.{path}")))
        .is_some_and(|value| !value_is_empty(&value))
}

fn value_is_empty(value: &Value) -> bool {
    match value {
        Value::Null => true,
        Value::String(value) => value.trim().is_empty(),
        Value::Array(value) => value.is_empty(),
        Value::Object(value) => value.is_empty(),
        _ => false,
    }
}

fn field_type_matches(kind: FieldType, value: &Value) -> bool {
    match kind {
        FieldType::Json => true,
        FieldType::String | FieldType::Path | FieldType::NodeRef => value.is_string(),
        FieldType::Integer => value.is_i64() || value.is_u64(),
        FieldType::Number => value.is_number(),
        FieldType::Boolean => value.is_boolean(),
        FieldType::List => value.is_array(),
        FieldType::Object => value.is_object(),
    }
}

fn validate_field_value(
    node: &Node,
    field: &str,
    definition: &crate::config::FieldDef,
    value: &Value,
    graph: &Graph,
    root: &Path,
    errors: &mut Vec<String>,
) {
    if !field_type_matches(definition.value_type, value) {
        errors.push(format!(
            "node {} field {} has the wrong type",
            node.id, field
        ));
        return;
    }
    if !definition.enum_values.is_empty() && !definition.enum_values.contains(value) {
        errors.push(format!(
            "node {} field {} is not one of the configured enum values",
            node.id, field
        ));
    }
    if let (Some(pattern), Some(text)) = (&definition.pattern, value.as_str()) {
        // Profile compilation validates every pattern before an Engine can be
        // opened, so this branch is only defensive against impossible IR.
        match regex::Regex::new(pattern) {
            Ok(pattern) if !pattern.is_match(text) => errors.push(format!(
                "node {} field {} does not match configured pattern",
                node.id, field
            )),
            Err(error) => errors.push(format!(
                "node {} field {} has an invalid configured pattern: {}",
                node.id, field, error
            )),
            _ => {}
        }
    }
    match definition.value_type {
        FieldType::Path => {
            if value
                .as_str()
                .is_none_or(|path| contained_join(root, Path::new(path)).is_err())
            {
                errors.push(format!(
                    "node {} field {} is not a project-relative path",
                    node.id, field
                ));
            }
        }
        FieldType::NodeRef => {
            if value
                .as_str()
                .is_none_or(|node_id| graph.node(node_id).is_none())
            {
                errors.push(format!(
                    "node {} field {} references a missing node",
                    node.id, field
                ));
            }
        }
        FieldType::List => {
            if let (Some(items), Some(item_definition)) = (value.as_array(), &definition.items) {
                for (index, item) in items.iter().enumerate() {
                    validate_field_value(
                        node,
                        &format!("{field}[{index}]"),
                        item_definition,
                        item,
                        graph,
                        root,
                        errors,
                    );
                }
            }
        }
        FieldType::Object => {
            let Some(object) = value.as_object() else {
                return;
            };
            for (property, property_definition) in &definition.properties {
                let property_path = format!("{field}.{property}");
                let property_value = object.get(property);
                if property_definition.required && property_value.is_none_or(value_is_empty) {
                    errors.push(format!("node {} requires field {}", node.id, property_path));
                }
                if let Some(property_value) = property_value {
                    validate_field_value(
                        node,
                        &property_path,
                        property_definition,
                        property_value,
                        graph,
                        root,
                        errors,
                    );
                }
            }
            if definition.additional_properties == Some(false) {
                for property in object
                    .keys()
                    .filter(|property| !definition.properties.contains_key(*property))
                {
                    errors.push(format!(
                        "node {} field {} contains unknown property {}",
                        node.id, field, property
                    ));
                }
            }
        }
        _ => {}
    }
}

fn relation_has_cycle(graph: &Graph, start: &str, relation: &str) -> bool {
    fn visit(
        graph: &Graph,
        node: &str,
        relation: &str,
        visiting: &mut HashSet<String>,
        visited: &mut HashSet<String>,
    ) -> bool {
        if visiting.contains(node) {
            return true;
        }
        if !visited.insert(node.to_owned()) {
            return false;
        }
        visiting.insert(node.to_owned());
        let cycle = graph
            .node(node)
            .and_then(|node| node.edges.get(relation))
            .into_iter()
            .flatten()
            .any(|target| visit(graph, target, relation, visiting, visited));
        visiting.remove(node);
        cycle
    }
    visit(
        graph,
        start,
        relation,
        &mut HashSet::new(),
        &mut HashSet::new(),
    )
}

fn count_matches(count: usize, leaf: &LeafPredicate) -> bool {
    leaf.exact.is_none_or(|exact| count == exact)
        && leaf.min.is_none_or(|min| count >= min)
        && leaf.max.is_none_or(|max| count <= max)
}

fn set_json_path(root: &mut Map<String, Value>, path: &str, value: Value) {
    let mut segments = path.split('.').peekable();
    let mut current = root;
    while let Some(segment) = segments.next() {
        if segments.peek().is_none() {
            current.insert(segment.to_owned(), value);
            return;
        }
        current = current
            .entry(segment.to_owned())
            .or_insert_with(|| Value::Object(Map::new()))
            .as_object_mut()
            .expect("intermediate initial spec fields are objects");
    }
}

fn remove_json_path(root: &mut Map<String, Value>, path: &str) {
    fn remove(remaining: &[&str], current: &mut Map<String, Value>) -> bool {
        let Some((segment, tail)) = remaining.split_first() else {
            return current.is_empty();
        };
        if tail.is_empty() {
            current.remove(*segment);
        } else if let Some(child) = current.get_mut(*segment).and_then(Value::as_object_mut)
            && remove(tail, child)
        {
            current.remove(*segment);
        }
        current.is_empty()
    }

    let segments = path.split('.').collect::<Vec<_>>();
    remove(&segments, root);
}

fn render_ticket_title(template: &str, target: Option<&Node>, operation: &str) -> String {
    template
        .replace("{{ operation }}", operation)
        .replace(
            "{{ target.title }}",
            target
                .map(|node| node.title.as_str())
                .unwrap_or("graph transition"),
        )
        .replace(
            "{{ target.type }}",
            target.map(|node| node.node_type.as_str()).unwrap_or("node"),
        )
        .replace(
            "{{ target.id }}",
            target.map(|node| node.id.as_str()).unwrap_or("unknown"),
        )
}

fn goal_title(goal: &str) -> String {
    let title: String = goal.trim().chars().take(96).collect();
    if title.is_empty() {
        "Untitled goal".to_owned()
    } else {
        title
    }
}

fn worktree_name(run_id: &str, ticket_id: &str) -> String {
    format!(
        "koni-{}-{}",
        &run_id[..8.min(run_id.len())],
        ticket_id.replace('/', "-")
    )
}

fn managed_worktree_branch_deletion_target(
    primitive: &str,
    branch: &str,
) -> Result<Option<String>> {
    match primitive {
        "lease.release" | "worktree.retire" => Ok(None),
        "worktree.remove" => Ok(Some(format!("refs/heads/{branch}"))),
        other => Err(KoniError::Action(format!(
            "{other} is not a worktree retirement primitive"
        ))),
    }
}

fn managed_worktree_name_for_path(
    git: &GitBackend,
    workspace: &Path,
    fallback: &str,
) -> Result<String> {
    if workspace.exists() {
        let workspace_git = GitBackend::discover(workspace)?;
        if workspace_git.common_dir() != git.common_dir()
            || workspace_git.git_dir().parent()
                != Some(git.common_dir().join("worktrees").as_path())
        {
            return Err(KoniError::Action(format!(
                "leased worktree {} is outside the managed Git namespace",
                workspace.display()
            )));
        }
        return workspace_git
            .git_dir()
            .file_name()
            .and_then(|name| name.to_str())
            .map(ToOwned::to_owned)
            .ok_or_else(|| {
                KoniError::Action(format!(
                    "leased worktree {} has no valid managed name",
                    workspace.display()
                ))
            });
    }
    for name in git.worktree_names()? {
        if git.worktree_path(&name)?.as_deref() == Some(workspace) {
            return Ok(name);
        }
    }
    Ok(fallback.to_owned())
}

const AGENT_TERM_GRACE: Duration = Duration::from_secs(2);
const AGENT_KILL_GRACE: Duration = Duration::from_secs(2);

fn canonical_ticket_agent_worktree(root: &Path, ticket: &Ticket) -> Result<PathBuf> {
    let lease = ticket.lease.as_ref().ok_or_else(|| {
        KoniError::Action(format!(
            "ticket {} cannot spawn an agent without an active worktree lease",
            ticket.id
        ))
    })?;
    if !lease.worktree.is_absolute() {
        return Err(KoniError::Action(format!(
            "ticket {} worktree lease is not canonical: {}",
            ticket.id,
            lease.worktree.display()
        )));
    }
    let canonical = lease
        .worktree
        .canonicalize()
        .map_err(|error| io_error(&lease.worktree, error))?;
    if canonical != lease.worktree {
        return Err(KoniError::Action(format!(
            "ticket {} worktree lease is not canonical: recorded {}, canonical {}",
            ticket.id,
            lease.worktree.display(),
            canonical.display()
        )));
    }
    let project_git = GitBackend::discover(root)?;
    let worktree_git = GitBackend::discover(&canonical)?;
    if worktree_git.workdir() != canonical {
        return Err(KoniError::Action(format!(
            "ticket {} lease path {} is not a Git worktree root",
            ticket.id,
            canonical.display()
        )));
    }
    if worktree_git.common_dir() != project_git.common_dir() {
        return Err(KoniError::Action(format!(
            "ticket {} lease worktree belongs to a different Git repository",
            ticket.id
        )));
    }
    let expected_branch = format!("refs/heads/{}", lease.branch);
    let actual_branch = worktree_git.branch_ref()?;
    if actual_branch != expected_branch {
        return Err(KoniError::Action(format!(
            "ticket {} lease expects branch {}, but worktree {} selects {}",
            ticket.id,
            expected_branch,
            canonical.display(),
            actual_branch
        )));
    }
    Ok(canonical)
}

fn ensure_runtime_ticket_lease_matches(canonical: &Ticket, runtime: &Ticket) -> Result<()> {
    let canonical_lease = canonical.lease.as_ref().ok_or_else(|| {
        KoniError::Action(format!(
            "ticket {} has no canonical worktree lease",
            canonical.id
        ))
    })?;
    let runtime_lease = runtime.lease.as_ref().ok_or_else(|| {
        KoniError::Action(format!(
            "ticket {} canonical worktree state has no lease",
            canonical.id
        ))
    })?;
    if runtime.id != canonical.id
        || runtime_lease.id != canonical_lease.id
        || runtime_lease.branch != canonical_lease.branch
        || runtime_lease.worktree != canonical_lease.worktree
    {
        return Err(KoniError::Action(format!(
            "ticket {} canonical worktree state does not match its active lease",
            canonical.id
        )));
    }
    Ok(())
}

struct SpawnedAgentProcess {
    child: Option<Child>,
    identity: AgentProcessIdentity,
}

impl SpawnedAgentProcess {
    fn new(mut child: Child) -> Result<Self> {
        let pid = child.id();
        let started = Instant::now();
        let identity = loop {
            if let Some(identity) = capture_owned_agent_process_identity(pid) {
                break identity;
            }
            if child
                .try_wait()
                .map_err(|error| {
                    KoniError::Process(format!("failed to inspect spawned agent {pid}: {error}"))
                })?
                .is_some()
                || started.elapsed() >= Duration::from_millis(250)
            {
                let cleanup = terminate_spawned_child(&mut child);
                return Err(KoniError::Process(format!(
                    "could not capture durable identity for spawned agent {pid}{}",
                    cleanup
                        .err()
                        .map(|error| format!("; cleanup also failed: {error}"))
                        .unwrap_or_default()
                )));
            }
            thread::sleep(Duration::from_millis(5));
        };
        Ok(Self {
            child: Some(child),
            identity,
        })
    }

    fn terminate_and_wait(&mut self) -> Result<()> {
        let Some(child) = &mut self.child else {
            return Ok(());
        };
        let result = terminate_spawned_child(child);
        self.child = None;
        result
    }

    fn release_to_reaper(
        mut self,
        on_exit: impl FnOnce(AgentProcessIdentity, std::io::Result<std::process::ExitStatus>)
        + Send
        + 'static,
    ) {
        let Some(mut child) = self.child.take() else {
            return;
        };
        let identity = self.identity.clone();
        thread::spawn(move || {
            on_exit(identity, child.wait());
        });
    }
}

impl Drop for SpawnedAgentProcess {
    fn drop(&mut self) {
        let _ = self.terminate_and_wait();
    }
}

#[cfg(test)]
fn persist_spawned_agent_process(
    process: SpawnedAgentProcess,
    pid_path: &Path,
    persist_runtime: impl FnOnce(&AgentProcessIdentity) -> Result<()>,
) -> Result<AgentProcessIdentity> {
    persist_spawned_agent_process_with_reaper(process, pid_path, persist_runtime, |_, _| {})
}

fn persist_spawned_agent_process_with_reaper(
    mut process: SpawnedAgentProcess,
    pid_path: &Path,
    persist_runtime: impl FnOnce(&AgentProcessIdentity) -> Result<()>,
    on_exit: impl FnOnce(AgentProcessIdentity, std::io::Result<std::process::ExitStatus>)
    + Send
    + 'static,
) -> Result<AgentProcessIdentity> {
    let identity = process.identity.clone();
    let persisted =
        atomic_write_worker_pid(pid_path, identity.pid).and_then(|()| persist_runtime(&identity));
    if let Err(error) = persisted {
        let _ = remove_worker_pid(pid_path);
        let cleanup = process.terminate_and_wait();
        return Err(match cleanup {
            Ok(()) => error,
            Err(cleanup_error) => KoniError::Process(format!(
                "{error}; failed to terminate spawned agent {} after persistence failure: {cleanup_error}",
                identity.pid
            )),
        });
    }
    process.release_to_reaper(on_exit);
    Ok(identity)
}

/// Persist the operating-system outcome for the raw worker record created by
/// `agent.spawn`. This record describes a process session, not proof that its
/// ticket or orchestration stage reached semantic completion; those remain
/// compiler-owned decisions. A zero exit therefore means the session itself
/// completed, while ticket progress is still derived from outputs/receipts.
fn reconcile_reaped_agent_exit(
    control: &RunControlStore,
    agent_id: &str,
    expected_identity: &AgentProcessIdentity,
    exit: std::io::Result<std::process::ExitStatus>,
    authority: Option<(&Path, &str)>,
) {
    let _authority_barrier = if let Some((sidecar_root, run_id)) = authority {
        let Ok(barrier) = acquire_run_authority_barrier_at(sidecar_root, run_id) else {
            return;
        };
        if sidecar_root
            .join("deletions")
            .join(format!("{run_id}.yaml"))
            .exists()
        {
            return;
        }
        let registry_path = sidecar_root.join("project.yaml");
        if registry_path.exists() {
            let Ok(text) = fs::read_to_string(&registry_path) else {
                return;
            };
            let Ok(registry) = serde_yaml::from_str::<ProjectRegistry>(&text) else {
                return;
            };
            if registry
                .runs
                .get(run_id)
                .is_none_or(|run| !run_registration_status_is_live(&run.status))
            {
                return;
            }
        } else if !control.root().exists() {
            return;
        }
        if control.root().join("deletion.yaml").exists() || !control.root().exists() {
            return;
        }
        Some(barrier)
    } else {
        None
    };
    let Ok(Some(mut record)) = control.agent(agent_id) else {
        return;
    };
    // Agent IDs are normally unique, but the identity comparison makes the
    // background waiter fail closed if a record was ever replaced/retried.
    if record.status != "running" || record.process_identity.as_ref() != Some(expected_identity) {
        return;
    }
    match exit {
        Ok(status) => {
            record.exit_code = status.code();
            record.status = if status.success() {
                "completed".to_owned()
            } else {
                "failed".to_owned()
            };
        }
        Err(error) => {
            record.status = "supervision_failed".to_owned();
            let mut result = record
                .result
                .take()
                .and_then(|value| value.as_object().cloned())
                .unwrap_or_default();
            result.insert(
                "supervision_error".to_owned(),
                Value::String(error.to_string()),
            );
            record.result = Some(Value::Object(result));
        }
    }
    if record.codex_session_id.is_none()
        && let Some(path) = record.stdout_path.as_deref()
    {
        record.codex_session_id = last_codex_session_id(path);
    }
    let now = Utc::now();
    record.finished_at = Some(now);
    record.updated_at = now;
    let _ = control.write_agent(&record);
}

fn last_codex_session_id(path: &Path) -> Option<String> {
    let file = fs::File::open(path).ok()?;
    BufReader::new(file)
        .lines()
        .map_while(std::result::Result::ok)
        .filter_map(|line| serde_json::from_str::<Value>(&line).ok())
        .filter_map(|event| {
            (event.get("type").and_then(Value::as_str) == Some("thread.started"))
                .then(|| {
                    event
                        .get("thread_id")
                        .and_then(Value::as_str)
                        .map(ToOwned::to_owned)
                })
                .flatten()
        })
        .last()
}

fn atomic_write_worker_pid(path: &Path, pid: u32) -> Result<()> {
    let parent = path.parent().ok_or_else(|| {
        KoniError::Process(format!("worker PID path has no parent: {}", path.display()))
    })?;
    fs::create_dir_all(parent).map_err(|error| io_error(parent, error))?;
    let temporary = path.with_extension(format!("pid.{}.tmp", Uuid::now_v7()));
    let result = (|| {
        let mut file = fs::OpenOptions::new()
            .create_new(true)
            .write(true)
            .open(&temporary)
            .map_err(|error| io_error(&temporary, error))?;
        file.write_all(format!("{pid}\n").as_bytes())
            .map_err(|error| io_error(&temporary, error))?;
        file.sync_all()
            .map_err(|error| io_error(&temporary, error))?;
        fs::rename(&temporary, path).map_err(|error| io_error(path, error))?;
        sync_directory(parent)
    })();
    if result.is_err() {
        let _ = fs::remove_file(&temporary);
    }
    result
}

fn read_worker_pid(path: &Path) -> Result<Option<u32>> {
    let text = match fs::read_to_string(path) {
        Ok(text) => text,
        Err(error) if error.kind() == std::io::ErrorKind::NotFound => return Ok(None),
        Err(error) => return Err(io_error(path, error)),
    };
    text.trim().parse::<u32>().map(Some).map_err(|error| {
        KoniError::Process(format!(
            "worker PID file {} is invalid: {error}",
            path.display()
        ))
    })
}

fn remove_worker_pid(path: &Path) -> Result<()> {
    match fs::remove_file(path) {
        Ok(()) => {
            if let Some(parent) = path.parent() {
                sync_directory(parent)?;
            }
            Ok(())
        }
        Err(error) if error.kind() == std::io::ErrorKind::NotFound => Ok(()),
        Err(error) => Err(io_error(path, error)),
    }
}

#[cfg(unix)]
fn sync_directory(path: &Path) -> Result<()> {
    fs::File::open(path)
        .and_then(|directory| directory.sync_all())
        .map_err(|error| io_error(path, error))
}

#[cfg(not(unix))]
fn sync_directory(_path: &Path) -> Result<()> {
    Ok(())
}

fn terminate_spawned_child(child: &mut Child) -> Result<()> {
    let process_group_id = child.id();
    if process_group_is_alive(process_group_id) {
        signal_process_group(process_group_id, "TERM")?;
        if !wait_for_child_process_group_exit(child, AGENT_TERM_GRACE)? {
            signal_process_group(process_group_id, "KILL")?;
            if !wait_for_child_process_group_exit(child, AGENT_KILL_GRACE)? {
                return Err(KoniError::Process(format!(
                    "spawned agent process group {process_group_id} did not exit after SIGKILL"
                )));
            }
        }
    } else {
        child.wait().map_err(|error| {
            KoniError::Process(format!(
                "failed to reap spawned agent {process_group_id}: {error}"
            ))
        })?;
    }
    Ok(())
}

fn wait_for_child_process_group_exit(child: &mut Child, timeout: Duration) -> Result<bool> {
    let process_group_id = child.id();
    let started = Instant::now();
    loop {
        let leader_exited = child
            .try_wait()
            .map_err(|error| {
                KoniError::Process(format!(
                    "failed waiting for spawned agent {process_group_id}: {error}"
                ))
            })?
            .is_some();
        if !process_group_is_alive(process_group_id) {
            if !leader_exited {
                child.wait().map_err(|error| {
                    KoniError::Process(format!(
                        "failed to reap spawned agent {process_group_id}: {error}"
                    ))
                })?;
            }
            return Ok(true);
        }
        if started.elapsed() >= timeout {
            return Ok(false);
        }
        thread::sleep(Duration::from_millis(20));
    }
}

fn terminate_owned_agent_process(
    identity: &AgentProcessIdentity,
    term_grace: Duration,
    kill_grace: Duration,
) -> Result<bool> {
    if !owned_agent_process_is_alive(identity) {
        if process_is_alive(identity.pid) {
            return Err(KoniError::Process(format!(
                "refusing to signal PID {} because its durable process identity no longer matches",
                identity.pid
            )));
        }
        return Ok(false);
    }
    signal_process_group(identity.process_group_id, "TERM")?;
    if wait_for_process_group_exit(identity.process_group_id, term_grace) {
        return Ok(true);
    }
    signal_process_group(identity.process_group_id, "KILL")?;
    if wait_for_process_group_exit(identity.process_group_id, kill_grace) {
        return Ok(true);
    }
    Err(KoniError::Process(format!(
        "agent process group {} did not exit after SIGKILL",
        identity.process_group_id
    )))
}

fn signal_process_group(process_group_id: u32, signal: &str) -> Result<()> {
    #[cfg(unix)]
    let target = format!("-{process_group_id}");
    #[cfg(not(unix))]
    let target = process_group_id.to_string();
    let status = Command::new("kill")
        .arg(format!("-{signal}"))
        .arg("--")
        .arg(target)
        .stdin(Stdio::null())
        .stdout(Stdio::null())
        .stderr(Stdio::null())
        .status()
        .map_err(|error| {
            KoniError::Process(format!(
                "failed to signal agent process group {process_group_id}: {error}"
            ))
        })?;
    if status.success() || !process_group_is_alive(process_group_id) {
        Ok(())
    } else {
        Err(KoniError::Process(format!(
            "agent process group {process_group_id} did not accept SIG{signal}"
        )))
    }
}

fn process_group_is_alive(process_group_id: u32) -> bool {
    #[cfg(unix)]
    let target = format!("-{process_group_id}");
    #[cfg(not(unix))]
    let target = process_group_id.to_string();
    Command::new("kill")
        .arg("-0")
        .arg("--")
        .arg(target)
        .stdin(Stdio::null())
        .stdout(Stdio::null())
        .stderr(Stdio::null())
        .status()
        .is_ok_and(|status| status.success())
}

fn wait_for_process_group_exit(process_group_id: u32, timeout: Duration) -> bool {
    let started = Instant::now();
    while process_group_is_alive(process_group_id) {
        if started.elapsed() >= timeout {
            return false;
        }
        thread::sleep(Duration::from_millis(20));
    }
    true
}

fn active_worker_process_identity(ticket: &Ticket) -> Result<Option<AgentProcessIdentity>> {
    let Some(value) = ticket
        .extensions
        .get("active_worker")
        .and_then(Value::as_object)
        .and_then(|worker| worker.get("process_identity"))
    else {
        return Ok(None);
    };
    serde_json::from_value(value.clone())
        .map(Some)
        .map_err(|error| {
            KoniError::Action(format!(
                "ticket {} has invalid active worker process identity: {error}",
                ticket.id
            ))
        })
}

fn clear_ticket_review_runtime(
    store: &StateStore,
    ticket_id: &str,
    expected_pid: Option<u32>,
) -> Result<()> {
    let mut ticket = store.ticket(ticket_id)?;
    let recorded_pid = ticket.lease.as_ref().and_then(|lease| lease.worker_pid);
    if recorded_pid.is_none() && !ticket.extensions.contains_key("active_worker") {
        return Ok(());
    }
    if let Some(expected_pid) = expected_pid
        && recorded_pid != Some(expected_pid)
    {
        return Err(KoniError::Process(format!(
            "refusing to clear ticket {ticket_id} reviewer runtime: expected process {expected_pid}, recorded {:?}",
            recorded_pid
        )));
    }
    if let Some(identity) = active_worker_process_identity(&ticket)?
        && owned_agent_process_is_alive(&identity)
    {
        return Err(KoniError::Process(format!(
            "refusing to clear live ticket reviewer {}",
            identity.pid
        )));
    }
    if let Some(lease) = &mut ticket.lease {
        lease.worker_pid = None;
        lease.heartbeat_at = Utc::now();
    }
    ticket.extensions.remove("active_worker");
    store.write_ticket(&ticket)
}

fn ticket_worker_is_alive(ticket: &Ticket) -> bool {
    let Some(pid) = ticket.lease.as_ref().and_then(|lease| lease.worker_pid) else {
        return false;
    };
    match active_worker_process_identity(ticket) {
        Ok(Some(identity)) => identity.pid == pid && owned_agent_process_is_alive(&identity),
        Ok(None) => false,
        Err(_) => false,
    }
}

fn process_is_alive(pid: u32) -> bool {
    let signalable = Command::new("kill")
        .arg("-0")
        .arg(pid.to_string())
        .stdin(Stdio::null())
        .stdout(Stdio::null())
        .stderr(Stdio::null())
        .status()
        .is_ok_and(|status| status.success());
    if !signalable {
        return false;
    }
    Command::new("ps")
        .args(["-o", "stat=", "-p", &pid.to_string()])
        .stdin(Stdio::null())
        .stderr(Stdio::null())
        .output()
        .ok()
        .filter(|output| output.status.success())
        .and_then(|output| String::from_utf8(output.stdout).ok())
        .is_none_or(|state| !state.trim_start().starts_with('Z'))
}

fn owned_agent_pid(context: &BTreeMap<String, Value>) -> Option<u32> {
    context
        .get("effects")?
        .as_array()?
        .iter()
        .rev()
        .find(|effect| effect.get("primitive").and_then(Value::as_str) == Some("agent.spawn"))?
        .get("output")?
        .get("pid")?
        .as_u64()
        .and_then(|pid| u32::try_from(pid).ok())
}

fn owned_agent_identity(context: &BTreeMap<String, Value>) -> Option<AgentProcessIdentity> {
    serde_json::from_value(
        context
            .get("effects")?
            .as_array()?
            .iter()
            .rev()
            .find(|effect| effect.get("primitive").and_then(Value::as_str) == Some("agent.spawn"))?
            .get("output")?
            .get("process_identity")?
            .clone(),
    )
    .ok()
}

fn ticket_operation<'a>(
    profile: &'a CompiledProfile,
    ticket: &Ticket,
) -> Result<&'a crate::config::OperationDef> {
    let registry_id = ticket
        .extensions
        .get("operation_registry_id")
        .and_then(Value::as_str)
        .ok_or_else(|| {
            KoniError::Profile(format!(
                "ticket {} has no operation registry binding",
                ticket.id
            ))
        })?;
    profile.operations.get(registry_id).ok_or_else(|| {
        KoniError::Profile(format!(
            "ticket {} references missing operation {registry_id}",
            ticket.id
        ))
    })
}

fn unbound_ordinary_change_control_barrier(
    profile: &CompiledProfile,
    ticket: &Ticket,
) -> Option<bool> {
    if !ticket.change_control.is_inactive_history_only() {
        return None;
    }
    let mut candidates = profile
        .operations
        .values()
        .filter(|candidate| candidate.public_operation() == ticket.operation);
    let first = candidates.next()?;
    if !matches!(
        &first.change_control,
        OperationChangeControlDef::Ordinary { .. }
    ) {
        return None;
    }
    let barrier = first.change_control_barrier;
    candidates
        .all(|candidate| {
            matches!(
                &candidate.change_control,
                OperationChangeControlDef::Ordinary { .. }
            ) && candidate.change_control_barrier == barrier
        })
        .then_some(barrier)
}

fn expand_ticket_owned_scope(profile: &CompiledProfile, ticket: &mut Ticket) -> Result<bool> {
    let operation = ticket_operation(profile, ticket)?;
    let mut changed = false;
    for node in ticket.outputs.iter().flat_map(|output| {
        output
            .typed
            .get("graph_delta")
            .into_iter()
            .flat_map(|delta| {
                [
                    "upsert",
                    "add_nodes",
                    "added_nodes",
                    "nodes",
                    "update_nodes",
                    "updated_nodes",
                ]
                .into_iter()
                .flat_map(|field| {
                    delta
                        .get(field)
                        .and_then(Value::as_array)
                        .into_iter()
                        .flatten()
                })
            })
    }) {
        let Some(node_id) = node.get("id").and_then(Value::as_str) else {
            continue;
        };
        let Some(node_type) = node.get("type").and_then(Value::as_str) else {
            continue;
        };
        if !operation
            .allowed_new_node_types
            .iter()
            .any(|allowed| allowed == node_type)
        {
            continue;
        }
        changed |= ticket.scope.read_nodes.insert(node_id.to_owned());
        changed |= ticket.scope.write_nodes.insert(node_id.to_owned());
    }
    Ok(changed)
}

fn context_dependency_node_types(
    profile: &CompiledProfile,
    graph: &Graph,
    outputs: &[crate::state::StepOutput],
) -> BTreeSet<String> {
    fn collect_declared_nodes(
        profile: &CompiledProfile,
        value: &Value,
        declared: &mut BTreeMap<String, String>,
    ) {
        match value {
            Value::Object(object) => {
                if let (Some(id), Some(node_type)) = (
                    object.get("id").and_then(Value::as_str),
                    object.get("type").and_then(Value::as_str),
                ) && profile.node_types.contains_key(node_type)
                {
                    declared.insert(id.to_owned(), node_type.to_owned());
                }
                for child in object.values() {
                    collect_declared_nodes(profile, child, declared);
                }
            }
            Value::Array(items) => {
                for child in items {
                    collect_declared_nodes(profile, child, declared);
                }
            }
            _ => {}
        }
    }

    fn collect_referenced_types(
        graph: &Graph,
        declared: &BTreeMap<String, String>,
        value: &Value,
        types: &mut BTreeSet<String>,
    ) {
        match value {
            Value::String(candidate) => {
                if let Some(node) = graph.node(candidate) {
                    types.insert(node.node_type.clone());
                } else if let Some(node_type) = declared.get(candidate) {
                    types.insert(node_type.clone());
                }
            }
            Value::Object(object) => {
                for child in object.values() {
                    collect_referenced_types(graph, declared, child, types);
                }
            }
            Value::Array(items) => {
                for child in items {
                    collect_referenced_types(graph, declared, child, types);
                }
            }
            _ => {}
        }
    }

    let mut declared = BTreeMap::new();
    for output in outputs {
        collect_declared_nodes(
            profile,
            &serde_json::to_value(output).expect("step output serializes"),
            &mut declared,
        );
    }
    let mut types = BTreeSet::new();
    for output in outputs {
        collect_referenced_types(
            graph,
            &declared,
            &serde_json::to_value(output).expect("step output serializes"),
            &mut types,
        );
    }
    types
}

/// Select the semantic policy contracts an agent needs to interpret the graph
/// contract it received. A policy enters through one of its declared graph
/// roles or through an edge predicate, then brings along policies referenced
/// by its selectors (including references reached through named queries).
fn context_gate_contract_ids(
    profile: &CompiledProfile,
    node_type_ids: &BTreeSet<String>,
    edge_types: &[EdgeTypeDef],
) -> (BTreeSet<String>, BTreeSet<String>) {
    let mut selected = profile
        .gate_policies
        .iter()
        .filter(|(_, policy)| {
            policy
                .gate_node_types
                .iter()
                .chain(&policy.candidate_node_types)
                .chain(&policy.applicability.subject_node_types)
                .any(|node_type| node_type_ids.contains(node_type))
        })
        .map(|(id, _)| id.clone())
        .collect::<BTreeSet<_>>();
    let mut query_ids = BTreeSet::new();
    for predicate in edge_types.iter().filter_map(|edge| edge.when.as_ref()) {
        predicate.referenced_gate_policies(&mut selected);
        predicate.referenced_queries(&mut query_ids);
    }
    collect_query_gate_policy_references(profile, &mut query_ids, &mut selected);

    let mut expanded = BTreeSet::new();
    loop {
        let pending = selected.difference(&expanded).cloned().collect::<Vec<_>>();
        if pending.is_empty() {
            break;
        }
        for policy_id in pending {
            expanded.insert(policy_id.clone());
            let Some(policy) = profile.gate_policies.get(&policy_id) else {
                continue;
            };
            let mut selectors = vec![
                &policy.gate_subjects,
                &policy.candidate_pool,
                &policy.evaluation_targets.select,
                &policy.applicability.direct_gates,
                &policy.applicability.inherited_gates,
                &policy.applicability.context,
            ];
            selectors.extend(policy.applicability.context_classes.values());
            if let Some(context) = &policy.context {
                selectors.push(&context.select);
            }
            let mut policy_queries = BTreeSet::new();
            for selector in selectors {
                selector.referenced_gate_policies(&mut selected);
                selector.referenced_queries(&mut policy_queries);
            }
            collect_query_gate_policy_references(profile, &mut policy_queries, &mut selected);
            query_ids.extend(policy_queries);
        }
    }
    (selected, query_ids)
}

fn collect_query_gate_policy_references(
    profile: &CompiledProfile,
    pending: &mut BTreeSet<String>,
    policies: &mut BTreeSet<String>,
) {
    let mut expanded = BTreeSet::new();
    loop {
        let query_ids = pending.difference(&expanded).cloned().collect::<Vec<_>>();
        if query_ids.is_empty() {
            break;
        }
        for query_id in query_ids {
            expanded.insert(query_id.clone());
            let Some(query) = profile.queries.get(&query_id) else {
                continue;
            };
            if let Some(selector) = &query.select {
                selector.referenced_gate_policies(policies);
                selector.referenced_queries(pending);
            }
            if let Some(traverse) = &query.traverse {
                traverse.from.referenced_gate_policies(policies);
                traverse.from.referenced_queries(pending);
            }
            if let Some(predicate) = &query.predicate {
                predicate.referenced_gate_policies(policies);
                predicate.referenced_queries(pending);
            }
        }
    }
}

fn render_git_template(template: &str, run: &RunManifest, ticket: &Ticket) -> String {
    template
        .replace("{{ run.id }}", &run.id)
        .replace("{{ ticket.id }}", &ticket.id)
        .replace("{{ ticket.operation }}", &ticket.operation)
        .replace("{{ ticket.title }}", &ticket.title)
}

fn render_commit_value(
    template: &str,
    run: &RunManifest,
    ticket: &Ticket,
    profile_hash: &str,
) -> String {
    let review_id = ticket
        .reviews
        .last()
        .map(|review| review.id.as_str())
        .unwrap_or_default();
    render_git_template(template, run, ticket)
        .replace("{{ profile.hash }}", profile_hash)
        .replace("{{ review.id }}", review_id)
}

fn derive_filesystem_manifest(
    node: &Node,
    definition: &FilesystemManifestDef,
    project_root: &Path,
    accept_changes: bool,
) -> Value {
    let mut errors = BTreeSet::new();
    let root_value = node
        .field_owned(&definition.root_field)
        .and_then(|value| value.as_str().map(ToOwned::to_owned))
        .filter(|value| !value.trim().is_empty());
    let normalized_root =
        root_value
            .as_deref()
            .and_then(|raw| match normalized_relative_filesystem_path(raw) {
                Ok(path) => Some(path),
                Err(error) => {
                    errors.insert(format!("filesystem root {error}: {raw}"));
                    None
                }
            });
    if root_value.is_none() {
        errors.insert(format!(
            "{} must be a nonempty project-relative path",
            definition.root_field
        ));
    }
    if let Some(root) = &normalized_root
        && !definition.allowed_root_prefixes.is_empty()
        && !definition.allowed_root_prefixes.iter().any(|prefix| {
            normalized_relative_filesystem_path(prefix).is_ok_and(|prefix| root.starts_with(prefix))
        })
    {
        errors.insert(format!(
            "filesystem root {} is outside configured root prefixes",
            path_text(root)
        ));
    }

    let project_canonical = match project_root.canonicalize() {
        Ok(root) if root.is_dir() => Some(root),
        _ => {
            errors.insert("project root cannot be resolved as a directory".to_owned());
            None
        }
    };
    let mut canonical_root = None;
    let mut file_rows = Vec::new();
    if let (Some(root), Some(project_canonical)) = (&normalized_root, project_canonical.as_ref()) {
        let concrete = project_root.join(root);
        if definition.scan.symlinks == FilesystemSymlinkPolicy::Reject
            && filesystem_path_contains_symlink(project_root, root)
        {
            errors.insert(format!(
                "filesystem root or one of its parents must not be a symlink: {}",
                path_text(root)
            ));
        } else {
            match fs::symlink_metadata(&concrete) {
                Err(_) => {
                    errors.insert(format!(
                        "filesystem root does not exist: {}",
                        path_text(root)
                    ));
                }
                Ok(_) => match concrete.canonicalize() {
                    Err(_) => {
                        errors.insert(format!(
                            "filesystem root cannot be resolved: {}",
                            path_text(root)
                        ));
                    }
                    Ok(resolved)
                        if !resolved.starts_with(project_canonical) || !resolved.is_dir() =>
                    {
                        errors.insert(format!(
                            "filesystem root escapes the project or is not a directory: {}",
                            path_text(root)
                        ));
                    }
                    Ok(root_resolved) => {
                        let mut allowed_boundary = definition.allowed_root_prefixes.is_empty();
                        for prefix in &definition.allowed_root_prefixes {
                            let Ok(prefix) = normalized_relative_filesystem_path(prefix) else {
                                continue;
                            };
                            match project_root.join(&prefix).canonicalize() {
                                Ok(boundary)
                                    if boundary.starts_with(project_canonical)
                                        && boundary.is_dir()
                                        && root_resolved.starts_with(&boundary) =>
                                {
                                    allowed_boundary = true;
                                }
                                Ok(_) => {}
                                Err(_) => {
                                    errors.insert(format!(
                                        "configured filesystem root prefix cannot be resolved: {}",
                                        path_text(&prefix)
                                    ));
                                }
                            }
                        }
                        if !allowed_boundary {
                            errors.insert(format!(
                                "filesystem root resolves outside configured root prefixes: {}",
                                path_text(root)
                            ));
                        } else {
                            canonical_root = Some(root_resolved.clone());
                            let walker = WalkDir::new(&concrete)
                                .follow_links(
                                    definition.scan.symlinks == FilesystemSymlinkPolicy::Contained,
                                )
                                .sort_by_file_name();
                            for entry in walker {
                                let entry = match entry {
                                    Ok(entry) => entry,
                                    Err(error) => {
                                        errors
                                            .insert(format!("filesystem inventory error: {error}"));
                                        continue;
                                    }
                                };
                                if entry.path() == concrete {
                                    continue;
                                }
                                let Ok(relative_to_root) = entry.path().strip_prefix(&concrete)
                                else {
                                    errors.insert(
                                        "filesystem inventory produced an escaped path".to_owned(),
                                    );
                                    continue;
                                };
                                if filesystem_manifest_path_is_ignored(relative_to_root, definition)
                                {
                                    continue;
                                }
                                let symlink = fs::symlink_metadata(entry.path())
                                    .is_ok_and(|metadata| metadata.file_type().is_symlink());
                                if symlink
                                    && definition.scan.symlinks == FilesystemSymlinkPolicy::Reject
                                {
                                    errors.insert(format!(
                                        "filesystem inventory rejects symlink: {}",
                                        path_text(&root.join(relative_to_root))
                                    ));
                                    continue;
                                }
                                if !entry.path().is_file() {
                                    continue;
                                }
                                match entry.path().canonicalize() {
                                    Ok(file_resolved)
                                        if file_resolved.starts_with(project_canonical)
                                            && file_resolved.starts_with(&root_resolved) => {}
                                    Ok(_) => {
                                        errors.insert(format!(
                                            "filesystem inventory path escapes configured root: {}",
                                            path_text(&root.join(relative_to_root))
                                        ));
                                        continue;
                                    }
                                    Err(_) => {
                                        errors.insert(format!(
                                            "filesystem inventory path cannot be resolved: {}",
                                            path_text(&root.join(relative_to_root))
                                        ));
                                        continue;
                                    }
                                }
                                let bytes = match fs::read(entry.path()) {
                                    Ok(bytes) => bytes,
                                    Err(_) => {
                                        errors.insert(format!(
                                            "filesystem inventory path cannot be read: {}",
                                            path_text(&root.join(relative_to_root))
                                        ));
                                        continue;
                                    }
                                };
                                let project_path = root.join(relative_to_root);
                                file_rows.push(json!({
                                    "path": path_text(&project_path),
                                    "bytes": bytes.len(),
                                    "sha256": raw_sha256(&bytes),
                                }));
                            }
                        }
                    }
                },
            }
        }
    }
    file_rows.sort_by(|left, right| {
        left["path"]
            .as_str()
            .unwrap_or_default()
            .cmp(right["path"].as_str().unwrap_or_default())
    });

    let contract = node.field_owned(&definition.implementation_contract_field);
    let contract_hash = contract
        .as_ref()
        .filter(|value| value.is_object())
        .map(normalized_hash);
    let bound_contract_fields = definition
        .contract_fields
        .iter()
        .map(|field| {
            (
                field.clone(),
                node.field_owned(field).unwrap_or(Value::Null),
            )
        })
        .collect::<BTreeMap<_, _>>();
    let contract_fields_hash = normalized_hash(&bound_contract_fields);
    if contract.as_ref().is_none_or(|value| !value.is_object()) {
        errors.insert(format!(
            "{} must be a mapping",
            definition.implementation_contract_field
        ));
    }
    let kind = node
        .field_owned(&definition.implementation_kind_field)
        .and_then(|value| value.as_str().map(str::trim).map(ToOwned::to_owned))
        .filter(|value| !value.is_empty());
    if kind.is_none() {
        errors.insert(format!(
            "{} is required",
            definition.implementation_kind_field
        ));
    }
    let raw_entrypoints = node
        .field_owned(&definition.implementation_entrypoints_field)
        .and_then(|value| value.as_array().cloned());
    if raw_entrypoints.as_ref().is_none_or(Vec::is_empty) {
        errors.insert(format!(
            "{} must be a nonempty list",
            definition.implementation_entrypoints_field
        ));
    }
    let inventory = file_rows
        .iter()
        .filter_map(|row| {
            row["path"]
                .as_str()
                .map(|path| (path.to_owned(), row.clone()))
        })
        .collect::<BTreeMap<_, _>>();
    let mut seen = BTreeSet::new();
    let mut entrypoints = Vec::new();
    for (index, value) in raw_entrypoints.unwrap_or_default().into_iter().enumerate() {
        let Some(raw) = value
            .as_str()
            .map(str::trim)
            .filter(|value| !value.is_empty())
        else {
            errors.insert(format!(
                "{}[{index}] must be a nonempty path string",
                definition.implementation_entrypoints_field
            ));
            continue;
        };
        let relative = match normalized_relative_filesystem_path(raw) {
            Ok(relative) => relative,
            Err(error) => {
                errors.insert(format!("implementation entrypoint {error}: {raw}"));
                continue;
            }
        };
        let normalized = path_text(&relative);
        if !seen.insert(normalized.clone()) {
            errors.insert(format!("duplicate implementation entrypoint: {normalized}"));
            continue;
        }
        let Some(root) = normalized_root.as_ref() else {
            errors.insert(format!(
                "implementation entrypoint cannot be validated without a root: {normalized}"
            ));
            continue;
        };
        if !relative.starts_with(root) {
            errors.insert(format!(
                "implementation entrypoint escapes configured root: {normalized}"
            ));
            continue;
        }
        let concrete = project_root.join(&relative);
        if definition.scan.symlinks == FilesystemSymlinkPolicy::Reject
            && filesystem_path_contains_symlink(project_root, &relative)
        {
            errors.insert(format!(
                "implementation entrypoint is a symlink: {normalized}"
            ));
            continue;
        }
        let resolved = match concrete.canonicalize() {
            Ok(resolved) => resolved,
            Err(_) => {
                errors.insert(format!(
                    "implementation entrypoint does not exist: {normalized}"
                ));
                continue;
            }
        };
        if canonical_root
            .as_ref()
            .is_none_or(|root| !resolved.starts_with(root))
            || project_canonical
                .as_ref()
                .is_none_or(|project_root| !resolved.starts_with(project_root))
        {
            errors.insert(format!(
                "implementation entrypoint escapes configured root: {normalized}"
            ));
            continue;
        }
        if !resolved.is_file() {
            errors.insert(format!(
                "implementation entrypoint is not a file: {normalized}"
            ));
            continue;
        }
        if resolved
            .metadata()
            .map_or(true, |metadata| metadata.len() == 0)
        {
            errors.insert(format!("implementation entrypoint is empty: {normalized}"));
            continue;
        }
        let Some(row) = inventory.get(&normalized) else {
            errors.insert(format!(
                "implementation entrypoint is absent from filesystem manifest: {normalized}"
            ));
            continue;
        };
        entrypoints.push(row.clone());
    }
    entrypoints.sort_by(|left, right| {
        left["path"]
            .as_str()
            .unwrap_or_default()
            .cmp(right["path"].as_str().unwrap_or_default())
    });

    let (source, external, vendor_status) = derive_filesystem_vendor_status(
        node,
        definition,
        project_root,
        canonical_root.as_deref(),
        &file_rows,
    );
    if vendor_status != "vendored" {
        errors.insert(format!(
            "filesystem vendor status is not ready: {vendor_status}"
        ));
    }
    let content_hash = normalized_hash(&json!({
        "root": normalized_root.as_ref().map(|path| path_text(path)),
        "source": source,
        "external": external,
        "vendor_status": vendor_status,
        "implementation_kind": kind,
        "implementation_contract_hash": contract_hash,
        "contract_fields_hash": contract_fields_hash,
        "entrypoints": entrypoints,
        "files": file_rows,
    }));
    let previous_accepted_hash = node
        .field_owned(&definition.output_field)
        .and_then(|manifest| {
            manifest
                .get("accepted_content_hash")
                .and_then(Value::as_str)
                .map(ToOwned::to_owned)
        });
    let structurally_ready = errors.is_empty() && !entrypoints.is_empty();
    let accepted_content_hash = if structurally_ready && accept_changes {
        Some(content_hash.clone())
    } else {
        previous_accepted_hash
    };
    if structurally_ready && accepted_content_hash.as_deref() != Some(content_hash.as_str()) {
        errors.insert("filesystem content hash requires scoped compiler acceptance".to_owned());
    }
    let implementation_errors = errors.into_iter().map(Value::String).collect::<Vec<_>>();
    let implementation_status = if implementation_errors.is_empty() {
        "ready"
    } else {
        "incomplete"
    };
    let mut manifest = json!({
        "schema_version": "1.0",
        "root": normalized_root.as_ref().map(|path| path_text(path)),
        "source": source,
        "external": external,
        "vendor_status": vendor_status,
        "implementation_status": implementation_status,
        "implementation_kind": kind,
        "implementation_contract_hash": contract_hash,
        "contract_fields_hash": contract_fields_hash,
        "content_hash": content_hash,
        "accepted_content_hash": accepted_content_hash,
        "entrypoint_count": entrypoints.len(),
        "file_count": file_rows.len(),
        "implementation_errors": implementation_errors,
        "entrypoints": entrypoints,
        "files": file_rows,
    });
    let hash = normalized_hash(&manifest);
    manifest["hash"] = Value::String(hash);
    manifest
}

fn ticket_can_accept_filesystem_manifest(
    ticket: &Ticket,
    node: &Node,
    definition: &FilesystemManifestDef,
) -> bool {
    if !ticket.scope.write_nodes.contains(&node.id) {
        return false;
    }
    let Some(root) = node
        .field_owned(&definition.root_field)
        .and_then(|value| value.as_str().map(ToOwned::to_owned))
        .and_then(|root| normalized_relative_filesystem_path(root.trim()).ok())
    else {
        return false;
    };
    ticket.scope.write_paths.iter().any(|configured| {
        normalized_relative_filesystem_path(configured)
            .is_ok_and(|configured| root == configured || root.starts_with(configured))
    })
}

fn normalized_relative_filesystem_path(raw: &str) -> std::result::Result<PathBuf, &'static str> {
    let path = Path::new(raw);
    if path.is_absolute() {
        return Err("must be project-relative");
    }
    let mut normalized = PathBuf::new();
    for component in path.components() {
        match component {
            std::path::Component::Normal(component) => normalized.push(component),
            std::path::Component::CurDir => {}
            std::path::Component::ParentDir => return Err("escapes the project"),
            std::path::Component::RootDir | std::path::Component::Prefix(_) => {
                return Err("must be project-relative");
            }
        }
    }
    if normalized.as_os_str().is_empty() {
        return Err("must be nonempty");
    }
    Ok(normalized)
}

fn path_text(path: &Path) -> String {
    path.to_string_lossy().replace('\\', "/")
}

fn filesystem_manifest_path_is_ignored(
    relative: &Path,
    definition: &FilesystemManifestDef,
) -> bool {
    let file_name = relative.file_name().and_then(|name| name.to_str());
    if file_name.is_some_and(|name| {
        definition
            .scan
            .ignored_file_names
            .iter()
            .any(|ignored| ignored == name)
    }) {
        return true;
    }
    if relative.components().any(|component| {
        component.as_os_str().to_str().is_some_and(|component| {
            definition
                .scan
                .ignored_path_components
                .iter()
                .any(|ignored| ignored == component)
        })
    }) {
        return true;
    }
    let lower = file_name.unwrap_or_default().to_ascii_lowercase();
    if definition
        .scan
        .ignored_suffixes
        .iter()
        .any(|suffix| lower.ends_with(&suffix.to_ascii_lowercase()))
    {
        return true;
    }
    definition.scan.ignored_path_prefixes.iter().any(|prefix| {
        normalized_relative_filesystem_path(prefix).is_ok_and(|prefix| relative.starts_with(prefix))
    })
}

fn filesystem_path_contains_symlink(project_root: &Path, relative: &Path) -> bool {
    let mut current = project_root.to_path_buf();
    for component in relative.components() {
        current.push(component.as_os_str());
        if fs::symlink_metadata(&current).is_ok_and(|metadata| metadata.file_type().is_symlink()) {
            return true;
        }
    }
    false
}

fn derive_filesystem_vendor_status(
    node: &Node,
    definition: &FilesystemManifestDef,
    project_root: &Path,
    canonical_root: Option<&Path>,
    file_rows: &[Value],
) -> (String, bool, String) {
    let Some(source_policy) = &definition.source else {
        return (
            "unspecified".to_owned(),
            false,
            if file_rows.is_empty() {
                "missing"
            } else {
                "vendored"
            }
            .to_owned(),
        );
    };
    let source = node
        .field_owned(&source_policy.field)
        .and_then(|value| value.as_str().map(str::trim).map(ToOwned::to_owned))
        .filter(|value| !value.is_empty())
        .unwrap_or_else(|| source_policy.unspecified_value.clone());
    let external = source_policy
        .external_values
        .iter()
        .any(|value| value.eq_ignore_ascii_case(&source));
    let Some(vendor) = &source_policy.vendor else {
        return (
            source,
            external,
            if file_rows.is_empty() {
                "missing"
            } else {
                "vendored"
            }
            .to_owned(),
        );
    };
    if vendor.blocked_reason_fields.iter().any(|field| {
        node.field_owned(field)
            .and_then(|value| value.as_str().map(str::trim).map(ToOwned::to_owned))
            .is_some_and(|value| !value.is_empty())
    }) {
        return (source, external, "blocked".to_owned());
    }
    let expected = vendor
        .path_fields
        .iter()
        .flat_map(|field| match node.field_owned(field) {
            Some(Value::String(value)) => vec![value],
            Some(Value::Array(values)) => values
                .into_iter()
                .filter_map(|value| value.as_str().map(ToOwned::to_owned))
                .collect(),
            _ => Vec::new(),
        })
        .collect::<Vec<_>>();
    if expected.is_empty() {
        return (
            source,
            external,
            if file_rows.is_empty() {
                "missing"
            } else {
                "vendored"
            }
            .to_owned(),
        );
    }
    let inventory = file_rows
        .iter()
        .filter_map(|row| row["path"].as_str().map(|path| (path, row)))
        .collect::<BTreeMap<_, _>>();
    let normalized_root = node
        .field_owned(&definition.root_field)
        .and_then(|value| value.as_str().map(ToOwned::to_owned))
        .and_then(|value| normalized_relative_filesystem_path(value.trim()).ok());
    for raw in expected {
        let Ok(relative) = normalized_relative_filesystem_path(raw.trim()) else {
            return (source, external, "invalid_path".to_owned());
        };
        let Some(relative_to_root) = normalized_root
            .as_ref()
            .and_then(|root| relative.strip_prefix(root).ok())
        else {
            return (source, external, "invalid_path".to_owned());
        };
        if filesystem_manifest_path_is_ignored(relative_to_root, definition)
            || (definition.scan.symlinks == FilesystemSymlinkPolicy::Reject
                && filesystem_path_contains_symlink(project_root, &relative))
        {
            return (source, external, "invalid_path".to_owned());
        }
        let concrete = project_root.join(&relative);
        let Ok(resolved) = concrete.canonicalize() else {
            return (source, external, "missing".to_owned());
        };
        if canonical_root.is_none_or(|root| !resolved.starts_with(root)) {
            return (source, external, "invalid_path".to_owned());
        }
        if !resolved.is_file() {
            return (source, external, "missing".to_owned());
        }
        let path = path_text(
            &normalized_root
                .as_ref()
                .expect("root checked above")
                .join(relative_to_root),
        );
        if inventory
            .get(path.as_str())
            .and_then(|row| row.get("bytes"))
            .and_then(Value::as_u64)
            .is_none_or(|bytes| bytes == 0)
        {
            return (source, external, "missing".to_owned());
        }
    }
    (source, external, "vendored".to_owned())
}

fn contained_join(root: &Path, relative: &Path) -> Result<PathBuf> {
    if relative.is_absolute()
        || relative
            .components()
            .any(|component| matches!(component, std::path::Component::ParentDir))
    {
        return Err(KoniError::Action(format!(
            "path escapes project root: {}",
            relative.display()
        )));
    }
    Ok(root.join(relative))
}

fn lookup_dynamic_path<'a>(
    root: &'a Value,
    path: &str,
    variables: &BTreeMap<String, String>,
) -> Option<&'a Value> {
    let mut value = root;
    for segment in split_dynamic_path(path)? {
        let field_end = segment.find('[').unwrap_or(segment.len());
        let field = &segment[..field_end];
        if !field.is_empty() {
            value = value.as_object()?.get(field)?;
        }

        let mut remainder = &segment[field_end..];
        while !remainder.is_empty() {
            let close = remainder.find(']')?;
            if !remainder.starts_with('[') {
                return None;
            }
            let raw_key = remainder[1..close].trim();
            let key = if let Some(variable) = raw_key.strip_prefix('$') {
                variables.get(variable)?.as_str()
            } else {
                raw_key.trim_matches(['\'', '"'])
            };
            value = match value {
                Value::Object(object) => object.get(key)?,
                Value::Array(items) => items.get(key.parse::<usize>().ok()?)?,
                _ => return None,
            };
            remainder = &remainder[close + 1..];
        }
    }
    Some(value)
}

fn split_dynamic_path(path: &str) -> Option<Vec<String>> {
    let mut segments = Vec::new();
    let mut current = String::new();
    let mut bracket_depth = 0_u32;
    for character in path.chars() {
        match character {
            '[' => {
                bracket_depth = bracket_depth.checked_add(1)?;
                current.push(character);
            }
            ']' => {
                bracket_depth = bracket_depth.checked_sub(1)?;
                current.push(character);
            }
            '.' if bracket_depth == 0 => {
                if current.is_empty() {
                    return None;
                }
                segments.push(std::mem::take(&mut current));
            }
            _ => current.push(character),
        }
    }
    if bracket_depth != 0 || current.is_empty() {
        return None;
    }
    segments.push(current);
    Some(segments)
}

/// Keep a long-lived agent out of the short-lived command runner's process
/// group. Codex command execution reaps processes left in its group when the
/// command returns; without this boundary, a successfully spawned ticket
/// worker can be killed before it emits `thread.started`.
#[cfg(unix)]
fn isolate_agent_process_group(command: &mut Command) {
    command.process_group(0);
}

#[cfg(not(unix))]
fn isolate_agent_process_group(_command: &mut Command) {}

const AGENT_RUNTIME_EXCLUDE_MARKER: &str = "# koni agent runtime (operational, never semantic)";

fn agent_runtime_repo_path(git: &GitBackend, runtime_tickets: &Path) -> Option<PathBuf> {
    let runtime_tickets = runtime_tickets.canonicalize().ok()?;
    let relative = runtime_tickets.strip_prefix(git.workdir()).ok()?;
    (!relative.as_os_str().is_empty()
        && relative.components().all(|component| {
            matches!(
                component,
                std::path::Component::Normal(_) | std::path::Component::CurDir
            )
        }))
    .then(|| relative.to_path_buf())
}

fn git_pattern_path(path: &Path) -> Result<String> {
    path.components()
        .filter_map(|component| match component {
            std::path::Component::Normal(value) => Some(value),
            std::path::Component::CurDir => None,
            _ => None,
        })
        .map(|component| {
            component.to_str().map(ToOwned::to_owned).ok_or_else(|| {
                KoniError::Profile(format!(
                    "agent runtime path is not valid UTF-8: {}",
                    path.display()
                ))
            })
        })
        .collect::<Result<Vec<_>>>()
        .map(|components| components.join("/"))
}

fn ensure_agent_runtime_excludes(git: &GitBackend, runtime_repo_path: Option<&Path>) -> Result<()> {
    let Some(runtime_repo_path) = runtime_repo_path else {
        return Ok(());
    };
    let runtime_pattern = git_pattern_path(runtime_repo_path)?;
    let path = git.common_dir().join("info/exclude");
    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent).map_err(|error| io_error(parent, error))?;
    }
    let existing = fs::read_to_string(&path).unwrap_or_default();

    // Remove only the legacy Koni-owned global block. Those patterns were
    // broad enough to hide product files named worker.log or worker.pid.
    let lines = existing.lines().collect::<Vec<_>>();
    let mut retained = Vec::new();
    let mut index = 0;
    while index < lines.len() {
        if lines[index] == AGENT_RUNTIME_EXCLUDE_MARKER {
            index += 1;
            while index < lines.len() && matches!(lines[index], "**/worker.log" | "**/worker.pid") {
                index += 1;
            }
            continue;
        }
        retained.push(lines[index].to_owned());
        index += 1;
    }

    let marker = format!("{AGENT_RUNTIME_EXCLUDE_MARKER}: /{runtime_pattern}");
    let log_pattern = format!("/{runtime_pattern}/**/worker.log");
    let pid_pattern = format!("/{runtime_pattern}/**/worker.pid");
    for line in [&marker, &log_pattern, &pid_pattern] {
        if !retained.iter().any(|existing| existing == line) {
            retained.push(line.clone());
        }
    }
    let mut updated = retained.join("\n");
    if !updated.is_empty() {
        updated.push('\n');
    }
    if updated == existing {
        return Ok(());
    }
    fs::write(&path, updated).map_err(|error| io_error(&path, error))
}

fn is_agent_runtime_path(path: &Path, runtime_repo_path: &Path) -> bool {
    let Ok(relative) = path.strip_prefix(runtime_repo_path) else {
        return false;
    };
    matches!(
        relative.file_name().and_then(|name| name.to_str()),
        Some("worker.log" | "worker.pid")
    ) && relative
        .parent()
        .is_some_and(|parent| !parent.as_os_str().is_empty())
}

fn cleanup_agent_runtime_artifacts(
    repository: &git2::Repository,
    runtime_repo_path: Option<&Path>,
) -> Result<(Vec<PathBuf>, Option<String>, git2::Index)> {
    let parent = repository.head()?.peel_to_commit()?;
    let parent_tree = parent.tree()?;
    let mut cleanup_index = git2::Index::new()?;
    cleanup_index.read_tree(&parent_tree)?;

    let mut runtime_paths = BTreeSet::new();
    if let Some(runtime_repo_path) = runtime_repo_path {
        runtime_paths.extend(
            cleanup_index
                .iter()
                .filter_map(|entry| String::from_utf8(entry.path.to_vec()).ok())
                .map(PathBuf::from)
                .filter(|path| is_agent_runtime_path(path, runtime_repo_path)),
        );
        let live_index = repository.index()?;
        runtime_paths.extend(
            live_index
                .iter()
                .filter_map(|entry| String::from_utf8(entry.path.to_vec()).ok())
                .map(PathBuf::from)
                .filter(|path| is_agent_runtime_path(path, runtime_repo_path)),
        );
    }
    for path in &runtime_paths {
        if cleanup_index.get_path(path, 0).is_some() {
            cleanup_index.remove_path(path)?;
        }
    }

    let runtime_free_tree = cleanup_index.write_tree_to(repository)?;
    let runtime_cleanup_commit = if runtime_free_tree != parent_tree.id() {
        let tree = repository.find_tree(runtime_free_tree)?;
        let signature = git2::Signature::now("Koni State", "koni-state@example.local")?;
        Some(
            repository
                .commit(
                    Some("HEAD"),
                    &signature,
                    &signature,
                    "chore(koni): detach agent runtime files",
                    &tree,
                    &[&parent],
                )?
                .to_string(),
        )
    } else {
        None
    };

    // The cleanup tree is built in-memory. Remove only Koni runtime entries
    // from the live index so unrelated staged changes retain their exact state.
    if !runtime_paths.is_empty() {
        let mut live_index = repository.index()?;
        let mut changed = false;
        for path in &runtime_paths {
            if live_index.get_path(path, 0).is_some() {
                live_index.remove_path(path)?;
                changed = true;
            }
        }
        if changed {
            live_index.write()?;
        }
    }

    Ok((
        runtime_paths.into_iter().collect(),
        runtime_cleanup_commit,
        cleanup_index,
    ))
}

fn resolved_agent_runtime_blocker(
    message: &str,
    runtime_repo_path: &Path,
    index: &git2::Index,
) -> bool {
    let Some(paths) = message.strip_prefix("action error: integration checkout is dirty: ") else {
        return false;
    };
    let paths = paths
        .split(',')
        .map(str::trim)
        .filter(|path| !path.is_empty())
        .map(PathBuf::from)
        .collect::<Vec<_>>();
    !paths.is_empty()
        && paths.iter().all(|path| {
            is_agent_runtime_path(path, runtime_repo_path) && index.get_path(path, 0).is_none()
        })
}

fn ticket_check_value(ticket: &Ticket, graph: &Graph) -> Value {
    let mut value = serde_json::to_value(ticket).expect("ticket serializes");
    let object = value.as_object_mut().expect("ticket serializes as object");
    if let Some(spec) = ticket
        .target_nodes
        .first()
        .and_then(|id| graph.node(id))
        .and_then(|node| node.spec.as_object())
    {
        for (key, value) in spec {
            object.entry(key.clone()).or_insert_with(|| value.clone());
        }
    }
    for (key, value) in &ticket.extensions {
        object.insert(key.clone(), value.clone());
    }
    value
}

#[derive(Clone)]
struct EffectiveCommandSource {
    kind: DynamicSourceKind,
    field: String,
    role: String,
    selection: Option<DynamicNodeSelection>,
    node_types: Vec<String>,
    gate_policy: Option<String>,
}

fn effective_command_source(
    check: &crate::config::CheckDef,
    ticket: Option<&Ticket>,
    graph: &Graph,
) -> Result<Option<EffectiveCommandSource>> {
    if let Some(source) = &check.command_source {
        return Ok(Some(EffectiveCommandSource {
            kind: source.kind,
            field: source.field.clone(),
            role: source.role.clone(),
            selection: source.selection,
            node_types: source.node_types.clone(),
            gate_policy: source.gate_policy.clone(),
        }));
    }
    let Some(legacy) = check.argv_from.as_ref().and_then(Value::as_str) else {
        return Ok(None);
    };
    let (root, field) = legacy.split_once('.').unwrap_or(("target", legacy));
    if field.trim().is_empty() {
        return Err(KoniError::Profile(format!(
            "check {} has an empty legacy argv_from field",
            check.id
        )));
    }
    if root == "ticket" {
        return Ok(Some(EffectiveCommandSource {
            kind: DynamicSourceKind::Ticket,
            field: field.to_owned(),
            role: "ticket".to_owned(),
            selection: None,
            node_types: Vec::new(),
            gate_policy: None,
        }));
    }
    if root == "target" {
        let node_types = ticket
            .into_iter()
            .flat_map(|ticket| &ticket.target_nodes)
            .filter_map(|id| graph.node(id).map(|node| node.node_type.clone()))
            .collect::<BTreeSet<_>>()
            .into_iter()
            .collect();
        return Ok(Some(EffectiveCommandSource {
            kind: DynamicSourceKind::Node,
            field: field.to_owned(),
            role: "target".to_owned(),
            selection: Some(DynamicNodeSelection::Target),
            node_types,
            gate_policy: None,
        }));
    }
    Ok(Some(EffectiveCommandSource {
        kind: DynamicSourceKind::Node,
        field: field.to_owned(),
        role: root.to_owned(),
        selection: Some(DynamicNodeSelection::ReadScope),
        node_types: vec![root.to_owned()],
        gate_policy: None,
    }))
}

fn command_variables(ticket: Option<&Ticket>, graph: &Graph) -> BTreeMap<String, String> {
    let mut variables = BTreeMap::new();
    if let Some(ticket) = ticket {
        variables.insert("ticket.id".to_owned(), ticket.id.clone());
        if let Some(target) = ticket.target_nodes.first().and_then(|id| graph.node(id)) {
            variables.insert("target.id".to_owned(), target.id.clone());
            variables.insert(format!("{}.id", target.node_type), target.id.clone());
        }
    }
    variables
}

fn resolve_execution_candidate(
    profile: &CompiledProfile,
    check: &crate::config::CheckDef,
    source: &EffectiveCommandSource,
    invocation: CheckInvocation<'_>,
    graph: &Graph,
    project_root: &Path,
    policy_store: &StateStore,
) -> Result<ResolvedExecutionCandidate> {
    let ticket = match invocation {
        CheckInvocation::Ticket(ticket) => Some(ticket),
        CheckInvocation::Unscoped | CheckInvocation::GatePolicy { .. } => None,
    };
    if source.kind == DynamicSourceKind::Ticket {
        let ticket = ticket.ok_or_else(|| {
            KoniError::Action(format!(
                "dynamic check {} ticket command source cannot run automatically",
                check.id
            ))
        })?;
        let base_variables = command_variables(Some(ticket), graph);
        let value = ticket_check_value(ticket, graph);
        let command =
            lookup_dynamic_path(&value, &source.field, &base_variables).ok_or_else(|| {
                KoniError::Action(format!(
                    "check {} ticket source {} is missing",
                    check.id, source.field
                ))
            })?;
        let argv = command_value_argv(check, command)?;
        let semantic = json!({
            "ticket_id": ticket.id,
            "operation": ticket.operation,
            "target_nodes": ticket.target_nodes,
            "scope": ticket.scope,
            "command_field": source.field,
            "command": command,
        });
        return Ok(ResolvedExecutionCandidate {
            kind: "ticket".to_owned(),
            role: source.role.clone(),
            id: ticket.id.clone(),
            node_type: None,
            field: source.field.clone(),
            semantic_hash: normalized_hash(&semantic),
            value,
            argv,
            variables: base_variables,
            gate_policy_binding: None,
        });
    }

    if let Some(policy_id) = &source.gate_policy {
        let (invocation_policy_id, gate_id) = match invocation {
            CheckInvocation::GatePolicy { policy_id, gate_id } => (policy_id, gate_id),
            CheckInvocation::Ticket(ticket) => {
                let policy = profile.gate_policies.get(policy_id).ok_or_else(|| {
                    KoniError::Profile(format!(
                        "check {} references missing gate policy {}",
                        check.id, policy_id
                    ))
                })?;
                let gates = ticket
                    .target_nodes
                    .iter()
                    .filter_map(|id| graph.node(id))
                    .filter(|node| policy.gate_node_types.contains(&node.node_type))
                    .collect::<Vec<_>>();
                if gates.len() != 1 {
                    return Err(KoniError::Action(format!(
                        "check {} gate policy {} requires exactly one ticket-authorized gate target, found {}",
                        check.id,
                        policy_id,
                        gates.len()
                    )));
                }
                (policy_id.as_str(), gates[0].id.as_str())
            }
            CheckInvocation::Unscoped => {
                return Err(KoniError::Action(format!(
                    "check {} gate policy command requires a gate subject",
                    check.id
                )));
            }
        };
        if invocation_policy_id != policy_id {
            return Err(KoniError::Profile(format!(
                "check {} is bound to gate policy {}, not {}",
                check.id, policy_id, invocation_policy_id
            )));
        }
        let resolver = GraphResolver::new(graph, profile, policy_store, project_root);
        let binding = resolver.gate_policy_binding(policy_id, gate_id)?;
        let winner = binding.selection.winner_id.as_deref().ok_or_else(|| {
            KoniError::Action(format!(
                "check {} gate policy {} selected no winner from {} compatible candidates",
                check.id,
                policy_id,
                binding.selection.compatible_candidates.len()
            ))
        })?;
        let node = graph.node(winner).ok_or_else(|| {
            KoniError::Action(format!(
                "check {} gate policy {} winner {} is missing",
                check.id, policy_id, winner
            ))
        })?;
        if !source.node_types.contains(&node.node_type) {
            return Err(KoniError::Action(format!(
                "check {} gate policy {} winner {} has unauthorized type {}",
                check.id, policy_id, winner, node.node_type
            )));
        }
        let value = node.as_value();
        let mut variables = BTreeMap::new();
        variables.insert("gate.id".to_owned(), gate_id.to_owned());
        if binding.evaluation_targets.len() == 1
            && let Some(target_id) = binding.evaluation_targets.keys().next()
        {
            variables.insert("target.id".to_owned(), target_id.clone());
            if let Some(target) = graph.node(target_id) {
                variables.insert(format!("{}.id", target.node_type), target.id.clone());
            }
        }
        variables.insert(format!("{}.id", source.role), node.id.clone());
        variables.insert(format!("{}.id", node.node_type), node.id.clone());
        let command = lookup_dynamic_path(&value, &source.field, &variables).ok_or_else(|| {
            KoniError::Action(format!(
                "check {} gate policy {} winner {} lacks command field {}; selection will not fall through",
                check.id, policy_id, node.id, source.field
            ))
        })?;
        let argv = command_value_argv(check, command)?;
        let definition = &profile.node_types[&node.node_type];
        return Ok(ResolvedExecutionCandidate {
            kind: "gate_policy".to_owned(),
            role: source.role.clone(),
            id: node.id.clone(),
            node_type: Some(node.node_type.clone()),
            field: source.field.clone(),
            semantic_hash: semantic_receipt_node_hash(
                node,
                &definition.semantic_fields,
                &definition.compiler_owned_fields,
            ),
            value,
            argv,
            variables,
            gate_policy_binding: Some(binding),
        });
    }

    let ticket = ticket.ok_or_else(|| {
        KoniError::Action(format!(
            "dynamic check {} requires an exact ticket",
            check.id
        ))
    })?;
    let base_variables = command_variables(Some(ticket), graph);

    let authorized_ids = match source.selection {
        Some(DynamicNodeSelection::Target) => ticket.target_nodes.iter().collect::<BTreeSet<_>>(),
        Some(DynamicNodeSelection::ReadScope) => {
            ticket.scope.read_nodes.iter().collect::<BTreeSet<_>>()
        }
        None => {
            return Err(KoniError::Profile(format!(
                "node command source for check {} has no bounded selection",
                check.id
            )));
        }
    };
    let mut matches = Vec::new();
    for id in authorized_ids {
        let node = graph.node(id).ok_or_else(|| {
            KoniError::Action(format!(
                "check {} authorized command source node {} is missing",
                check.id, id
            ))
        })?;
        if !source.node_types.contains(&node.node_type) {
            continue;
        }
        let value = node.as_value();
        let mut variables = base_variables.clone();
        variables.insert(format!("{}.id", source.role), node.id.clone());
        variables.insert(format!("{}.id", node.node_type), node.id.clone());
        let Some(command) = lookup_dynamic_path(&value, &source.field, &variables) else {
            continue;
        };
        let argv = command_value_argv(check, command)?;
        let definition = profile.node_types.get(&node.node_type).ok_or_else(|| {
            KoniError::Profile(format!(
                "check {} source node {} has unknown type {}",
                check.id, node.id, node.node_type
            ))
        })?;
        matches.push(ResolvedExecutionCandidate {
            kind: "node".to_owned(),
            role: source.role.clone(),
            id: node.id.clone(),
            node_type: Some(node.node_type.clone()),
            field: source.field.clone(),
            semantic_hash: semantic_receipt_node_hash(
                node,
                &definition.semantic_fields,
                &definition.compiler_owned_fields,
            ),
            value,
            argv,
            variables,
            gate_policy_binding: None,
        });
    }
    if matches.len() != 1 {
        return Err(KoniError::Action(format!(
            "check {} resolved {} authorized {} command sources for role {}, expected exactly one",
            check.id,
            matches.len(),
            source
                .node_types
                .iter()
                .map(String::as_str)
                .collect::<Vec<_>>()
                .join("/"),
            source.role,
        )));
    }
    Ok(matches.pop().expect("one dynamic command source"))
}

fn command_value_argv(check: &crate::config::CheckDef, value: &Value) -> Result<Vec<String>> {
    let values = value.as_array().ok_or_else(|| {
        KoniError::Action(format!(
            "check {} command source is not an argv array",
            check.id
        ))
    })?;
    let argv = values
        .iter()
        .map(|value| value.as_str().map(ToOwned::to_owned))
        .collect::<Option<Vec<_>>>()
        .ok_or_else(|| {
            KoniError::Action(format!(
                "check {} command source contains a non-string argument",
                check.id
            ))
        })?;
    if argv.is_empty() || argv[0].trim().is_empty() || argv.iter().any(|arg| arg.contains('\0')) {
        return Err(KoniError::Action(format!(
            "check {} command source must be a nonempty NUL-free argv",
            check.id
        )));
    }
    Ok(argv)
}

fn semantic_command_bindings(
    profile: &CompiledProfile,
    graph: &Graph,
    ids: impl IntoIterator<Item = String>,
    owner: &str,
) -> Result<BTreeMap<String, SemanticCommandBinding>> {
    ids.into_iter()
        .collect::<BTreeSet<_>>()
        .into_iter()
        .map(|id| {
            let node = graph.node(&id).ok_or_else(|| {
                KoniError::Action(format!("{owner} references missing node {id}"))
            })?;
            let definition = profile.node_types.get(&node.node_type).ok_or_else(|| {
                KoniError::Profile(format!(
                    "{owner} references unknown node type {}",
                    node.node_type
                ))
            })?;
            Ok((
                id,
                SemanticCommandBinding {
                    node_type: node.node_type.clone(),
                    semantic_hash: semantic_receipt_node_hash(
                        node,
                        &definition.semantic_fields,
                        &definition.compiler_owned_fields,
                    ),
                },
            ))
        })
        .collect()
}

fn dynamic_bound_value<'a>(
    source: &crate::config::DynamicBoundValueSourceDef,
    candidate: &'a ResolvedExecutionCandidate,
    ticket_value: &'a Value,
) -> Option<&'a Value> {
    let root = if source.role == "ticket" {
        ticket_value
    } else if source.role == candidate.role {
        &candidate.value
    } else {
        return None;
    };
    lookup_dynamic_path(root, &source.field, &candidate.variables)
}

fn path_is_covered_by_ticket_scope(path: &str, scopes: &BTreeSet<String>) -> bool {
    scopes.iter().any(|allowed| {
        allowed == "."
            || normalized_relative_filesystem_path(allowed).is_ok_and(|allowed| {
                Path::new(path) == allowed || Path::new(path).starts_with(allowed)
            })
    })
}

fn dynamic_path_authority_matches(
    authority: &crate::config::DynamicPathAuthorityDef,
    path: &str,
    ticket: &Ticket,
) -> bool {
    match authority.authority {
        crate::config::TicketPathAuthority::ReadPaths => {
            path_is_covered_by_ticket_scope(path, &ticket.scope.read_paths)
        }
        crate::config::TicketPathAuthority::WritePaths => {
            path_is_covered_by_ticket_scope(path, &ticket.scope.write_paths)
        }
    }
}

fn dynamic_path_authorities_have_scope(
    authorities: &[crate::config::DynamicPathAuthorityDef],
    ticket: &Ticket,
) -> bool {
    authorities
        .iter()
        .any(|authority| match authority.authority {
            crate::config::TicketPathAuthority::ReadPaths => !ticket.scope.read_paths.is_empty(),
            crate::config::TicketPathAuthority::WritePaths => !ticket.scope.write_paths.is_empty(),
        })
}

fn resolved_dynamic_requirements(
    check: &crate::config::CheckDef,
    candidate: &ResolvedExecutionCandidate,
    ticket_value: &Value,
    ticket: Option<&Ticket>,
    project_root: &Path,
) -> Result<(Value, Option<String>)> {
    let Some(configured) = &check.dynamic_result else {
        return Ok((json!({}), None));
    };
    let mut requirements = Map::new();
    if let Some(required) = &configured.required_keys {
        let values = dynamic_bound_value(&required.source, candidate, ticket_value)
            .and_then(Value::as_array)
            .ok_or_else(|| {
                KoniError::Action(format!(
                    "check {} required-key source {}.{} is not an array",
                    check.id, required.source.role, required.source.field
                ))
            })?;
        let expected = values
            .iter()
            .map(Value::as_str)
            .collect::<Option<Vec<_>>>()
            .ok_or_else(|| {
                KoniError::Action(format!(
                    "check {} required-key source contains a non-string value",
                    check.id
                ))
            })?;
        let unique = expected.iter().copied().collect::<BTreeSet<_>>();
        if expected.is_empty()
            || unique.len() != expected.len()
            || expected.iter().any(|value| value.trim().is_empty())
        {
            return Err(KoniError::Action(format!(
                "check {} required-key source must be nonempty, unique, and contain nonempty strings",
                check.id
            )));
        }
        requirements.insert(
            "required_keys".to_owned(),
            json!({
                "source_role": required.source.role,
                "source_field": required.source.field,
                "actual_field": required.actual_field,
                "relation": required.relation,
                "expected": unique,
            }),
        );
    }
    if configured.result_path.is_none() && configured.artifacts.is_none() {
        return Ok((Value::Object(requirements), None));
    }
    let ticket = ticket.ok_or_else(|| {
        KoniError::Action(format!(
            "check {} dynamic result path authority requires an exact ticket",
            check.id
        ))
    })?;
    let result_path = if let Some(configured_path) = &configured.result_path {
        let source = &configured_path.source;
        match dynamic_bound_value(source, candidate, ticket_value) {
            None | Some(Value::Null) => None,
            Some(Value::String(raw)) if raw.trim().is_empty() => {
                return Err(KoniError::Action(format!(
                    "check {} result-path source {}.{} must be a nonempty project-relative path when present",
                    check.id, source.role, source.field
                )));
            }
            Some(Value::String(raw)) => {
                if !dynamic_path_authorities_have_scope(&configured_path.path_authorities, ticket) {
                    return Err(KoniError::Action(format!(
                        "check {} result path has no configured nonempty ticket path authority",
                        check.id
                    )));
                }
                let normalized = normalized_relative_path(raw)?;
                // The file may be created by the command, but its parent and
                // eventual resolution must already be project-contained.
                contained_process_path(project_root, &normalized)?;
                if !configured_path
                    .path_authorities
                    .iter()
                    .any(|authority| dynamic_path_authority_matches(authority, &normalized, ticket))
                {
                    return Err(KoniError::Action(format!(
                        "check {} result path is outside its configured ticket path authorities: {normalized}",
                        check.id
                    )));
                }
                requirements.insert(
                    "result_path".to_owned(),
                    json!({
                        "source_role": source.role,
                        "source_field": source.field,
                        "path": normalized,
                        "path_authorities": configured_path.path_authorities,
                    }),
                );
                Some(normalized)
            }
            Some(_) => {
                return Err(KoniError::Action(format!(
                    "check {} result-path source {}.{} must be a string when present",
                    check.id, source.role, source.field
                )));
            }
        }
    } else {
        None
    };
    if let Some(artifacts) = &configured.artifacts {
        requirements.insert(
            "artifacts".to_owned(),
            json!({
                "field": artifacts.field,
                "allow_path_strings": artifacts.allow_path_strings,
                "path_field": artifacts.path_field,
                "path_authorities": artifacts.path_authorities,
            }),
        );
    }
    Ok((Value::Object(requirements), result_path))
}

fn argv_input_rows(
    profile: &CompiledProfile,
    check: &crate::config::CheckDef,
    candidate: &ResolvedExecutionCandidate,
    graph: &Graph,
    project_root: &Path,
    ticket: Option<&Ticket>,
) -> Result<Vec<Value>> {
    let Some(bindings) = &check.argv_input_bindings else {
        return Ok(Vec::new());
    };
    validate_argv_input_bindings(
        Some(bindings),
        &candidate.value,
        &candidate.argv,
        project_root,
        &candidate.variables,
    )?;
    let inputs = lookup_dynamic_path(&candidate.value, &bindings.from, &candidate.variables)
        .and_then(Value::as_array)
        .expect("validated argv input array");
    inputs
        .iter()
        .map(|input| {
            let path = lookup_dynamic_path(input, &bindings.path_field, &candidate.variables)
                .and_then(Value::as_str)
                .unwrap_or_default();
            let file = if path.is_empty() {
                Value::Null
            } else {
                let path = normalized_relative_path(path)?;
                if let Some(ticket) = ticket
                    && !ticket.scope.read_paths.iter().any(|allowed| {
                        allowed == "."
                            || normalized_relative_filesystem_path(allowed).is_ok_and(|allowed| {
                                Path::new(&path) == allowed || Path::new(&path).starts_with(allowed)
                            })
                    })
                {
                    return Err(KoniError::Action(format!(
                        "check {} argv input path is outside ticket read scope: {path}",
                        check.id
                    )));
                }
                let concrete = contained_process_path(project_root, &path)?;
                let bytes = fs::read(&concrete).map_err(|error| io_error(&concrete, error))?;
                json!({"path": path, "bytes": bytes.len(), "sha256": raw_sha256(&bytes)})
            };
            let mut referenced_ids = BTreeSet::new();
            collect_graph_node_references(input, graph, &mut referenced_ids);
            if let Some(ticket) = ticket {
                let authorized = ticket
                    .target_nodes
                    .iter()
                    .chain(&ticket.scope.read_nodes)
                    .collect::<BTreeSet<_>>();
                let outside = referenced_ids
                    .iter()
                    .filter(|id| !authorized.contains(id))
                    .cloned()
                    .collect::<Vec<_>>();
                if !outside.is_empty() {
                    return Err(KoniError::Action(format!(
                        "check {} argv inputs reference out-of-scope graph nodes: {}",
                        check.id,
                        outside.join(", ")
                    )));
                }
            }
            let referenced_node_hashes = referenced_ids
                .into_iter()
                .map(|id| {
                    let node = graph.node(&id).expect("collected graph node exists");
                    let definition = &profile.node_types[&node.node_type];
                    (
                        id,
                        semantic_receipt_node_hash(
                            node,
                            &definition.semantic_fields,
                            &definition.compiler_owned_fields,
                        ),
                    )
                })
                .collect::<BTreeMap<_, _>>();
            Ok(json!({
                "binding": input,
                "file": file,
                "referenced_node_hashes": referenced_node_hashes,
            }))
        })
        .collect()
}

fn resolve_check_execution_with_store(
    profile: &CompiledProfile,
    check: &crate::config::CheckDef,
    ticket: Option<&Ticket>,
    graph: &Graph,
    project_root: &Path,
    policy_store: &StateStore,
) -> Result<ResolvedCheckExecution> {
    let invocation = ticket.map_or(CheckInvocation::Unscoped, CheckInvocation::Ticket);
    resolve_check_execution_for_invocation(
        profile,
        check,
        invocation,
        graph,
        project_root,
        policy_store,
        &mut ExecutionResolutionCache::default(),
    )
}

#[allow(clippy::too_many_arguments)]
fn resolve_gate_policy_check_execution_with_store(
    profile: &CompiledProfile,
    check: &crate::config::CheckDef,
    policy_id: &str,
    gate_id: &str,
    graph: &Graph,
    project_root: &Path,
    policy_store: &StateStore,
    cache: &mut ExecutionResolutionCache,
) -> Result<ResolvedCheckExecution> {
    resolve_check_execution_for_invocation(
        profile,
        check,
        CheckInvocation::GatePolicy { policy_id, gate_id },
        graph,
        project_root,
        policy_store,
        cache,
    )
}

fn resolve_check_execution_for_invocation(
    profile: &CompiledProfile,
    check: &crate::config::CheckDef,
    invocation: CheckInvocation<'_>,
    graph: &Graph,
    project_root: &Path,
    policy_store: &StateStore,
    cache: &mut ExecutionResolutionCache,
) -> Result<ResolvedCheckExecution> {
    let ticket = match invocation {
        CheckInvocation::Ticket(ticket) => Some(ticket),
        CheckInvocation::Unscoped | CheckInvocation::GatePolicy { .. } => None,
    };
    let source = effective_command_source(check, ticket, graph)?;
    let candidate = if let Some(source) = &source {
        resolve_execution_candidate(
            profile,
            check,
            source,
            invocation,
            graph,
            project_root,
            policy_store,
        )?
    } else {
        let argv = check.argv.clone();
        if argv.is_empty() {
            return Err(KoniError::Profile(format!(
                "check {} has no configured command",
                check.id
            )));
        }
        ResolvedExecutionCandidate {
            kind: "static".to_owned(),
            role: "configured".to_owned(),
            id: check.id.clone(),
            node_type: None,
            field: "argv".to_owned(),
            semantic_hash: normalized_hash(&argv),
            value: json!({"argv": argv}),
            argv,
            variables: command_variables(ticket, graph),
            gate_policy_binding: None,
        }
    };
    let ticket_value = ticket
        .map(|ticket| ticket_check_value(ticket, graph))
        .unwrap_or_else(|| json!({}));
    let (dynamic_requirements, result_path) =
        resolved_dynamic_requirements(check, &candidate, &ticket_value, ticket, project_root)?;
    let argv_input_rows = argv_input_rows(profile, check, &candidate, graph, project_root, ticket)?;
    let (
        target_bindings,
        read_scope_bindings,
        read_path_manifest,
        read_path_exclusions,
        produced_path_roots,
    ) = if let Some(binding) = &candidate.gate_policy_binding {
        if let Some(ticket) = ticket {
            authorize_ticket_gate_policy_execution(check, ticket, binding)?;
            for path in &binding.context_read_paths {
                if !path_is_covered_by_ticket_scope(path, &ticket.scope.read_paths) {
                    return Err(KoniError::Action(format!(
                        "check {} gate policy {} context read path {} is outside ticket read scope",
                        check.id, binding.selection.policy_id, path
                    )));
                }
            }
        }
        let read_path_exclusions =
            command_read_path_exclusions(profile, std::iter::empty::<&str>())?;
        (
            BTreeMap::new(),
            BTreeMap::new(),
            project_read_path_manifest(
                project_root,
                &binding.context_read_paths.iter().cloned().collect(),
                &read_path_exclusions,
            )?,
            read_path_exclusions.into_iter().collect(),
            Vec::new(),
        )
    } else if let Some(ticket) = ticket {
        let produced_path_roots = if check.effect == crate::config::ProcessEffect::WorkspaceWrite
            && dynamic_result_allows_produced_output(check)
        {
            ticket
                .scope
                .write_paths
                .iter()
                .map(|path| {
                    if path == "." {
                        Ok(".".to_owned())
                    } else {
                        normalized_relative_path(path)
                    }
                })
                .collect::<Result<Vec<_>>>()?
        } else {
            Vec::new()
        };
        let read_path_exclusions =
            command_read_path_exclusions(profile, produced_path_roots.iter().map(String::as_str))?;
        (
            semantic_command_bindings(
                profile,
                graph,
                ticket.target_nodes.clone(),
                &format!("check {} target scope", check.id),
            )?,
            semantic_command_bindings(
                profile,
                graph,
                ticket.scope.read_nodes.iter().cloned(),
                &format!("check {} read scope", check.id),
            )?,
            project_read_path_manifest(
                project_root,
                &ticket.scope.read_paths,
                &read_path_exclusions,
            )?,
            read_path_exclusions.into_iter().collect(),
            produced_path_roots,
        )
    } else {
        (
            BTreeMap::new(),
            BTreeMap::new(),
            Vec::new(),
            Vec::new(),
            Vec::new(),
        )
    };
    let sandbox_read_paths = candidate
        .gate_policy_binding
        .as_ref()
        .map(|binding| binding.context_read_paths.clone())
        .or_else(|| {
            ticket.map(|ticket| ticket.scope.read_paths.iter().cloned().collect::<Vec<_>>())
        })
        .unwrap_or_default();
    let environment_policy = EnvironmentPolicy {
        inherit: !check.environment.inherit.is_empty(),
        allow: check.environment.inherit.iter().cloned().collect(),
        deny: check.environment.remove.iter().cloned().collect(),
        set: check.environment.set.clone(),
    };
    let mut environment = resolved_environment(&environment_policy, &candidate.variables)?;
    let private_temp_required = check.effect == crate::config::ProcessEffect::ReadOnly;
    if private_temp_required {
        for (key, value) in [
            ("TMPDIR", "<PRIVATE_TMP>"),
            ("XDG_CACHE_HOME", "<PRIVATE_TMP>/xdg-cache"),
            ("npm_config_cache", "<PRIVATE_TMP>/npm-cache"),
            ("CARGO_TARGET_DIR", "<PRIVATE_TMP>/cargo-target"),
            ("PYTHONPYCACHEPREFIX", "<PRIVATE_TMP>/python-cache"),
            ("COVERAGE_FILE", "<PRIVATE_TMP>/coverage"),
            ("NEXT_TELEMETRY_DISABLED", "1"),
        ] {
            environment.insert(key.to_owned(), value.to_owned());
        }
    }
    let environment_bindings = environment
        .iter()
        .map(|(name, value)| (name.clone(), raw_sha256(value.as_bytes())))
        .collect::<BTreeMap<_, _>>();
    let mut argv = candidate
        .argv
        .iter()
        .map(|argument| interpolate_command(argument, &candidate.variables))
        .collect::<Result<Vec<_>>>()?;
    if argv.is_empty() {
        return Err(KoniError::Profile(format!(
            "check {} has no resolved command",
            check.id
        )));
    }
    let cwd = interpolate_command(&check.cwd.to_string_lossy(), &candidate.variables)?;
    let executable = resolve_executable_binding(project_root, &cwd, &argv[0], &environment, cache)?;
    argv[0] = executable.resolved_path.clone();
    let (sandbox_executable, sandbox_profile_hash) = resolve_read_only_sandbox(
        check.effect,
        project_root,
        &cwd,
        &sandbox_read_paths,
        &argv,
        &environment,
        cache,
    )?;
    let mut resolved = ResolvedCheckExecution {
        schema_version: "1.0".to_owned(),
        profile_hash: profile.hash.clone(),
        check_id: check.id.clone(),
        source_kind: candidate.kind,
        source_role: candidate.role,
        source_id: candidate.id,
        source_node_type: candidate.node_type,
        source_field: candidate.field,
        source_semantic_hash: candidate.semantic_hash,
        cwd,
        command_hash: normalized_hash(&argv),
        argv,
        environment_policy_hash: normalized_hash(&environment_policy),
        environment_bindings,
        executable,
        sandbox_executable,
        sandbox_profile_hash,
        private_temp_required,
        target_bindings,
        read_scope_bindings,
        read_path_manifest,
        read_path_exclusions,
        produced_path_roots,
        argv_input_rows,
        dynamic_requirements,
        result_path,
        gate_policy_binding: candidate.gate_policy_binding,
        binding_hash: String::new(),
    };
    resolved.binding_hash = normalized_hash(&resolved);
    Ok(resolved)
}

fn authorize_ticket_gate_policy_execution(
    check: &crate::config::CheckDef,
    ticket: &Ticket,
    binding: &GatePolicyBinding,
) -> Result<()> {
    if !ticket.target_nodes.contains(&binding.selection.gate.id) {
        return Err(KoniError::Action(format!(
            "check {} gate policy {} subject {} is not a ticket target",
            check.id, binding.selection.policy_id, binding.selection.gate.id
        )));
    }
    let authorized = ticket
        .target_nodes
        .iter()
        .chain(&ticket.scope.read_nodes)
        .chain(&ticket.scope.write_nodes)
        .cloned()
        .collect::<BTreeSet<_>>();
    let required = std::iter::once(binding.selection.gate.id.clone())
        .chain(binding.selection.winner_id.iter().cloned())
        .chain(binding.evaluation_targets.keys().cloned())
        .chain(binding.direct_gate_bindings.keys().cloned())
        .chain(binding.inherited_gate_bindings.keys().cloned())
        .chain(binding.applicability_context_bindings.keys().cloned())
        .chain(binding.context_bindings.keys().cloned())
        .collect::<BTreeSet<_>>();
    let unauthorized = required
        .difference(&authorized)
        .cloned()
        .collect::<Vec<_>>();
    if !unauthorized.is_empty() {
        return Err(KoniError::Action(format!(
            "check {} gate policy {} requires graph context outside ticket scope: {}",
            check.id,
            binding.selection.policy_id,
            unauthorized.join(", ")
        )));
    }
    Ok(())
}

fn execution_variables(
    invocation: CheckInvocation<'_>,
    execution: &ResolvedCheckExecution,
    graph: &Graph,
) -> BTreeMap<String, String> {
    let mut variables = match invocation {
        CheckInvocation::Ticket(ticket) => command_variables(Some(ticket), graph),
        CheckInvocation::Unscoped | CheckInvocation::GatePolicy { .. } => BTreeMap::new(),
    };
    if let Some(binding) = &execution.gate_policy_binding {
        variables.insert("gate.id".to_owned(), binding.selection.gate.id.clone());
        if binding.evaluation_targets.len() == 1
            && let Some(target_id) = binding.evaluation_targets.keys().next()
        {
            variables.insert("target.id".to_owned(), target_id.clone());
            if let Some(target) = graph.node(target_id) {
                variables.insert(format!("{}.id", target.node_type), target.id.clone());
            }
        }
        variables.insert(
            format!("{}.id", execution.source_role),
            execution.source_id.clone(),
        );
        if let Some(node_type) = &execution.source_node_type {
            variables.insert(format!("{node_type}.id"), execution.source_id.clone());
        }
    }
    variables
}

fn resolve_executable_binding(
    project_root: &Path,
    cwd: &str,
    requested: &str,
    environment: &BTreeMap<String, String>,
    cache: &mut ExecutionResolutionCache,
) -> Result<ExecutableBinding> {
    if requested.trim().is_empty() || requested.contains('\0') {
        return Err(KoniError::Process(
            "resolved executable must be nonempty and NUL-free".to_owned(),
        ));
    }
    let command_cwd = contained_process_path(project_root, cwd)?;
    let requested_path = Path::new(requested);
    let resolved = if requested_path.is_absolute() || requested.contains('/') {
        let candidate = if requested_path.is_absolute() {
            requested_path.to_path_buf()
        } else {
            command_cwd.join(requested_path)
        };
        canonical_regular_executable(&candidate, requested)?
    } else {
        let path_value = environment.get("PATH").ok_or_else(|| {
            KoniError::Process(format!(
                "cannot resolve executable {requested}: the bound environment has no PATH"
            ))
        })?;
        let mut found = None;
        for entry in std::env::split_paths(path_value) {
            let directory = if entry.as_os_str().is_empty() {
                command_cwd.clone()
            } else if entry.is_absolute() {
                entry
            } else {
                command_cwd.join(entry)
            };
            let candidate = directory.join(requested);
            if !candidate.exists() {
                continue;
            }
            found = Some(canonical_regular_executable(&candidate, requested)?);
            break;
        }
        found.ok_or_else(|| {
            KoniError::Process(format!(
                "cannot resolve executable {requested} from the bound PATH"
            ))
        })?
    };
    let metadata = fs::metadata(&resolved).map_err(|error| io_error(&resolved, error))?;
    #[cfg(unix)]
    if metadata.mode() & 0o111 == 0 {
        return Err(KoniError::Process(format!(
            "resolved executable {requested} at {} has no executable permission bit",
            resolved.display()
        )));
    }
    let modified = metadata
        .modified()
        .ok()
        .and_then(|value| value.duration_since(UNIX_EPOCH).ok())
        .map(|value| value.as_nanos());
    let resolved_path = resolved.to_str().ok_or_else(|| {
        KoniError::Process(format!(
            "resolved executable path is not UTF-8: {}",
            resolved.display()
        ))
    })?;
    let path_hash = raw_sha256(
        environment
            .get("PATH")
            .map(String::as_bytes)
            .unwrap_or_default(),
    );
    let key = (resolved_path.to_owned(), path_hash);
    if let Some((size, cached_modified, binding)) = cache.executables.get(&key)
        && *size == metadata.len()
        && *cached_modified == modified
    {
        return Ok(binding.clone());
    }
    let bytes = fs::read(&resolved).map_err(|error| io_error(&resolved, error))?;
    let canonical_project_root = project_root.canonicalize().ok();
    let project_relative = canonical_project_root
        .as_ref()
        .and_then(|root| resolved.strip_prefix(root).ok())
        .map(normalized_project_path);
    let binding = ExecutableBinding {
        requested: requested.to_owned(),
        path_kind: if project_relative.is_some() {
            "project_relative"
        } else {
            "external_absolute"
        }
        .to_owned(),
        resolved_path: project_relative.unwrap_or_else(|| resolved_path.to_owned()),
        size_bytes: bytes.len() as u64,
        sha256: raw_sha256(&bytes),
        #[cfg(unix)]
        mode: Some(metadata.mode()),
        #[cfg(not(unix))]
        mode: None,
        #[cfg(unix)]
        device: canonical_project_root
            .as_ref()
            .is_none_or(|root| !resolved.starts_with(root))
            .then_some(metadata.dev()),
        #[cfg(not(unix))]
        device: None,
        #[cfg(unix)]
        inode: canonical_project_root
            .as_ref()
            .is_none_or(|root| !resolved.starts_with(root))
            .then_some(metadata.ino()),
        #[cfg(not(unix))]
        inode: None,
        modified_ns: canonical_project_root
            .as_ref()
            .is_none_or(|root| !resolved.starts_with(root))
            .then_some(modified)
            .flatten(),
    };
    cache
        .executables
        .insert(key, (metadata.len(), modified, binding.clone()));
    Ok(binding)
}

fn canonical_regular_executable(path: &Path, requested: &str) -> Result<PathBuf> {
    let metadata = fs::symlink_metadata(path).map_err(|error| {
        KoniError::Process(format!(
            "cannot inspect executable {requested} at {}: {error}",
            path.display()
        ))
    })?;
    if metadata.file_type().is_symlink() {
        let target = path.canonicalize().map_err(|error| io_error(path, error))?;
        let target_metadata = fs::metadata(&target).map_err(|error| io_error(&target, error))?;
        if !target_metadata.is_file() {
            return Err(KoniError::Process(format!(
                "resolved executable {requested} symlink target is not a regular file"
            )));
        }
        return Ok(target);
    }
    if !metadata.is_file() {
        return Err(KoniError::Process(format!(
            "resolved executable {requested} is not a regular file"
        )));
    }
    path.canonicalize().map_err(|error| io_error(path, error))
}

fn resolve_read_only_sandbox(
    effect: crate::config::ProcessEffect,
    project_root: &Path,
    cwd: &str,
    read_paths: &[String],
    argv: &[String],
    environment: &BTreeMap<String, String>,
    cache: &mut ExecutionResolutionCache,
) -> Result<(Option<ExecutableBinding>, Option<String>)> {
    if effect != crate::config::ProcessEffect::ReadOnly {
        return Ok((None, None));
    }
    #[cfg(target_os = "macos")]
    {
        let sandbox_path = Path::new("/usr/bin/sandbox-exec");
        if !sandbox_path.is_file() {
            return Err(KoniError::Process(
                "read-only checks require /usr/bin/sandbox-exec on macOS".to_owned(),
            ));
        }
        let sandbox = resolve_executable_binding(
            project_root,
            cwd,
            sandbox_path.to_str().expect("static sandbox path is UTF-8"),
            environment,
            cache,
        )?;
        let contract = json!({
            "version": "macos-seatbelt.v2",
            "read_paths": read_paths,
            "private_tmp": true,
            "network": "denied",
            "semantic_argv": argv,
        });
        Ok((Some(sandbox), Some(normalized_hash(&contract))))
    }
    #[cfg(not(target_os = "macos"))]
    {
        let _ = (project_root, cwd, read_paths, argv, environment, cache);
        Ok((None, None))
    }
}

fn create_private_check_temp(
    required: bool,
    project_root: &Path,
    state_root: &Path,
) -> Result<Option<PathBuf>> {
    if !required {
        return Ok(None);
    }
    #[cfg(target_os = "macos")]
    let base = Path::new("/private/tmp");
    #[cfg(not(target_os = "macos"))]
    let base = Path::new("/tmp");
    let base = base.canonicalize().map_err(|error| io_error(base, error))?;
    let project_root = project_root
        .canonicalize()
        .map_err(|error| io_error(project_root, error))?;
    let state_root = state_root
        .canonicalize()
        .map_err(|error| io_error(state_root, error))?;
    for _ in 0..16 {
        let path = base.join(format!(".koni-read-only-{}", Uuid::now_v7()));
        if path.starts_with(&project_root)
            || path.starts_with(&state_root)
            || project_root.starts_with(&path)
            || state_root.starts_with(&path)
        {
            continue;
        }
        let mut builder = fs::DirBuilder::new();
        #[cfg(unix)]
        builder.mode(0o700);
        match builder.create(&path) {
            Ok(()) => return Ok(Some(path)),
            Err(error) if error.kind() == std::io::ErrorKind::AlreadyExists => continue,
            Err(error) => return Err(io_error(&path, error)),
        }
    }
    Err(KoniError::Process(
        "could not allocate a private read-only command scratch directory".to_owned(),
    ))
}

fn cleanup_private_check_temp(path: Option<&Path>) -> Result<()> {
    let Some(path) = path else {
        return Ok(());
    };
    let metadata = fs::symlink_metadata(path).map_err(|error| io_error(path, error))?;
    if metadata.file_type().is_symlink() || !metadata.is_dir() {
        return Err(KoniError::Process(format!(
            "refusing to clean untrusted scratch path {}",
            path.display()
        )));
    }
    fs::remove_dir_all(path).map_err(|error| io_error(path, error))
}

fn rendered_command_argv(
    execution: &ResolvedCheckExecution,
    project_root: &Path,
    state_root: &Path,
    profile: &CompiledProfile,
    private_temp: Option<&Path>,
) -> Result<(Vec<String>, Value)> {
    let mut semantic_argv = execution.argv.clone();
    let executable_path = executable_spawn_path(&execution.executable, project_root)?;
    if let Some(program) = semantic_argv.first_mut() {
        *program = executable_path.to_string_lossy().into_owned();
    }
    let Some(sandbox) = &execution.sandbox_executable else {
        return Ok((
            semantic_argv,
            json!({"kind": "none", "semantic_argv_hash": normalized_hash(&execution.argv)}),
        ));
    };
    #[cfg(target_os = "macos")]
    {
        let project_root = project_root
            .canonicalize()
            .map_err(|error| io_error(project_root, error))?;
        let state_root = state_root
            .canonicalize()
            .map_err(|error| io_error(state_root, error))?;
        let mut readable_roots = BTreeSet::from([
            PathBuf::from("/System"),
            PathBuf::from("/usr"),
            PathBuf::from("/bin"),
            PathBuf::from("/sbin"),
            PathBuf::from("/Library"),
            PathBuf::from("/private/etc"),
            PathBuf::from("/private/var/db/timezone"),
        ]);
        let mut readable_files = BTreeSet::from([executable_path.clone()]);
        if executable_path.starts_with("/opt/homebrew/") {
            readable_roots.insert(PathBuf::from("/opt/homebrew"));
        }
        if executable_path.starts_with("/usr/local/") {
            readable_roots.insert(PathBuf::from("/usr/local"));
        }
        let manifest_files = execution
            .read_path_manifest
            .iter()
            .filter_map(|manifest| manifest.get("files").and_then(Value::as_array))
            .flatten()
            .filter_map(|file| file.get("path").and_then(Value::as_str))
            .collect::<Vec<_>>();
        for configured in manifest_files {
            let resolved = contained_process_path(&project_root, configured)?;
            readable_files.insert(
                resolved
                    .canonicalize()
                    .map_err(|error| io_error(&resolved, error))?,
            );
        }
        let read_rules = readable_roots
            .iter()
            .map(|path| {
                let path = sandbox_string_literal(&path.to_string_lossy());
                format!("(allow file-read* (literal \"{path}\") (subpath \"{path}\"))")
            })
            .chain(readable_files.iter().map(|path| {
                let path = sandbox_string_literal(&path.to_string_lossy());
                format!("(allow file-read* (literal \"{path}\"))")
            }))
            .collect::<Vec<_>>()
            .join(" ");
        let mut writable_roots = BTreeSet::new();
        if let Some(private_temp) = private_temp {
            writable_roots.insert(private_temp.to_path_buf());
        }
        let storage = &profile.manifest.storage;
        let state_prefix = storage
            .state_path
            .parent()
            .filter(|path| !path.as_os_str().is_empty())
            .unwrap_or(Path::new("."));
        let protected_roots = BTreeSet::from([
            state_root.clone(),
            project_root.join(&storage.graph_dir),
            project_root.join(&storage.tickets_dir),
            project_root.join(&storage.receipts_dir),
            project_root.join(&storage.reports_dir),
            project_root.join(&storage.work_dir),
            project_root.join(&storage.state_path),
            project_root.join(state_prefix.join("locks")),
            project_root.join(".git"),
            project_root.join(&profile.manifest.git.worktree_root),
        ]);
        for writable in &writable_roots {
            if protected_roots
                .iter()
                .any(|protected| writable.starts_with(protected) || protected.starts_with(writable))
            {
                return Err(KoniError::Profile(format!(
                    "sandbox cache root {} overlaps compiler authority",
                    writable.display()
                )));
            }
        }
        let write_rules = writable_roots
            .iter()
            .map(|path| {
                let path = sandbox_string_literal(&path.to_string_lossy());
                format!("(allow file-read* file-write* (literal \"{path}\") (subpath \"{path}\"))")
            })
            .collect::<Vec<_>>()
            .join(" ");
        let deny_rules = protected_roots
            .iter()
            .map(|path| {
                let path = sandbox_string_literal(&path.to_string_lossy());
                format!("(deny file-write* (literal \"{path}\") (subpath \"{path}\"))")
            })
            .collect::<Vec<_>>()
            .join(" ");
        let mut metadata_roots = BTreeSet::new();
        for path in readable_roots
            .iter()
            .chain(&readable_files)
            .chain(&writable_roots)
        {
            let mut cursor = Some(path.as_path());
            while let Some(current) = cursor {
                metadata_roots.insert(current.to_path_buf());
                cursor = current.parent();
            }
        }
        let metadata_rules = metadata_roots
            .iter()
            .map(|path| {
                let path = sandbox_string_literal(&path.to_string_lossy());
                format!("(allow file-read-metadata (literal \"{path}\"))")
            })
            .collect::<Vec<_>>()
            .join(" ");
        let sandbox_profile = format!(
            "(version 1) (deny default) (allow process*) (allow sysctl-read) (allow file-read-data (literal \"/\")) {metadata_rules} {read_rules} {write_rules} (allow file-read* (literal \"/dev/null\") (literal \"/dev/urandom\")) (allow file-write* (literal \"/dev/null\")) {deny_rules}"
        );
        let mut argv = vec![
            sandbox.resolved_path.clone(),
            "-p".to_owned(),
            sandbox_profile.clone(),
            "--".to_owned(),
        ];
        argv.extend(semantic_argv);
        Ok((
            argv,
            json!({
                "kind": "macos-seatbelt.v2",
                "rendered_profile_hash": raw_sha256(sandbox_profile.as_bytes()),
                "project_root": project_root,
                "state_root": state_root,
                "semantic_profile_hash": execution.sandbox_profile_hash,
                "private_temp": private_temp,
            }),
        ))
    }
    #[cfg(not(target_os = "macos"))]
    {
        let _ = (sandbox, project_root, state_root, profile, private_temp);
        Ok((execution.argv.clone(), json!({"kind": "unsupported"})))
    }
}

fn executable_spawn_path(binding: &ExecutableBinding, project_root: &Path) -> Result<PathBuf> {
    match binding.path_kind.as_str() {
        "project_relative" => {
            let path = contained_process_path(project_root, &binding.resolved_path)?;
            path.canonicalize().map_err(|error| io_error(&path, error))
        }
        "external_absolute" => Ok(PathBuf::from(&binding.resolved_path)),
        other => Err(KoniError::Process(format!(
            "unknown executable path binding kind {other}"
        ))),
    }
}

#[cfg(target_os = "macos")]
fn sandbox_string_literal(value: &str) -> String {
    value.replace('\\', "\\\\").replace('"', "\\\"")
}

/// Convenience used by isolated unit-level resolution. Engine runtime and
/// receipt currentness always call `resolve_check_execution_with_store` with
/// their authoritative backend store.
#[cfg(test)]
fn resolve_check_execution(
    profile: &CompiledProfile,
    check: &crate::config::CheckDef,
    ticket: Option<&Ticket>,
    graph: &Graph,
    project_root: &Path,
) -> Result<ResolvedCheckExecution> {
    let state_prefix = profile
        .manifest
        .storage
        .state_path
        .parent()
        .filter(|path| !path.as_os_str().is_empty())
        .unwrap_or(Path::new("."));
    let store =
        StateStore::with_storage(project_root.join(state_prefix), &profile.manifest.storage)?;
    resolve_check_execution_with_store(profile, check, ticket, graph, project_root, &store)
}

fn dynamic_result_allows_produced_output(check: &crate::config::CheckDef) -> bool {
    check.dynamic_result.as_ref().is_some_and(|dynamic| {
        dynamic
            .result_path
            .as_ref()
            .into_iter()
            .flat_map(|path| &path.path_authorities)
            .chain(
                dynamic
                    .artifacts
                    .as_ref()
                    .into_iter()
                    .flat_map(|artifacts| &artifacts.path_authorities),
            )
            .any(|authority| {
                authority.provenance == crate::config::DynamicPathProvenance::ProducedOutput
            })
    })
}

fn command_read_path_exclusions<'a>(
    profile: &CompiledProfile,
    produced_roots: impl IntoIterator<Item = &'a str>,
) -> Result<BTreeSet<CommandPathExclusion>> {
    let storage = &profile.manifest.storage;
    let mut exclusions = BTreeSet::new();
    for path in &profile.manifest.storage.filesystem_scope_excludes {
        let normalized = normalized_command_exclusion_path(path)?;
        let match_mode = if Path::new(&normalized).components().count() == 1 {
            CommandPathExclusionMode::Component
        } else {
            CommandPathExclusionMode::Prefix
        };
        exclusions.insert(CommandPathExclusion {
            path: normalized,
            match_mode,
        });
    }
    let mut prefixes = vec![
        PathBuf::from(".git"),
        profile.manifest.git.worktree_root.clone(),
    ];
    prefixes.extend(compiler_owned_state_catalog(storage).paths().cloned());
    prefixes.extend(produced_roots.into_iter().map(PathBuf::from));
    for path in prefixes {
        exclusions.insert(CommandPathExclusion {
            path: normalized_command_exclusion_path(&path)?,
            match_mode: CommandPathExclusionMode::Prefix,
        });
    }
    Ok(exclusions)
}

fn read_only_workspace_fingerprint(
    root: &Path,
    profile: &CompiledProfile,
    authority_root: &Path,
) -> Result<WorkspaceFingerprint> {
    let canonical_root = root.canonicalize().map_err(|error| io_error(root, error))?;
    let mut fingerprint = if let Ok(repository) = git2::Repository::discover(&canonical_root)
        && let Some(workdir) = repository.workdir()
    {
        let canonical_workdir = workdir
            .canonicalize()
            .map_err(|error| io_error(workdir, error))?;
        if canonical_root.starts_with(&canonical_workdir) {
            git_workspace_fingerprint(&repository, &canonical_root, &canonical_workdir, profile)?
        } else {
            filesystem_workspace_fingerprint(&canonical_root, profile)?
        }
    } else {
        filesystem_workspace_fingerprint(&canonical_root, profile)?
    };
    let authority_root = authority_root
        .canonicalize()
        .map_err(|error| io_error(authority_root, error))?;
    if !authority_root.starts_with(&canonical_root) {
        fingerprint.authority_root = Some(authority_root.to_string_lossy().into_owned());
        fingerprint.authority_paths = authority_workspace_paths(&authority_root, profile)?;
    }
    fingerprint.hash.clear();
    fingerprint.hash = normalized_hash(&fingerprint);
    Ok(fingerprint)
}

fn git_workspace_fingerprint(
    repository: &git2::Repository,
    root: &Path,
    workdir: &Path,
    profile: &CompiledProfile,
) -> Result<WorkspaceFingerprint> {
    let project_prefix = root.strip_prefix(workdir).unwrap_or(Path::new(""));
    let head = repository.head().ok().map(|head| {
        format!(
            "{}:{}",
            head.name().unwrap_or("DETACHED"),
            head.target()
                .map(|oid| oid.to_string())
                .unwrap_or_else(|| "UNBORN".to_owned())
        )
    });
    let index = repository.index()?;
    let index_rows = index
        .iter()
        .map(|entry| {
            json!({
                "path": String::from_utf8_lossy(&entry.path),
                "oid": entry.id.to_string(),
                "mode": entry.mode,
                "flags": entry.flags,
                "flags_extended": entry.flags_extended,
            })
        })
        .collect::<Vec<_>>();
    let index_file_hash = repository
        .path()
        .join("index")
        .is_file()
        .then(|| fs::read(repository.path().join("index")))
        .transpose()
        .map_err(|error| io_error(repository.path().join("index"), error))?
        .map(|bytes| raw_sha256(&bytes));
    let index_hash = Some(normalized_hash(&json!({
        "file": index_file_hash,
        "entries": index_rows,
    })));
    let mut options = git2::StatusOptions::new();
    options
        .include_untracked(true)
        .recurse_untracked_dirs(true)
        .include_ignored(true)
        .recurse_ignored_dirs(true)
        .include_unmodified(false)
        .exclude_submodules(false);
    let statuses = repository.statuses(Some(&mut options))?;
    let mut paths = BTreeMap::new();
    for entry in statuses.iter() {
        let repository_relative = PathBuf::from(entry.path()?);
        let Ok(project_relative) = repository_relative.strip_prefix(project_prefix) else {
            continue;
        };
        if project_relative.as_os_str().is_empty()
            || workspace_guard_path_excluded(profile, project_relative)
        {
            continue;
        }
        let normalized = normalized_project_path(project_relative);
        let index_oid = index
            .get_path(&repository_relative, 0)
            .map(|entry| entry.id.to_string());
        paths.insert(
            normalized,
            workspace_path_fingerprint(
                &root.join(project_relative),
                Some(entry.status().bits()),
                index_oid,
            )?,
        );
    }
    for entry in WalkDir::new(root)
        .follow_links(false)
        .sort_by_file_name()
        .into_iter()
        .filter_entry(|entry| {
            if entry.path() == root {
                return true;
            }
            entry.path().strip_prefix(root).ok().is_some_and(|path| {
                path != Path::new(".git")
                    && !path.starts_with(".git")
                    && !workspace_guard_path_excluded(profile, path)
            })
        })
    {
        let entry = entry.map_err(|error| {
            KoniError::Process(format!("workspace directory inventory failed: {error}"))
        })?;
        if entry.path() == root || !entry.file_type().is_dir() {
            continue;
        }
        let relative = entry.path().strip_prefix(root).map_err(|_| {
            KoniError::Process("workspace directory inventory escaped project".to_owned())
        })?;
        paths
            .entry(normalized_project_path(relative))
            .or_insert(workspace_path_fingerprint(entry.path(), None, None)?);
    }
    finish_workspace_fingerprint("git", head, index_hash, paths)
}

fn filesystem_workspace_fingerprint(
    root: &Path,
    profile: &CompiledProfile,
) -> Result<WorkspaceFingerprint> {
    let mut paths = BTreeMap::new();
    for entry in WalkDir::new(root)
        .follow_links(false)
        .sort_by_file_name()
        .into_iter()
        .filter_entry(|entry| {
            if entry.path() == root {
                return true;
            }
            entry.path().strip_prefix(root).ok().is_some_and(|path| {
                path != Path::new(".git")
                    && !path.starts_with(".git")
                    && !workspace_guard_path_excluded(profile, path)
            })
        })
    {
        let entry = entry
            .map_err(|error| KoniError::Process(format!("workspace inventory failed: {error}")))?;
        if entry.path() == root {
            continue;
        }
        let relative = entry.path().strip_prefix(root).map_err(|_| {
            KoniError::Process("workspace inventory escaped project root".to_owned())
        })?;
        paths.insert(
            normalized_project_path(relative),
            workspace_path_fingerprint(entry.path(), None, None)?,
        );
    }
    finish_workspace_fingerprint("filesystem", None, None, paths)
}

fn workspace_guard_path_excluded(profile: &CompiledProfile, path: &Path) -> bool {
    let storage = &profile.manifest.storage;
    if path.starts_with(&storage.graph_dir) || path.starts_with(&storage.tickets_dir) {
        return false;
    }
    if storage.filesystem_scope_excludes.iter().any(|excluded| {
        if excluded.components().count() == 1 {
            path.components()
                .any(|component| component.as_os_str() == excluded)
        } else {
            path.starts_with(excluded)
        }
    }) {
        return true;
    }
    if path.starts_with(&storage.work_dir) {
        return path.file_name().is_some_and(|name| {
            matches!(
                name.to_str(),
                Some("worker.pid" | "worker.jsonl" | "stdout.log" | "stderr.log")
            )
        });
    }
    false
}

fn workspace_path_fingerprint(
    path: &Path,
    status: Option<u32>,
    index_oid: Option<String>,
) -> Result<WorkspacePathFingerprint> {
    let Ok(metadata) = fs::symlink_metadata(path) else {
        return Ok(WorkspacePathFingerprint {
            status,
            kind: "missing".to_owned(),
            mode: None,
            size_bytes: None,
            sha256: None,
            index_oid,
            link_target: None,
        });
    };
    if metadata.file_type().is_symlink() {
        let target = fs::read_link(path).map_err(|error| io_error(path, error))?;
        let target = target.to_string_lossy().into_owned();
        return Ok(WorkspacePathFingerprint {
            status,
            kind: "symlink".to_owned(),
            #[cfg(unix)]
            mode: Some(metadata.mode()),
            #[cfg(not(unix))]
            mode: None,
            size_bytes: Some(metadata.len()),
            sha256: Some(raw_sha256(target.as_bytes())),
            index_oid,
            link_target: Some(target),
        });
    }
    if metadata.is_file() {
        let bytes = fs::read(path).map_err(|error| io_error(path, error))?;
        return Ok(WorkspacePathFingerprint {
            status,
            kind: "file".to_owned(),
            #[cfg(unix)]
            mode: Some(metadata.mode()),
            #[cfg(not(unix))]
            mode: None,
            size_bytes: Some(bytes.len() as u64),
            sha256: Some(raw_sha256(&bytes)),
            index_oid,
            link_target: None,
        });
    }
    Ok(WorkspacePathFingerprint {
        status,
        kind: if metadata.is_dir() {
            "directory"
        } else {
            "other"
        }
        .to_owned(),
        #[cfg(unix)]
        mode: Some(metadata.mode()),
        #[cfg(not(unix))]
        mode: None,
        size_bytes: (!metadata.is_dir()).then_some(metadata.len()),
        sha256: None,
        index_oid,
        link_target: None,
    })
}

fn finish_workspace_fingerprint(
    backend: &str,
    head: Option<String>,
    index_hash: Option<String>,
    paths: BTreeMap<String, WorkspacePathFingerprint>,
) -> Result<WorkspaceFingerprint> {
    let mut fingerprint = WorkspaceFingerprint {
        schema_version: "1.0".to_owned(),
        backend: backend.to_owned(),
        head,
        index_hash,
        paths,
        authority_root: None,
        authority_paths: BTreeMap::new(),
        hash: String::new(),
    };
    fingerprint.hash = normalized_hash(&fingerprint);
    Ok(fingerprint)
}

fn workspace_fingerprint_changed_paths(
    pre: &WorkspaceFingerprint,
    post: &WorkspaceFingerprint,
) -> Vec<String> {
    let mut changed = pre
        .paths
        .keys()
        .chain(post.paths.keys())
        .filter(|path| pre.paths.get(*path) != post.paths.get(*path))
        .cloned()
        .collect::<BTreeSet<_>>();
    changed.extend(
        pre.authority_paths
            .keys()
            .chain(post.authority_paths.keys())
            .filter(|path| pre.authority_paths.get(*path) != post.authority_paths.get(*path))
            .map(|path| format!("<state>/{path}")),
    );
    if pre.head != post.head {
        changed.insert(".git/HEAD".to_owned());
    }
    if pre.index_hash != post.index_hash {
        changed.insert(".git/index".to_owned());
    }
    changed.into_iter().collect()
}

fn workspace_fingerprint_changes(
    pre: &WorkspaceFingerprint,
    post: &WorkspaceFingerprint,
) -> Vec<Value> {
    workspace_fingerprint_changed_paths(pre, post)
        .into_iter()
        .map(|path| {
            let pre_value = workspace_fingerprint_entry(pre, &path);
            let post_value = workspace_fingerprint_entry(post, &path);
            json!({
                "path": path,
                "pre": pre_value,
                "post": post_value,
            })
        })
        .collect()
}

fn workspace_fingerprint_entry(fingerprint: &WorkspaceFingerprint, path: &str) -> Value {
    match path {
        ".git/HEAD" => fingerprint.head.clone().map_or(Value::Null, Value::String),
        ".git/index" => fingerprint
            .index_hash
            .clone()
            .map_or(Value::Null, Value::String),
        _ if path.starts_with("<state>/") => fingerprint
            .authority_paths
            .get(path.trim_start_matches("<state>/"))
            .map(|value| serde_json::to_value(value).expect("workspace entry serializes"))
            .unwrap_or(Value::Null),
        _ => fingerprint
            .paths
            .get(path)
            .map(|value| serde_json::to_value(value).expect("workspace entry serializes"))
            .unwrap_or(Value::Null),
    }
}

fn direct_workspace_fingerprint_entry(
    workspace_root: &Path,
    state_root: &Path,
    path: &str,
) -> Result<Value> {
    if path == ".git/HEAD" {
        let repository = git2::Repository::discover(workspace_root)?;
        return Ok(repository.head().ok().map_or(Value::Null, |head| {
            Value::String(format!(
                "{}:{}",
                head.name().unwrap_or("DETACHED"),
                head.target()
                    .map(|oid| oid.to_string())
                    .unwrap_or_else(|| "UNBORN".to_owned())
            ))
        }));
    }
    if path == ".git/index" {
        let repository = git2::Repository::discover(workspace_root)?;
        let index = repository.index()?;
        let rows = index
            .iter()
            .map(|entry| {
                json!({
                    "path": String::from_utf8_lossy(&entry.path),
                    "oid": entry.id.to_string(),
                    "mode": entry.mode,
                    "flags": entry.flags,
                    "flags_extended": entry.flags_extended,
                })
            })
            .collect::<Vec<_>>();
        let index_file = repository.path().join("index");
        let file_hash = index_file
            .is_file()
            .then(|| fs::read(&index_file))
            .transpose()
            .map_err(|error| io_error(&index_file, error))?
            .map(|bytes| raw_sha256(&bytes));
        return Ok(Value::String(normalized_hash(&json!({
            "file": file_hash,
            "entries": rows,
        }))));
    }
    if let Some(relative) = path.strip_prefix("<state>/") {
        let absolute = state_root.join(relative);
        if !absolute.exists() {
            return Ok(Value::Null);
        }
        let entry = workspace_path_fingerprint(&absolute, None, None)?;
        return Ok(serde_json::to_value(entry).expect("workspace entry serializes"));
    }
    let relative = Path::new(path);
    validate_project_relative_scope_path(relative)?;
    let repository = git2::Repository::discover(workspace_root).ok();
    let (status, index_oid) = if let Some(repository) = repository.as_ref()
        && let Some(workdir) = repository.workdir()
        && let Ok(prefix) = workspace_root.strip_prefix(workdir)
    {
        let repository_relative = prefix.join(relative);
        (
            repository
                .status_file(&repository_relative)
                .ok()
                .map(|status| status.bits()),
            repository
                .index()
                .ok()
                .and_then(|index| index.get_path(&repository_relative, 0))
                .map(|entry| entry.id.to_string()),
        )
    } else {
        (None, None)
    };
    let absolute = workspace_root.join(relative);
    if !absolute.is_dir()
        && status.is_none_or(|status| status == 0)
        && ((absolute.exists() && index_oid.is_some())
            || (!absolute.exists() && index_oid.is_none()))
    {
        return Ok(Value::Null);
    }
    let entry = workspace_path_fingerprint(&absolute, status, index_oid)?;
    Ok(serde_json::to_value(entry).expect("workspace entry serializes"))
}

#[derive(Debug, Clone)]
struct ValidatedCommandJournalAuthority {
    workspace_root: PathBuf,
    state_root: PathBuf,
    receipts_root: PathBuf,
}

fn command_journal_provenance_error(journal: &Value, message: impl Into<String>) -> KoniError {
    KoniError::Process(format!(
        "read-only command journal {} failed authority provenance: {}",
        journal
            .get("sequence")
            .and_then(Value::as_u64)
            .map(|sequence| sequence.to_string())
            .unwrap_or_else(|| "<unknown>".to_owned()),
        message.into()
    ))
}

fn journal_absolute_path_field(journal: &Value, field: &str) -> Result<PathBuf> {
    let path = journal
        .get(field)
        .and_then(Value::as_str)
        .filter(|path| !path.is_empty())
        .map(PathBuf::from)
        .ok_or_else(|| command_journal_provenance_error(journal, format!("missing {field}")))?;
    if !path.is_absolute()
        || path.components().any(|component| {
            matches!(
                component,
                std::path::Component::CurDir | std::path::Component::ParentDir
            )
        })
    {
        return Err(command_journal_provenance_error(
            journal,
            format!("{field} is not a lexical canonical absolute path"),
        ));
    }
    Ok(path)
}

fn extend_managed_ticket_workspaces(
    candidates: &mut BTreeSet<PathBuf>,
    store: &StateStore,
    run_id: &str,
    profile_hash: &str,
) -> Result<()> {
    if !store.manifest_path().exists() {
        return Ok(());
    }
    let manifest = store.manifest()?;
    if manifest.id != run_id || manifest.profile_hash != profile_hash {
        return Err(KoniError::Process(
            "compiler-owned ticket store does not match the current run identity".to_owned(),
        ));
    }
    candidates.extend(
        store
            .tickets()?
            .into_iter()
            .filter_map(|ticket| ticket.lease.map(|lease| lease.worktree)),
    );
    Ok(())
}

fn managed_run_workspace_roots(
    project_root: &Path,
    profile: &CompiledProfile,
    store: &StateStore,
    run_id: &str,
) -> Result<BTreeSet<PathBuf>> {
    let current_git = GitBackend::discover(project_root)?;
    let mut candidates = BTreeSet::from([current_git.workdir().to_path_buf()]);
    extend_managed_ticket_workspaces(&mut candidates, store, run_id, &profile.hash)?;

    let registry_path = current_git.sidecar_root().join("project.yaml");
    if registry_path.exists() {
        let registered_project_root = registry_project_root(project_root)?;
        let registry =
            ProjectRegistryStore::new(current_git.sidecar_root(), registered_project_root.clone())?;
        let registration = registry.run(run_id)?;
        if registration.profile_hash != profile.hash {
            return Err(KoniError::Process(format!(
                "registered run {run_id} does not match the active profile"
            )));
        }
        candidates.insert(registered_project_root);
        candidates.extend(registration.planning_worktree.iter().cloned());
        candidates.extend(registration.integration_worktree.iter().cloned());
        let canonical_store = match profile.manifest.storage.backend {
            StorageBackend::Tracked => registration
                .integration_worktree
                .as_ref()
                .map(|worktree| {
                    StateStore::with_storage(
                        tracked_state_root(worktree, profile),
                        &profile.manifest.storage,
                    )
                })
                .transpose()?,
            StorageBackend::GitCommonDir => {
                Some(registry.run_store(run_id, &profile.manifest.storage)?)
            }
        };
        if let Some(canonical_store) = canonical_store {
            extend_managed_ticket_workspaces(
                &mut candidates,
                &canonical_store,
                run_id,
                &profile.hash,
            )?;
        }
    }

    let mut managed = BTreeSet::new();
    for candidate in candidates {
        if !candidate.exists() {
            continue;
        }
        let canonical = candidate
            .canonicalize()
            .map_err(|error| io_error(&candidate, error))?;
        let candidate_git = GitBackend::discover(&canonical)?;
        if candidate_git.workdir() != canonical
            || candidate_git.common_dir() != current_git.common_dir()
        {
            continue;
        }
        managed.insert(canonical);
    }
    Ok(managed)
}

fn canonical_trusted_journal_root(journal: &Value, path: &Path, label: &str) -> Result<PathBuf> {
    let canonical = path
        .canonicalize()
        .map_err(|_| command_journal_provenance_error(journal, format!("{label} is missing")))?;
    if canonical != path {
        return Err(command_journal_provenance_error(
            journal,
            format!("{label} is noncanonical or contains a symlink"),
        ));
    }
    Ok(canonical)
}

fn validate_command_attempt_journal_authority(
    journal: &Value,
    project_root: &Path,
    profile: &CompiledProfile,
    store: &StateStore,
) -> Result<ValidatedCommandJournalAuthority> {
    if !command_attempt_journal_integrity_current(journal) {
        return Err(command_journal_provenance_error(
            journal,
            "journal integrity is invalid",
        ));
    }
    let manifest = store.manifest()?;
    if !command_attempt_journal_is_configured_read_only(profile, &manifest.id, journal) {
        return Err(command_journal_provenance_error(
            journal,
            "kind, producer, run, profile, or read-only check identity is invalid",
        ));
    }

    // These are parsed syntactically only. No journal-supplied path is touched
    // until the workspace is equal to a compiler-derived managed worktree.
    let workspace_root = journal_absolute_path_field(journal, "workspace_root")?;
    let state_root = journal_absolute_path_field(journal, "state_root")?;
    let receipts_root = journal_absolute_path_field(journal, "receipts_root")?;
    let managed = managed_run_workspace_roots(project_root, profile, store, &manifest.id)?;
    let workspace_root = managed.get(&workspace_root).cloned().ok_or_else(|| {
        command_journal_provenance_error(
            journal,
            "workspace_root is not a managed worktree for this run",
        )
    })?;
    let current_git = GitBackend::discover(project_root)?;
    let workspace_git = GitBackend::discover(&workspace_root)?;
    if workspace_git.common_dir() != current_git.common_dir() {
        return Err(command_journal_provenance_error(
            journal,
            "workspace_root belongs to another Git common repository",
        ));
    }

    let candidate_store = match profile.manifest.storage.backend {
        StorageBackend::Tracked => {
            let derived_state_root = tracked_state_root(&workspace_root, profile);
            let canonical_state_root =
                canonical_trusted_journal_root(journal, &derived_state_root, "state_root")?;
            if state_root != canonical_state_root
                || !canonical_state_root.starts_with(&workspace_root)
            {
                return Err(command_journal_provenance_error(
                    journal,
                    "state_root is not the exact tracked state root for workspace_root",
                ));
            }
            StateStore::with_storage(canonical_state_root, &profile.manifest.storage)?
        }
        StorageBackend::GitCommonDir => {
            let expected_run_root = current_git.sidecar_path(format!("runs/{}", manifest.id))?;
            let expected_store =
                StateStore::with_storage(expected_run_root, &profile.manifest.storage)?;
            let canonical_state_root = canonical_trusted_journal_root(
                journal,
                expected_store.root(),
                "registered run state_root",
            )?;
            let current_state_root =
                canonical_trusted_journal_root(journal, store.root(), "current run state_root")?;
            if state_root != canonical_state_root || current_state_root != canonical_state_root {
                return Err(command_journal_provenance_error(
                    journal,
                    "state_root is not the exact registered Git-common run store",
                ));
            }
            expected_store
        }
    };
    let candidate_manifest = candidate_store.manifest()?;
    if candidate_manifest.id != manifest.id
        || candidate_manifest.profile_hash != profile.hash
        || candidate_manifest.repository_root != manifest.repository_root
    {
        return Err(command_journal_provenance_error(
            journal,
            "state_root manifest does not match the current run identity",
        ));
    }
    let canonical_receipts_root =
        canonical_trusted_journal_root(journal, candidate_store.receipts_dir(), "receipts_root")?;
    if receipts_root != canonical_receipts_root
        || !canonical_receipts_root.starts_with(candidate_store.root())
    {
        return Err(command_journal_provenance_error(
            journal,
            "receipts_root is not the exact configured receipts directory",
        ));
    }
    Ok(ValidatedCommandJournalAuthority {
        workspace_root,
        state_root,
        receipts_root,
    })
}

fn command_authority_receipt_rows(
    profile: &CompiledProfile,
    store: &StateStore,
    project_root: &Path,
) -> Result<Vec<Value>> {
    let authority = command_authority_store(store, project_root)?;
    let local_rows = load_all_receipt_rows(store.receipts_dir())?;
    let journals = load_all_receipt_rows(&authority.work_dir().join("command-journals"))?;
    let validated = journals
        .iter()
        .map(|journal| {
            validate_command_attempt_journal_authority(journal, project_root, profile, store)
                .map(|authority| (journal, authority))
        })
        .collect::<Result<Vec<_>>>()?;
    let retired = retired_command_attempt_records(&authority, project_root, profile, store)?;
    let mut sequence_authority = BTreeMap::<u64, &str>::new();
    for journal in &journals {
        let sequence = journal
            .get("sequence")
            .and_then(Value::as_u64)
            .ok_or_else(|| KoniError::Process("live command journal has no sequence".to_owned()))?;
        let hash = journal
            .get("journal_hash")
            .and_then(Value::as_str)
            .ok_or_else(|| {
                KoniError::Process("live command journal has no integrity hash".to_owned())
            })?;
        if sequence_authority.insert(sequence, hash).is_some() {
            return Err(KoniError::Process(format!(
                "compiler authority contains duplicate live command sequence {sequence}"
            )));
        }
    }
    for (_, journal, _) in &retired {
        let sequence = journal
            .get("sequence")
            .and_then(Value::as_u64)
            .ok_or_else(|| {
                KoniError::Process("retired command journal has no sequence".to_owned())
            })?;
        let hash = journal
            .get("journal_hash")
            .and_then(Value::as_str)
            .ok_or_else(|| {
                KoniError::Process("retired command journal has no integrity hash".to_owned())
            })?;
        if let Some(existing) = sequence_authority.insert(sequence, hash)
            && existing != hash
        {
            return Err(KoniError::Process(format!(
                "live and retired command authority conflict at sequence {sequence}"
            )));
        }
    }
    let mut rows_by_root = BTreeMap::<PathBuf, Vec<Value>>::new();
    if store.receipts_dir().exists() {
        rows_by_root.insert(
            store
                .receipts_dir()
                .canonicalize()
                .map_err(|error| io_error(store.receipts_dir(), error))?,
            local_rows.clone(),
        );
    }
    for (_, validated) in &validated {
        if !rows_by_root.contains_key(&validated.receipts_root) {
            rows_by_root.insert(
                validated.receipts_root.clone(),
                load_all_receipt_rows(&validated.receipts_root)?,
            );
        }
    }
    let mut matched = Vec::new();
    let mut matched_hashes = BTreeSet::new();
    for (journal, validated) in &validated {
        for receipt in &rows_by_root[&validated.receipts_root] {
            if command_attempt_journal_matches_receipt(journal, receipt, profile) {
                let hash = normalized_hash(receipt);
                if matched_hashes.insert(hash) {
                    matched.push(receipt.clone());
                }
            }
        }
    }
    for (_, _, receipt) in &retired {
        if let Some(receipt) = receipt {
            let hash = normalized_hash(receipt);
            if matched_hashes.insert(hash) {
                matched.push(receipt.clone());
            }
        }
    }

    // Local semantic rows remain available for compatibility and non-command
    // checks. A read-only invalid-contract may influence global authority only
    // when its exact receipt is bound to one validated command journal. The one
    // exception is a valid unchanged guard, which is a local execution failure
    // and carries no workspace authority to dereference.
    let mut rows = local_rows;
    for receipt_rows in rows_by_root.values() {
        for receipt in receipt_rows {
            if !receipt_claims_configured_read_only_invalid_contract(profile, receipt)
                || matched_hashes.contains(&normalized_hash(receipt))
                || (command_receipt_integrity_current(receipt)
                    && receipt_is_configured_read_only_command(profile, receipt)
                    && read_only_workspace_guard_evidence(receipt)
                        == ReadOnlyWorkspaceGuardEvidence::ValidUnchanged)
            {
                continue;
            }
            return Err(KoniError::Process(format!(
                "read-only invalid-contract receipt {} has no exact validated command journal authority",
                receipt
                    .get("id")
                    .and_then(Value::as_str)
                    .unwrap_or("<unknown>")
            )));
        }
    }
    rows.extend(matched);
    rows.extend(load_all_receipt_rows(
        &authority.work_dir().join("remediations"),
    )?);
    Ok(rows
        .into_iter()
        .map(|row| (normalized_hash(&row), row))
        .collect::<BTreeMap<_, _>>()
        .into_values()
        .collect())
}

fn receipt_is_configured_read_only_command(profile: &CompiledProfile, receipt: &Value) -> bool {
    configured_command_check_for_receipt(profile, receipt).is_some_and(|check| {
        check.effect == crate::config::ProcessEffect::ReadOnly
            && receipt
                .get("process_effect")
                .and_then(Value::as_str)
                .is_none_or(|effect| effect == "read_only")
    })
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum ReadOnlyWorkspaceGuardEvidence {
    ValidUnchanged,
    ValidViolation,
    Invalid,
}

fn read_only_workspace_guard_evidence(receipt: &Value) -> ReadOnlyWorkspaceGuardEvidence {
    let Some(guard) = receipt.get("workspace_guard").and_then(Value::as_object) else {
        return ReadOnlyWorkspaceGuardEvidence::Invalid;
    };
    let Some(pre_hash) = guard.get("pre_hash").and_then(Value::as_str) else {
        return ReadOnlyWorkspaceGuardEvidence::Invalid;
    };
    let Some(post_hash) = guard.get("post_hash").and_then(Value::as_str) else {
        return ReadOnlyWorkspaceGuardEvidence::Invalid;
    };
    let Some(changed_paths) = guard.get("changed_paths").and_then(Value::as_array) else {
        return ReadOnlyWorkspaceGuardEvidence::Invalid;
    };
    let Some(changes) = guard.get("changes").and_then(Value::as_array) else {
        return ReadOnlyWorkspaceGuardEvidence::Invalid;
    };
    if pre_hash.is_empty() || post_hash.is_empty() {
        return ReadOnlyWorkspaceGuardEvidence::Invalid;
    }
    if guard.get("unchanged").and_then(Value::as_bool) == Some(true)
        && pre_hash == post_hash
        && changed_paths.is_empty()
        && changes.is_empty()
    {
        return ReadOnlyWorkspaceGuardEvidence::ValidUnchanged;
    }
    if guard.get("unchanged").and_then(Value::as_bool) != Some(false)
        || pre_hash == post_hash
        || changed_paths.is_empty()
        || changes.is_empty()
    {
        return ReadOnlyWorkspaceGuardEvidence::Invalid;
    }
    let changed_paths = changed_paths
        .iter()
        .filter_map(Value::as_str)
        .collect::<BTreeSet<_>>();
    if changed_paths.len() != changes.len() {
        return ReadOnlyWorkspaceGuardEvidence::Invalid;
    }
    let change_paths = changes
        .iter()
        .filter_map(|change| {
            let object = change.as_object()?;
            if object.len() != 3
                || !object
                    .keys()
                    .all(|key| matches!(key.as_str(), "path" | "pre" | "post"))
            {
                return None;
            }
            let path = object.get("path")?.as_str()?;
            let pre = object.get("pre")?;
            let post = object.get("post")?;
            (!path.is_empty() && pre != post).then_some(path)
        })
        .collect::<BTreeSet<_>>();
    if change_paths.len() == changes.len() && change_paths == changed_paths {
        ReadOnlyWorkspaceGuardEvidence::ValidViolation
    } else {
        ReadOnlyWorkspaceGuardEvidence::Invalid
    }
}

fn receipt_claims_configured_read_only_invalid_contract(
    profile: &CompiledProfile,
    receipt: &Value,
) -> bool {
    receipt.get("status").and_then(Value::as_str) == Some("invalid_contract")
        && configured_command_check_for_receipt(profile, receipt)
            .is_some_and(|check| check.effect == crate::config::ProcessEffect::ReadOnly)
}

fn receipt_is_read_only_workspace_violation(profile: &CompiledProfile, receipt: &Value) -> bool {
    receipt_claims_configured_read_only_invalid_contract(profile, receipt)
        && receipt_is_configured_read_only_command(profile, receipt)
        && read_only_workspace_guard_evidence(receipt)
            == ReadOnlyWorkspaceGuardEvidence::ValidViolation
}

fn corrupt_or_malformed_read_only_invalid_contract(
    profile: &CompiledProfile,
    receipt: &Value,
) -> bool {
    receipt_claims_configured_read_only_invalid_contract(profile, receipt)
        && (!command_receipt_integrity_current(receipt)
            || !receipt_is_configured_read_only_command(profile, receipt)
            || read_only_workspace_guard_evidence(receipt)
                == ReadOnlyWorkspaceGuardEvidence::Invalid)
}

fn command_attempt_journal_is_configured_read_only(
    profile: &CompiledProfile,
    run_id: &str,
    journal: &Value,
) -> bool {
    journal.get("schema_version").and_then(Value::as_str) == Some("1.0")
        && journal.get("kind").and_then(Value::as_str) == Some("compiler.read-only-command-attempt")
        && journal.get("producer").and_then(Value::as_str) == Some("compiler.read-only-quarantine")
        && journal.get("run_id").and_then(Value::as_str) == Some(run_id)
        && journal.get("profile_hash").and_then(Value::as_str) == Some(profile.hash.as_str())
        && journal
            .get("check_id")
            .and_then(Value::as_str)
            .and_then(|check_id| profile.checks.get(check_id))
            .is_some_and(|check| {
                check.kind == CheckKind::Command
                    && check.effect == crate::config::ProcessEffect::ReadOnly
            })
}

fn read_only_violation_watermark(
    profile: &CompiledProfile,
    store: &StateStore,
    project_root: &Path,
) -> Result<Option<u64>> {
    let mut found = false;
    let mut watermark = 0;
    let run_id = store.manifest()?.id;
    let receipts = command_authority_receipt_rows(profile, store, project_root)?;
    for receipt in &receipts {
        if corrupt_or_malformed_read_only_invalid_contract(profile, receipt) {
            return Err(KoniError::Process(format!(
                "compiler authority contains corrupt or malformed read-only invalid-contract receipt {}",
                receipt
                    .get("id")
                    .and_then(Value::as_str)
                    .unwrap_or("<unknown>")
            )));
        }
        if !receipt_is_read_only_workspace_violation(profile, receipt)
            || !command_receipt_integrity_current(receipt)
        {
            continue;
        }
        found = true;
        watermark = watermark.max(
            receipt
                .get("command_attempt_sequence")
                .and_then(Value::as_u64)
                .unwrap_or(0),
        );
    }
    let authority = command_authority_store(store, project_root)?;
    let journals = authority.work_dir().join("command-journals");
    for journal in load_all_receipt_rows(&journals)? {
        if !command_attempt_journal_integrity_current(&journal) {
            return Err(KoniError::Process(
                "compiler authority contains a corrupt read-only command journal".to_owned(),
            ));
        }
        if journal.get("kind").and_then(Value::as_str) != Some("compiler.read-only-command-attempt")
        {
            continue;
        }
        if !command_attempt_journal_is_configured_read_only(profile, &run_id, &journal) {
            return Err(KoniError::Process(
                "compiler authority contains an unbound read-only command journal".to_owned(),
            ));
        }
        if receipts
            .iter()
            .any(|receipt| command_attempt_journal_matches_receipt(&journal, receipt, profile))
        {
            continue;
        }
        let sequence = journal
            .get("sequence")
            .and_then(Value::as_u64)
            .ok_or_else(|| {
                KoniError::Process(
                    "compiler authority contains a read-only journal without a sequence".to_owned(),
                )
            })?;
        found = true;
        watermark = watermark.max(sequence);
    }
    for (_, journal, receipt) in
        retired_command_attempt_records(&authority, project_root, profile, store)?
    {
        if receipt.is_some() {
            continue;
        }
        let sequence = journal
            .get("sequence")
            .and_then(Value::as_u64)
            .ok_or_else(|| {
                KoniError::Process(
                    "retired receipt-free command attempt has no sequence".to_owned(),
                )
            })?;
        found = true;
        watermark = watermark.max(sequence);
    }
    Ok(found.then_some(watermark))
}

fn read_only_remediation_receipt_is_valid(receipt: &Value) -> bool {
    const FIELDS: &[&str] = &[
        "schema_version",
        "id",
        "receipt_type",
        "producer",
        "status",
        "violation_id",
        "violation_receipt_hash",
        "workspace_root",
        "state_root",
        "workspace_hash_at_remediation",
        "violation_profile_hash",
        "recorded_at",
        "profile_hash",
        "receipt_hash",
    ];
    let Some(object) = receipt.as_object() else {
        return false;
    };
    object.len() == FIELDS.len()
        && object.keys().all(|key| FIELDS.contains(&key.as_str()))
        && receipt.get("schema_version").and_then(Value::as_str) == Some("1.0")
        && receipt_kind(receipt) == Some("compiler.read-only-remediation")
        && receipt.get("producer").and_then(Value::as_str) == Some("compiler.read-only-quarantine")
        && receipt.get("status").and_then(Value::as_str) == Some("passed")
        && [
            "id",
            "violation_id",
            "violation_receipt_hash",
            "workspace_root",
            "state_root",
            "workspace_hash_at_remediation",
            "violation_profile_hash",
            "recorded_at",
            "profile_hash",
            "receipt_hash",
        ]
        .iter()
        .all(|field| {
            receipt
                .get(*field)
                .and_then(Value::as_str)
                .is_some_and(|value| !value.trim().is_empty())
        })
        && durable_receipt_integrity_current(receipt)
}

fn command_attempt_journal_matches_receipt(
    journal: &Value,
    receipt: &Value,
    profile: &CompiledProfile,
) -> bool {
    let completion_linkage_current = journal.get("status").and_then(Value::as_str)
        != Some("completed")
        || (journal
            .get("receipt_id")
            .and_then(Value::as_str)
            .is_some_and(|id| receipt.get("id").and_then(Value::as_str) == Some(id))
            && journal
                .get("receipt_hash")
                .and_then(Value::as_str)
                .is_some_and(|hash| {
                    receipt.get("receipt_hash").and_then(Value::as_str) == Some(hash)
                }));
    let workspace_pre_current = journal
        .get("workspace_pre")
        .and_then(|pre| pre.get("hash"))
        .and_then(Value::as_str)
        .is_some_and(|hash| {
            receipt
                .get("workspace_guard")
                .and_then(|guard| guard.get("pre_hash"))
                .and_then(Value::as_str)
                == Some(hash)
        });
    let workspace_post_current = journal
        .get("workspace_post")
        .filter(|post| !post.is_null())
        .is_none_or(|post| {
            post.get("hash")
                .and_then(Value::as_str)
                .is_some_and(|hash| {
                    receipt
                        .get("workspace_guard")
                        .and_then(|guard| guard.get("post_hash"))
                        .and_then(Value::as_str)
                        == Some(hash)
                })
        });
    let guard_evidence = read_only_workspace_guard_evidence(receipt);
    let guard_contract_current = guard_evidence != ReadOnlyWorkspaceGuardEvidence::Invalid
        && (guard_evidence != ReadOnlyWorkspaceGuardEvidence::ValidViolation
            || receipt.get("status").and_then(Value::as_str) == Some("invalid_contract"))
        && (receipt.get("status").and_then(Value::as_str) == Some("invalid_contract")
            || guard_evidence == ReadOnlyWorkspaceGuardEvidence::ValidUnchanged);
    completion_linkage_current
        && workspace_pre_current
        && workspace_post_current
        && guard_contract_current
        && receipt
            .get("command_attempt_sequence")
            .and_then(Value::as_u64)
            == journal.get("sequence").and_then(Value::as_u64)
        && command_receipt_integrity_current(receipt)
        && receipt.get("run_id").and_then(Value::as_str)
            == journal.get("run_id").and_then(Value::as_str)
        && receipt.get("check_id").and_then(Value::as_str)
            == journal.get("check_id").and_then(Value::as_str)
        && receipt.get("profile_hash").and_then(Value::as_str)
            == journal.get("profile_hash").and_then(Value::as_str)
        && receipt
            .get("execution_binding_hash")
            .and_then(Value::as_str)
            == journal
                .get("execution_binding_hash")
                .and_then(Value::as_str)
        && receipt.get("workspace_root").and_then(Value::as_str)
            == journal.get("workspace_root").and_then(Value::as_str)
        && receipt.get("state_root").and_then(Value::as_str)
            == journal.get("state_root").and_then(Value::as_str)
        && receipt.get("receipts_root").and_then(Value::as_str)
            == journal.get("receipts_root").and_then(Value::as_str)
        && receipt.get("process_effect").and_then(Value::as_str) == Some("read_only")
        && receipt.get("execution_binding") == journal.get("execution_binding")
        && receipt.get("spawn_binding") == journal.get("spawn_binding")
        && configured_command_check_for_receipt(profile, receipt).is_some_and(|check| {
            Some(check.id.as_str()) == journal.get("check_id").and_then(Value::as_str)
        })
}

fn recover_or_block_command_attempt_journals(
    root: &Path,
    profile: &CompiledProfile,
    store: &StateStore,
) -> Result<()> {
    let authority = command_authority_store(store, root)?;
    let directory = authority.work_dir().join("command-journals");
    if !directory.exists() {
        return Ok(());
    }
    for entry in fs::read_dir(&directory).map_err(|error| io_error(&directory, error))? {
        let path = entry.map_err(|error| io_error(&directory, error))?.path();
        if path.extension().and_then(|extension| extension.to_str()) != Some("yaml") {
            continue;
        }
        let journal = read_optional_yaml_value(&path)?.ok_or_else(|| {
            KoniError::Process(format!(
                "command attempt journal disappeared: {}",
                path.display()
            ))
        })?;
        let validated = validate_command_attempt_journal_authority(&journal, root, profile, store)?;
        let authority_receipts = load_all_receipt_rows(&validated.receipts_root)?;
        let matching_receipt = authority_receipts
            .iter()
            .find(|receipt| command_attempt_journal_matches_receipt(&journal, receipt, profile));
        if journal.get("status").and_then(Value::as_str) == Some("completed")
            && matching_receipt.is_some()
        {
            continue;
        }
        if journal.get("status").and_then(Value::as_str) == Some("recovered_no_receipt") {
            continue;
        }
        let sequence = journal
            .get("sequence")
            .and_then(Value::as_u64)
            .ok_or_else(|| {
                KoniError::Process(format!(
                    "command attempt journal has no sequence: {}",
                    path.display()
                ))
            })?;
        if let Some(receipt) = matching_receipt {
            let workspace_post = journal
                .get("workspace_post")
                .cloned()
                .and_then(|value| serde_json::from_value(value).ok());
            complete_command_attempt_journal(
                Some(&path),
                "completed",
                workspace_post.as_ref(),
                Some(receipt),
            )?;
            continue;
        }
        let pre = journal
            .get("workspace_pre")
            .cloned()
            .and_then(|value| serde_json::from_value::<WorkspaceFingerprint>(value).ok())
            .ok_or_else(|| {
                KoniError::Process(format!(
                    "command attempt journal has no exact prestate: {}",
                    path.display()
                ))
            })?;
        let current = read_only_workspace_fingerprint(
            &validated.workspace_root,
            profile,
            &validated.state_root,
        )?;
        if current.hash != pre.hash {
            complete_command_attempt_journal(Some(&path), "quarantined", Some(&current), None)?;
            return Err(KoniError::Process(format!(
                "compiler authority is quarantined by unresolved command attempt {} whose workspace differs from its exact prestate",
                sequence
            )));
        }
        complete_command_attempt_journal(
            Some(&path),
            "recovered_no_receipt",
            Some(&current),
            None,
        )?;
    }
    Ok(())
}

fn ensure_global_read_only_quarantine_clear(
    root: &Path,
    profile: &CompiledProfile,
    store: &StateStore,
) -> Result<()> {
    let (_barrier, sidecar_root, manifest) = acquire_run_authority_barrier(store, root)?;
    ensure_run_identity_current_under_barrier(&sidecar_root, &manifest, profile, store)?;
    ensure_global_read_only_quarantine_clear_under_barrier(root, profile, store)
}

fn ensure_global_read_only_quarantine_clear_under_barrier(
    root: &Path,
    profile: &CompiledProfile,
    store: &StateStore,
) -> Result<()> {
    let canonical_current_root = root
        .canonicalize()
        .map_err(|error| io_error(root, error))?
        .to_string_lossy()
        .into_owned();
    let canonical_current_state_root = store
        .root()
        .canonicalize()
        .map_err(|error| io_error(store.root(), error))?
        .to_string_lossy()
        .into_owned();
    recover_or_block_command_attempt_journals(root, profile, store)?;
    let rows = command_authority_receipt_rows(profile, store, root)?;
    let corrupt_violations = rows
        .iter()
        .filter(|receipt| corrupt_or_malformed_read_only_invalid_contract(profile, receipt))
        .map(|receipt| {
            receipt
                .get("id")
                .and_then(Value::as_str)
                .unwrap_or("<unknown>")
                .to_owned()
        })
        .collect::<Vec<_>>();
    if !corrupt_violations.is_empty() {
        return Err(KoniError::Process(format!(
            "compiler authority is quarantined by corrupt read-only violation receipt(s): {}",
            corrupt_violations.join(", ")
        )));
    }
    let remediated = rows
        .iter()
        .filter(|receipt| read_only_remediation_receipt_is_valid(receipt))
        .filter_map(|receipt| {
            Some((
                receipt.get("violation_id")?.as_str()?.to_owned(),
                receipt.get("violation_receipt_hash")?.as_str()?.to_owned(),
                receipt.get("workspace_root")?.as_str()?.to_owned(),
                receipt.get("state_root")?.as_str()?.to_owned(),
                receipt.get("violation_profile_hash")?.as_str()?.to_owned(),
            ))
        })
        .collect::<BTreeSet<_>>();
    let violations = rows
        .into_iter()
        .filter(|receipt| {
            receipt_is_read_only_workspace_violation(profile, receipt)
                && command_receipt_integrity_current(receipt)
                && !remediated.contains(&(
                    receipt
                        .get("id")
                        .and_then(Value::as_str)
                        .unwrap_or_default()
                        .to_owned(),
                    receipt
                        .get("receipt_hash")
                        .and_then(Value::as_str)
                        .unwrap_or_default()
                        .to_owned(),
                    receipt
                        .get("workspace_root")
                        .and_then(Value::as_str)
                        .unwrap_or(&canonical_current_root)
                        .to_owned(),
                    receipt
                        .get("state_root")
                        .and_then(Value::as_str)
                        .unwrap_or(&canonical_current_state_root)
                        .to_owned(),
                    receipt
                        .get("profile_hash")
                        .and_then(Value::as_str)
                        .unwrap_or_default()
                        .to_owned(),
                ))
        })
        .collect::<Vec<_>>();
    if violations.is_empty() {
        return Ok(());
    }
    let mut workspace_cache = BTreeMap::<(String, String), WorkspaceFingerprint>::new();
    let mut unresolved = Vec::new();
    let mut newly_remediated = Vec::new();
    for violation in violations {
        let id = violation
            .get("id")
            .and_then(Value::as_str)
            .unwrap_or("<unknown>");
        let workspace_root = violation
            .get("workspace_root")
            .and_then(Value::as_str)
            .unwrap_or(&canonical_current_root)
            .to_owned();
        let state_root = violation
            .get("state_root")
            .and_then(Value::as_str)
            .map(ToOwned::to_owned)
            .unwrap_or_else(|| canonical_current_state_root.clone());
        let violation_profile_hash = violation
            .get("profile_hash")
            .and_then(Value::as_str)
            .unwrap_or_default()
            .to_owned();
        if !command_receipt_integrity_current(&violation) {
            unresolved.push(format!("{id} (receipt integrity is invalid)"));
            continue;
        }
        let Some(changes) = violation
            .get("workspace_guard")
            .and_then(|guard| guard.get("changes"))
            .and_then(Value::as_array)
        else {
            unresolved.push(format!("{id} (workspace preimages are missing)"));
            continue;
        };
        let workspace_key = (workspace_root.clone(), state_root.clone());
        if !workspace_cache.contains_key(&workspace_key) {
            let workspace_path = Path::new(&workspace_root);
            if !workspace_path.is_dir() {
                unresolved.push(format!("{id} (recorded workspace is missing)"));
                continue;
            }
            let fingerprint =
                read_only_workspace_fingerprint(workspace_path, profile, Path::new(&state_root))?;
            workspace_cache.insert(workspace_key.clone(), fingerprint);
        }
        let current = workspace_cache
            .get(&workspace_key)
            .expect("inserted workspace fingerprint");
        let mut restored = true;
        for change in changes {
            let Some(path) = change.get("path").and_then(Value::as_str) else {
                restored = false;
                break;
            };
            let Some(pre) = change.get("pre") else {
                restored = false;
                break;
            };
            if direct_workspace_fingerprint_entry(
                Path::new(&workspace_root),
                Path::new(&state_root),
                path,
            )? != *pre
            {
                restored = false;
                break;
            }
        }
        if !restored {
            unresolved.push(id.to_owned());
        } else {
            newly_remediated.push((
                id.to_owned(),
                violation
                    .get("receipt_hash")
                    .and_then(Value::as_str)
                    .unwrap_or_default()
                    .to_owned(),
                workspace_root,
                state_root,
                current.hash.clone(),
                violation_profile_hash,
            ));
        }
    }
    if !unresolved.is_empty() {
        return Err(KoniError::Process(format!(
            "compiler authority is quarantined by unresolved read-only violation receipt(s): {}. Restore every recorded preimage before compiling again",
            unresolved.join(", ")
        )));
    }
    let remediation_authority = command_authority_store(store, root)?;
    let remediation_dir = remediation_authority.work_dir().join("remediations");
    for (
        violation_id,
        violation_receipt_hash,
        workspace_root,
        state_root,
        workspace_hash,
        violation_profile_hash,
    ) in newly_remediated
    {
        let mut receipt = json!({
            "schema_version": "1.0",
            "id": Uuid::now_v7().to_string(),
            "receipt_type": "compiler.read-only-remediation",
            "producer": "compiler.read-only-quarantine",
            "status": "passed",
            "violation_id": violation_id,
            "violation_receipt_hash": violation_receipt_hash,
            "workspace_root": workspace_root,
            "state_root": state_root,
            "workspace_hash_at_remediation": workspace_hash,
            "violation_profile_hash": violation_profile_hash,
            "recorded_at": Utc::now(),
            "profile_hash": profile.hash,
            "receipt_hash": "",
        });
        rehash_durable_receipt(&mut receipt);
        let id = receipt["id"].as_str().expect("remediation receipt id");
        durable_atomic_write_yaml(&remediation_dir.join(format!("{id}.yaml")), &receipt)?;
    }
    Ok(())
}

fn authority_workspace_paths(
    root: &Path,
    profile: &CompiledProfile,
) -> Result<BTreeMap<String, WorkspacePathFingerprint>> {
    let mut paths = BTreeMap::new();
    let storage = &profile.manifest.storage;
    let state_prefix = storage
        .state_path
        .parent()
        .filter(|path| !path.as_os_str().is_empty())
        .unwrap_or(Path::new("."));
    let under_authority_root = |configured: &Path| -> Result<PathBuf> {
        let relative = if state_prefix == Path::new(".") {
            configured
        } else {
            configured.strip_prefix(state_prefix).map_err(|_| {
                KoniError::Profile(format!(
                    "compiler-owned path {} is outside state root {}",
                    configured.display(),
                    state_prefix.display()
                ))
            })?
        };
        Ok(root.join(relative))
    };
    let catalog = compiler_owned_state_catalog(storage);
    let semantic_work_dir = under_authority_root(&storage.work_dir)?;
    let mut roots = catalog
        .directories()
        .map(|path| under_authority_root(path))
        .collect::<Result<Vec<_>>>()?;
    roots.sort();
    roots.dedup();
    for semantic_root in roots {
        if !semantic_root.exists() {
            continue;
        }
        for entry in WalkDir::new(&semantic_root)
            .follow_links(false)
            .sort_by_file_name()
        {
            let entry = entry.map_err(|error| {
                KoniError::Process(format!("state authority inventory failed: {error}"))
            })?;
            let relative = entry.path().strip_prefix(root).map_err(|_| {
                KoniError::Process("state authority inventory escaped its root".to_owned())
            })?;
            let volatile_work_file = entry.path().starts_with(&semantic_work_dir)
                && entry.path().file_name().is_some_and(|name| {
                    matches!(
                        name.to_str(),
                        Some("worker.pid" | "worker.jsonl" | "stdout.log" | "stderr.log")
                    )
                });
            if relative.as_os_str().is_empty() || volatile_work_file {
                continue;
            }
            paths.insert(
                normalized_project_path(relative),
                workspace_path_fingerprint(entry.path(), None, None)?,
            );
        }
    }
    for file in catalog
        .preserved_files
        .iter()
        .map(|path| under_authority_root(path))
        .collect::<Result<Vec<_>>>()?
    {
        if file.exists() {
            let relative = file.strip_prefix(root).map_err(|_| {
                KoniError::Process("state authority file escaped its root".to_owned())
            })?;
            paths.insert(
                normalized_project_path(relative),
                workspace_path_fingerprint(&file, None, None)?,
            );
        }
    }
    Ok(paths)
}

fn normalized_command_exclusion_path(path: &Path) -> Result<String> {
    let path = path.to_str().ok_or_else(|| {
        KoniError::Profile("filesystem scope exclusion is not valid UTF-8".to_owned())
    })?;
    if path == "." {
        Ok(".".to_owned())
    } else {
        normalized_relative_path(path)
    }
}

fn project_path_is_excluded(path: &str, exclusions: &BTreeSet<CommandPathExclusion>) -> bool {
    exclusions.iter().any(|excluded| {
        if excluded.path == "." {
            return true;
        }
        let excluded_path = Path::new(&excluded.path);
        match excluded.match_mode {
            CommandPathExclusionMode::Component => Path::new(path)
                .components()
                .any(|component| component.as_os_str() == excluded_path.as_os_str()),
            CommandPathExclusionMode::Prefix => {
                Path::new(path) == excluded_path || Path::new(path).starts_with(excluded_path)
            }
        }
    })
}

fn reject_project_path_symlink_components(root: &Path, path: &str, authority: &str) -> Result<()> {
    let mut current = root.to_path_buf();
    for component in Path::new(path).components() {
        if matches!(component, std::path::Component::CurDir) {
            continue;
        }
        current.push(component.as_os_str());
        if fs::symlink_metadata(&current).is_ok_and(|metadata| metadata.file_type().is_symlink()) {
            return Err(KoniError::Action(format!(
                "{authority} rejects symlink component: {}",
                current.display()
            )));
        }
    }
    Ok(())
}

fn project_read_path_manifest(
    root: &Path,
    paths: &BTreeSet<String>,
    exclusions: &BTreeSet<CommandPathExclusion>,
) -> Result<Vec<Value>> {
    let canonical_root = root.canonicalize().map_err(|error| io_error(root, error))?;
    let mut manifests = Vec::new();
    for configured in paths {
        let normalized = if configured == "." {
            ".".to_owned()
        } else {
            normalized_relative_path(configured)?
        };
        let concrete = if normalized == "." {
            root.to_path_buf()
        } else {
            root.join(&normalized)
        };
        if project_path_is_excluded(&normalized, exclusions) {
            return Err(KoniError::Action(format!(
                "command read scope path is wholly excluded by its configured inventory policy: {normalized}"
            )));
        }
        if !concrete.exists() {
            return Err(KoniError::Action(format!(
                "dynamic command read scope path does not exist: {normalized}"
            )));
        }
        reject_project_path_symlink_components(root, &normalized, "read scope inventory")?;
        let resolved = concrete
            .canonicalize()
            .map_err(|error| io_error(&concrete, error))?;
        if !resolved.starts_with(&canonical_root) {
            return Err(KoniError::Action(format!(
                "read scope path escapes project root: {normalized}"
            )));
        }
        let mut files = Vec::new();
        if resolved.is_file() {
            let bytes = fs::read(&resolved).map_err(|error| io_error(&resolved, error))?;
            files.push(json!({
                "path": normalized,
                "bytes": bytes.len(),
                "sha256": raw_sha256(&bytes),
            }));
        } else if resolved.is_dir() {
            for entry in WalkDir::new(&concrete)
                .follow_links(false)
                .sort_by_file_name()
                .into_iter()
                .filter_entry(|entry| {
                    if entry.path() == concrete {
                        return true;
                    }
                    entry
                        .path()
                        .strip_prefix(root)
                        .ok()
                        .map(normalized_project_path)
                        .is_none_or(|path| !project_path_is_excluded(&path, exclusions))
                })
            {
                let entry = entry.map_err(|error| {
                    KoniError::Action(format!("read scope inventory failed: {error}"))
                })?;
                if entry.path() == concrete {
                    continue;
                }
                let metadata = fs::symlink_metadata(entry.path())
                    .map_err(|error| io_error(entry.path(), error))?;
                if metadata.file_type().is_symlink() {
                    return Err(KoniError::Action(format!(
                        "read scope inventory rejects symlink: {}",
                        entry.path().display()
                    )));
                }
                if !metadata.is_file() {
                    continue;
                }
                let relative = entry.path().strip_prefix(root).map_err(|_| {
                    KoniError::Action("read scope inventory escaped project".to_owned())
                })?;
                let path = normalized_project_path(relative);
                let bytes =
                    fs::read(entry.path()).map_err(|error| io_error(entry.path(), error))?;
                files.push(json!({
                    "path": path,
                    "bytes": bytes.len(),
                    "sha256": raw_sha256(&bytes),
                }));
            }
        } else {
            return Err(KoniError::Action(format!(
                "read scope path is neither file nor directory: {normalized}"
            )));
        }
        if files.is_empty() {
            return Err(KoniError::Action(format!(
                "dynamic command read scope path has no regular files: {normalized}"
            )));
        }
        files.sort_by(|left, right| left["path"].as_str().cmp(&right["path"].as_str()));
        let kind = if resolved.is_file() {
            "file"
        } else {
            "directory"
        };
        let mut manifest = json!({"path": normalized, "kind": kind, "files": files});
        manifest["hash"] = Value::String(normalized_hash(&manifest));
        manifests.push(manifest);
    }
    manifests.sort_by(|left, right| left["path"].as_str().cmp(&right["path"].as_str()));
    Ok(manifests)
}

fn dynamic_path_prestate(root: &Path, roots: &[String]) -> Result<Value> {
    let canonical_root = root.canonicalize().map_err(|error| io_error(root, error))?;
    let mut manifests = Vec::new();
    for configured in roots {
        if configured == "." {
            return Err(KoniError::Action(
                "produced-output authority may not cover the entire project".to_owned(),
            ));
        }
        let normalized = normalized_relative_path(configured)?;
        reject_project_path_symlink_components(root, &normalized, "produced-output scope")?;
        let concrete = root.join(&normalized);
        let mut files = Vec::new();
        let kind = if !concrete.exists() {
            "missing"
        } else {
            if fs::symlink_metadata(&concrete)
                .is_ok_and(|metadata| metadata.file_type().is_symlink())
            {
                return Err(KoniError::Action(format!(
                    "produced-output scope rejects symlink: {}",
                    concrete.display()
                )));
            }
            let resolved = concrete
                .canonicalize()
                .map_err(|error| io_error(&concrete, error))?;
            if !resolved.starts_with(&canonical_root) {
                return Err(KoniError::Action(format!(
                    "produced-output scope escapes project root: {normalized}"
                )));
            }
            if resolved.is_file() {
                let bytes = fs::read(&resolved).map_err(|error| io_error(&resolved, error))?;
                files.push(json!({
                    "path": normalized,
                    "bytes": bytes.len(),
                    "sha256": raw_sha256(&bytes),
                }));
                "file"
            } else if resolved.is_dir() {
                for entry in WalkDir::new(&concrete)
                    .follow_links(false)
                    .sort_by_file_name()
                {
                    let entry = entry.map_err(|error| {
                        KoniError::Action(format!(
                            "produced-output prestate inventory failed: {error}"
                        ))
                    })?;
                    if entry.path() == concrete {
                        continue;
                    }
                    let metadata = fs::symlink_metadata(entry.path())
                        .map_err(|error| io_error(entry.path(), error))?;
                    if metadata.file_type().is_symlink() {
                        return Err(KoniError::Action(format!(
                            "produced-output scope rejects symlink: {}",
                            entry.path().display()
                        )));
                    }
                    if !metadata.is_file() {
                        continue;
                    }
                    let relative = entry.path().strip_prefix(root).map_err(|_| {
                        KoniError::Action("produced-output prestate escaped project".to_owned())
                    })?;
                    let path = normalized_project_path(relative);
                    let bytes =
                        fs::read(entry.path()).map_err(|error| io_error(entry.path(), error))?;
                    files.push(json!({
                        "path": path,
                        "bytes": bytes.len(),
                        "sha256": raw_sha256(&bytes),
                    }));
                }
                "directory"
            } else {
                return Err(KoniError::Action(format!(
                    "produced-output scope is neither a file nor directory: {normalized}"
                )));
            }
        };
        files.sort_by(|left, right| left["path"].as_str().cmp(&right["path"].as_str()));
        let mut manifest = json!({"path": normalized, "kind": kind, "files": files});
        manifest["hash"] = Value::String(normalized_hash(&manifest));
        manifests.push(manifest);
    }
    manifests.sort_by(|left, right| left["path"].as_str().cmp(&right["path"].as_str()));
    let mut prestate = json!({"schema_version": "1.0", "roots": manifests});
    prestate["hash"] = Value::String(normalized_hash(&prestate));
    Ok(prestate)
}

fn path_manifest_sha256<'a>(manifests: &'a [Value], path: &str) -> Option<&'a str> {
    manifests
        .iter()
        .filter_map(|manifest| manifest.get("files").and_then(Value::as_array))
        .flatten()
        .find(|file| file.get("path").and_then(Value::as_str) == Some(path))
        .and_then(|file| file.get("sha256"))
        .and_then(Value::as_str)
}

fn dynamic_prestate_sha256<'a>(prestate: &'a Value, path: &str) -> Option<&'a str> {
    prestate
        .get("roots")
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
        .filter_map(|manifest| manifest.get("files").and_then(Value::as_array))
        .flatten()
        .find(|file| file.get("path").and_then(Value::as_str) == Some(path))
        .and_then(|file| file.get("sha256"))
        .and_then(Value::as_str)
}

fn collect_graph_node_references(value: &Value, graph: &Graph, output: &mut BTreeSet<NodeId>) {
    match value {
        Value::String(candidate) if graph.node(candidate).is_some() => {
            output.insert(candidate.clone());
        }
        Value::Array(items) => {
            for item in items {
                collect_graph_node_references(item, graph, output);
            }
        }
        Value::Object(object) => {
            for item in object.values() {
                collect_graph_node_references(item, graph, output);
            }
        }
        _ => {}
    }
}

fn receipt_sort_key(value: &Value) -> (String, String) {
    let timestamp = value
        .get("recorded_at")
        .or_else(|| value.get("finished_at"))
        .and_then(Value::as_str)
        .unwrap_or_default()
        .to_owned();
    let receipt_id = value
        .get("id")
        .or_else(|| value.get("receipt_id"))
        .and_then(Value::as_str)
        .unwrap_or_default()
        .to_owned();
    (timestamp, receipt_id)
}

fn load_receipt_rows_with_input_currentness(
    profile: &CompiledProfile,
    store: &StateStore,
    project_root: &Path,
    graph: &Graph,
    receipt_type: &str,
) -> Result<Vec<Value>> {
    let mut rows = load_receipt_rows(store.receipts_dir(), receipt_type)?;
    let violation_watermark = read_only_violation_watermark(profile, store, project_root)?;
    for receipt in &mut rows {
        strip_receipt_currentness_markers(receipt);
        if receipt_kind(receipt) == Some("scoped-compile") {
            let current = receipt
                .get("ticket_id")
                .and_then(Value::as_str)
                .and_then(|id| store.ticket(id).ok())
                .is_some_and(|ticket| {
                    scoped_compile_receipt_is_current(
                        profile,
                        &ticket,
                        receipt,
                        graph,
                        project_root,
                    )
                });
            mark_scoped_compile_currentness(receipt, current);
            continue;
        }
        let Some(check) = configured_command_check_for_receipt(profile, receipt) else {
            if receipt_names_configured_command(profile, receipt)
                || profile
                    .checks
                    .get(receipt_type)
                    .is_some_and(|check| check.kind == CheckKind::Command)
                || receipt_type_has_configured_command(profile, receipt_type)
            {
                mark_command_receipt_not_current(receipt);
            }
            continue;
        };
        let ticket = receipt
            .get("ticket_id")
            .and_then(Value::as_str)
            .and_then(|id| store.ticket(id).ok());
        decorate_command_receipt_currentness(
            profile,
            check,
            ticket.as_ref(),
            graph,
            project_root,
            store,
            receipt,
            violation_watermark,
        );
    }
    Ok(rows)
}

fn decorate_receipt_rows_for_ticket(
    profile: &CompiledProfile,
    store: &StateStore,
    ticket: &Ticket,
    graph: &Graph,
    project_root: &Path,
    rows: &mut [Value],
) {
    let violation_watermark = match read_only_violation_watermark(profile, store, project_root) {
        Ok(watermark) => watermark,
        Err(_) => {
            for receipt in rows {
                strip_receipt_currentness_markers(receipt);
                mark_command_receipt_not_current(receipt);
            }
            return;
        }
    };
    decorate_receipt_rows_for_ticket_with_watermark(
        profile,
        store,
        ticket,
        graph,
        project_root,
        rows,
        violation_watermark,
    );
}

fn decorate_receipt_rows_for_ticket_with_watermark(
    profile: &CompiledProfile,
    store: &StateStore,
    ticket: &Ticket,
    graph: &Graph,
    project_root: &Path,
    rows: &mut [Value],
    violation_watermark: Option<u64>,
) {
    for receipt in rows {
        strip_receipt_currentness_markers(receipt);
        if receipt_kind(receipt) == Some("scoped-compile") {
            let current =
                scoped_compile_receipt_is_current(profile, ticket, receipt, graph, project_root);
            mark_scoped_compile_currentness(receipt, current);
            continue;
        }
        if let Some(check) = configured_command_check_for_receipt(profile, receipt) {
            decorate_command_receipt_currentness(
                profile,
                check,
                Some(ticket),
                graph,
                project_root,
                store,
                receipt,
                violation_watermark,
            );
        } else if receipt_names_configured_command(profile, receipt) {
            mark_command_receipt_not_current(receipt);
        }
    }
}

fn strip_receipt_currentness_markers(receipt: &mut Value) {
    if let Some(object) = receipt.as_object_mut() {
        object.retain(|key, _| !key.starts_with('_'));
    }
}

fn mark_scoped_compile_currentness(receipt: &mut Value, current: bool) {
    if let Some(object) = receipt.as_object_mut() {
        object.insert("_scoped_compile_current".to_owned(), Value::Bool(current));
    }
}

fn receipt_type_has_configured_command(profile: &CompiledProfile, receipt_type: &str) -> bool {
    profile
        .checks
        .values()
        .any(|check| check.kind == CheckKind::Command && check.receipt_type == receipt_type)
}

fn receipt_names_configured_command(profile: &CompiledProfile, receipt: &Value) -> bool {
    receipt
        .get("check_id")
        .and_then(Value::as_str)
        .and_then(|id| profile.checks.get(id))
        .is_some_and(|check| check.kind == CheckKind::Command)
        || receipt_kind(receipt)
            .is_some_and(|kind| receipt_type_has_configured_command(profile, kind))
}

fn configured_command_check_for_receipt<'a>(
    profile: &'a CompiledProfile,
    receipt: &Value,
) -> Option<&'a crate::config::CheckDef> {
    let receipt_type = receipt.get("receipt_type").and_then(Value::as_str)?;
    if let Some(check_id) = receipt.get("check_id").and_then(Value::as_str) {
        return profile.checks.get(check_id).filter(|check| {
            check.kind == CheckKind::Command && check.receipt_type == receipt_type
        });
    }
    let mut matching_type = profile
        .checks
        .values()
        .filter(|check| check.kind == CheckKind::Command && check.receipt_type == receipt_type);
    let unique = matching_type.next()?;
    if matching_type.next().is_some() {
        return None;
    }
    Some(unique)
}

fn mark_command_receipt_not_current(receipt: &mut Value) {
    let Some(object) = receipt.as_object_mut() else {
        return;
    };
    for marker in [
        "_receipt_integrity_current",
        "_profile_current",
        "_execution_binding_current",
        "_target_scope_current",
        "_artifact_manifest_current",
        "_result_source_current",
        "_dynamic_paths_current",
        "_workspace_guard_current",
        "_terminal_evidence_current",
        "_spawn_binding_current",
        "_violation_precedence_current",
        "_input_binding_current",
        "_command_current",
    ] {
        object.insert(marker.to_owned(), Value::Bool(false));
    }
}

#[allow(clippy::too_many_arguments)]
fn decorate_command_receipt_currentness(
    profile: &CompiledProfile,
    check: &crate::config::CheckDef,
    ticket: Option<&Ticket>,
    graph: &Graph,
    project_root: &Path,
    store: &StateStore,
    receipt: &mut Value,
    violation_watermark: Option<u64>,
) {
    let integrity = command_receipt_integrity_current(receipt)
        && receipt.get("check_id").and_then(Value::as_str) == Some(check.id.as_str())
        && receipt.get("receipt_type").and_then(Value::as_str) == Some(check.receipt_type.as_str());
    let profile_current =
        receipt.get("profile_hash").and_then(Value::as_str) == Some(profile.hash.as_str());
    let recorded = receipt
        .get("execution_binding")
        .cloned()
        .and_then(|value| serde_json::from_value::<ResolvedCheckExecution>(value).ok());
    let recorded_post = receipt
        .get("post_execution_binding")
        .cloned()
        .and_then(|value| serde_json::from_value::<ResolvedCheckExecution>(value).ok());
    let recorded_integrity = recorded
        .as_ref()
        .is_some_and(resolved_execution_binding_integrity_current);
    let recorded_post_integrity = recorded_post
        .as_ref()
        .is_some_and(resolved_execution_binding_integrity_current);
    let mut cache = ExecutionResolutionCache::default();
    let current = recorded
        .as_ref()
        .and_then(|binding| binding.gate_policy_binding.as_ref())
        .map(|binding| {
            resolve_gate_policy_check_execution_with_store(
                profile,
                check,
                &binding.selection.policy_id,
                &binding.selection.gate.id,
                graph,
                project_root,
                store,
                &mut cache,
            )
        })
        .unwrap_or_else(|| {
            resolve_check_execution_with_store(profile, check, ticket, graph, project_root, store)
        })
        .ok();
    let execution_current = recorded
        .as_ref()
        .zip(recorded_post.as_ref())
        .zip(current.as_ref())
        .is_some_and(|((recorded, recorded_post), current)| {
            (recorded.binding_hash == current.binding_hash
                || gate_policy_execution_equivalent(recorded, current))
                && recorded_post.binding_hash == recorded.binding_hash
                && receipt
                    .get("execution_binding_hash")
                    .and_then(Value::as_str)
                    == Some(recorded.binding_hash.as_str())
                && receipt
                    .get("post_execution_binding_hash")
                    .and_then(Value::as_str)
                    == Some(recorded_post.binding_hash.as_str())
                && receipt
                    .get("execution_bindings_unchanged")
                    .and_then(Value::as_bool)
                    == Some(true)
                && receipt
                    .get("input_bindings_unchanged")
                    .and_then(Value::as_bool)
                    == Some(true)
                && receipt
                    .get("semantic_argv")
                    .and_then(Value::as_array)
                    .is_some_and(|argv| {
                        argv.iter().map(Value::as_str).collect::<Option<Vec<_>>>()
                            == Some(recorded.argv.iter().map(String::as_str).collect())
                    })
        });
    let target_scope_current = match recorded
        .as_ref()
        .and_then(|binding| binding.gate_policy_binding.as_ref())
    {
        Some(binding) => {
            let subject_ids = receipt
                .get("subject_node_ids")
                .and_then(Value::as_array)
                .into_iter()
                .flatten()
                .filter_map(Value::as_str)
                .collect::<BTreeSet<_>>();
            let evaluation_ids = receipt
                .get("evaluation_target_node_ids")
                .and_then(Value::as_array)
                .into_iter()
                .flatten()
                .filter_map(Value::as_str)
                .collect::<BTreeSet<_>>();
            subject_ids == BTreeSet::from([binding.selection.gate.id.as_str()])
                && evaluation_ids
                    == binding
                        .evaluation_targets
                        .keys()
                        .map(String::as_str)
                        .collect()
                && receipt.get("gate_policy_id").and_then(Value::as_str)
                    == Some(binding.selection.policy_id.as_str())
        }
        None => match (ticket, recorded.as_ref()) {
            (Some(ticket), Some(binding)) => {
                let target_ids = ticket.target_nodes.iter().cloned().collect::<BTreeSet<_>>();
                let recorded_ids = receipt
                    .get("target_node_ids")
                    .and_then(Value::as_array)
                    .into_iter()
                    .flatten()
                    .filter_map(Value::as_str)
                    .map(ToOwned::to_owned)
                    .collect::<BTreeSet<_>>();
                let target_hashes = receipt.get("target_hashes").and_then(Value::as_object);
                target_ids == recorded_ids
                    && binding.target_bindings.len() == target_ids.len()
                    && target_hashes.is_some_and(|hashes| {
                        target_ids.iter().all(|id| {
                            binding.target_bindings.get(id).is_some_and(|semantic| {
                                hashes.get(id).and_then(Value::as_str)
                                    == Some(semantic.semantic_hash.as_str())
                            })
                        })
                    })
            }
            (None, Some(binding)) => {
                receipt.get("ticket_id").is_none_or(Value::is_null)
                    && binding.target_bindings.is_empty()
                    && binding.read_scope_bindings.is_empty()
            }
            _ => false,
        },
    };
    let artifact_current = command_artifact_manifest_current(receipt, project_root);
    let result_source_current = command_result_source_current(receipt, project_root, check);
    let dynamic_paths_current = command_dynamic_path_manifest_current(
        receipt,
        project_root,
        check,
        ticket,
        recorded.as_ref(),
    );
    let workspace_guard_current = command_workspace_guard_current(receipt, check);
    let terminal_evidence_current = command_terminal_evidence_current(receipt);
    let spawn_binding_current = recorded
        .as_ref()
        .is_some_and(|recorded| command_spawn_binding_current(receipt, recorded));
    let violation_precedence_current = check.effect != crate::config::ProcessEffect::ReadOnly
        || violation_watermark.is_none_or(|watermark| {
            receipt
                .get("command_attempt_sequence")
                .and_then(Value::as_u64)
                .unwrap_or(0)
                > watermark
        });
    let current = integrity
        && profile_current
        && recorded_integrity
        && recorded_post_integrity
        && execution_current
        && target_scope_current
        && artifact_current
        && result_source_current
        && dynamic_paths_current
        && workspace_guard_current
        && terminal_evidence_current
        && spawn_binding_current
        && violation_precedence_current;
    let object = receipt.as_object_mut().expect("receipt row is an object");
    object.insert(
        "_receipt_integrity_current".to_owned(),
        Value::Bool(integrity),
    );
    object.insert("_profile_current".to_owned(), Value::Bool(profile_current));
    object.insert(
        "_execution_binding_current".to_owned(),
        Value::Bool(recorded_integrity && recorded_post_integrity && execution_current),
    );
    object.insert(
        "_target_scope_current".to_owned(),
        Value::Bool(target_scope_current),
    );
    object.insert(
        "_artifact_manifest_current".to_owned(),
        Value::Bool(artifact_current),
    );
    object.insert(
        "_result_source_current".to_owned(),
        Value::Bool(result_source_current),
    );
    object.insert(
        "_dynamic_paths_current".to_owned(),
        Value::Bool(dynamic_paths_current),
    );
    object.insert(
        "_workspace_guard_current".to_owned(),
        Value::Bool(workspace_guard_current),
    );
    object.insert(
        "_terminal_evidence_current".to_owned(),
        Value::Bool(terminal_evidence_current),
    );
    object.insert(
        "_spawn_binding_current".to_owned(),
        Value::Bool(spawn_binding_current),
    );
    object.insert(
        "_violation_precedence_current".to_owned(),
        Value::Bool(violation_precedence_current),
    );
    object.insert("_input_binding_current".to_owned(), Value::Bool(current));
    object.insert("_command_current".to_owned(), Value::Bool(current));
}

fn command_spawn_binding_current(receipt: &Value, execution: &ResolvedCheckExecution) -> bool {
    let Some(binding) = receipt.get("spawn_binding") else {
        return false;
    };
    if execution.sandbox_executable.is_none() {
        let semantic_argv_hash = normalized_hash(&execution.argv);
        return binding.get("kind").and_then(Value::as_str) == Some("none")
            && binding.get("semantic_argv_hash").and_then(Value::as_str)
                == Some(semantic_argv_hash.as_str());
    }
    let rendered_hash = binding.get("rendered_profile_hash").and_then(Value::as_str);
    binding.get("kind").and_then(Value::as_str) == Some("macos-seatbelt.v2")
        && binding.get("semantic_profile_hash").and_then(Value::as_str)
            == execution.sandbox_profile_hash.as_deref()
        && rendered_hash.is_some_and(|hash| {
            hash.strip_prefix("sha256:").is_some_and(|digest| {
                digest.len() == 64 && digest.bytes().all(|byte| byte.is_ascii_hexdigit())
            })
        })
        && binding
            .get("project_root")
            .and_then(Value::as_str)
            .is_some()
        && binding.get("state_root").and_then(Value::as_str).is_some()
        && binding
            .get("private_temp")
            .and_then(Value::as_str)
            .is_some()
}

fn gate_policy_execution_equivalent(
    recorded: &ResolvedCheckExecution,
    current: &ResolvedCheckExecution,
) -> bool {
    let (Some(recorded_gate), Some(current_gate)) = (
        recorded.gate_policy_binding.as_ref(),
        current.gate_policy_binding.as_ref(),
    ) else {
        return false;
    };
    if !gate_policy_selection_equivalent_except_compiler_ranks(
        &recorded_gate.selection,
        &current_gate.selection,
    ) {
        return false;
    }
    let mut normalized = current.clone();
    let gate = normalized
        .gate_policy_binding
        .as_mut()
        .expect("checked current gate binding");
    gate.selection = recorded_gate.selection.clone();
    gate.binding_hash.clear();
    gate.binding_hash = normalized_hash(gate);
    normalized.binding_hash.clear();
    normalized.binding_hash = normalized_hash(&normalized);
    normalized == *recorded
}

fn gate_policy_selection_equivalent_except_compiler_ranks(
    recorded: &GatePolicySelectionBinding,
    current: &GatePolicySelectionBinding,
) -> bool {
    if recorded.policy_id != current.policy_id
        || recorded.policy_hash != current.policy_hash
        || recorded.gate != current.gate
        || recorded.required_capability_name != current.required_capability_name
        || recorded.required_version_requirement != current.required_version_requirement
        || recorded.capability_contract_valid != current.capability_contract_valid
        || recorded.capability_contract_hash != current.capability_contract_hash
        || recorded.selection_mode != current.selection_mode
        || recorded.selection_contract != current.selection_contract
        || recorded.winner_id != current.winner_id
    {
        return false;
    }
    if recorded
        .candidate_pool_projection
        .iter()
        .map(|candidate| (&candidate.id, &candidate.node_type))
        .collect::<Vec<_>>()
        != current
            .candidate_pool_projection
            .iter()
            .map(|candidate| (&candidate.id, &candidate.node_type))
            .collect::<Vec<_>>()
    {
        return false;
    }
    let normalize = |candidate: &GateCandidateBinding| {
        json!({
            "id": candidate.id,
            "node_type": candidate.node_type,
            "semantic_hash": candidate.semantic_hash,
            "matched_capability_index": candidate.matched_capability_index,
            "matched_capability": candidate.matched_capability,
            "matched_capability_hash": candidate.matched_capability_hash,
            "tie_break_value": candidate.tie_break_value,
            "tie_break_hash": candidate.tie_break_hash,
        })
    };
    recorded
        .compatible_candidates
        .iter()
        .map(normalize)
        .collect::<Vec<_>>()
        == current
            .compatible_candidates
            .iter()
            .map(normalize)
            .collect::<Vec<_>>()
}

fn resolved_execution_binding_integrity_current(binding: &ResolvedCheckExecution) -> bool {
    let expected = binding.binding_hash.clone();
    if expected.is_empty() {
        return false;
    }
    let mut candidate = binding.clone();
    candidate.binding_hash.clear();
    normalized_hash(&candidate) == expected
        && binding
            .gate_policy_binding
            .as_ref()
            .is_none_or(gate_policy_binding_integrity_current)
}

fn gate_policy_binding_integrity_current(binding: &GatePolicyBinding) -> bool {
    if binding.binding_hash.is_empty()
        || binding
            .selection
            .compatible_candidates
            .iter()
            .any(|candidate| {
                normalized_hash(&candidate.matched_capability) != candidate.matched_capability_hash
                    || normalized_hash(&candidate.tie_break_value) != candidate.tie_break_hash
                    || candidate
                        .ranks
                        .iter()
                        .any(|rank| normalized_hash(&rank.observed) != rank.observed_hash)
            })
    {
        return false;
    }
    let expected = binding.binding_hash.clone();
    let mut candidate = binding.clone();
    candidate.binding_hash.clear();
    normalized_hash(&candidate) == expected
        && gate_policy_selection_binding_integrity_current(&binding.selection)
}

fn gate_policy_selection_binding_integrity_current(binding: &GatePolicySelectionBinding) -> bool {
    if binding.binding_hash.is_empty() {
        return false;
    }
    let expected = binding.binding_hash.clone();
    let mut candidate = binding.clone();
    candidate.binding_hash.clear();
    normalized_hash(&candidate) == expected
}

fn command_receipt_integrity_current(receipt: &Value) -> bool {
    durable_receipt_integrity_current(receipt) && command_attempt_hashes_current(receipt)
}

fn command_attempt_hashes_current(receipt: &Value) -> bool {
    receipt
        .get("attempts")
        .and_then(Value::as_array)
        .is_some_and(|attempts| {
            attempts.iter().enumerate().all(|(index, attempt)| {
                let stdout = attempt.get("stdout").and_then(Value::as_str);
                let stderr = attempt.get("stderr").and_then(Value::as_str);
                attempt.get("attempt").and_then(Value::as_u64) == Some((index + 1) as u64)
                    && stdout.is_some_and(|stdout| {
                        attempt.get("stdout_hash").and_then(Value::as_str)
                            == Some(raw_sha256(stdout.as_bytes()).as_str())
                    })
                    && stderr.is_some_and(|stderr| {
                        attempt.get("stderr_hash").and_then(Value::as_str)
                            == Some(raw_sha256(stderr.as_bytes()).as_str())
                    })
            })
        })
}

fn command_workspace_guard_current(receipt: &Value, check: &crate::config::CheckDef) -> bool {
    let Some(guard) = receipt.get("workspace_guard").and_then(Value::as_object) else {
        return false;
    };
    if check.effect != crate::config::ProcessEffect::ReadOnly {
        return guard.get("pre_hash").is_some_and(Value::is_null)
            && guard.get("post_hash").is_some_and(Value::is_null)
            && guard.get("unchanged").and_then(Value::as_bool) == Some(true);
    }
    let pre = guard.get("pre_hash").and_then(Value::as_str);
    let post = guard.get("post_hash").and_then(Value::as_str);
    pre.is_some()
        && pre == post
        && guard.get("unchanged").and_then(Value::as_bool) == Some(true)
        && guard
            .get("changed_paths")
            .and_then(Value::as_array)
            .is_some_and(Vec::is_empty)
        && receipt.get("status").and_then(Value::as_str) != Some("invalid_contract")
}

fn command_terminal_evidence_current(receipt: &Value) -> bool {
    let status = receipt.get("status").and_then(Value::as_str);
    let attempts = receipt.get("attempts").and_then(Value::as_array);
    match status {
        Some("interrupted" | "invalid_contract") | None => false,
        Some("timed_out") => attempts
            .and_then(|attempts| attempts.last())
            .is_some_and(|attempt| {
                attempt.get("timed_out").and_then(Value::as_bool) == Some(true)
                    && attempt.get("interrupted").and_then(Value::as_bool) == Some(false)
            }),
        Some("failed") => attempts
            .and_then(|attempts| attempts.last())
            .is_some_and(|attempt| {
                attempt.get("timed_out").and_then(Value::as_bool) == Some(false)
                    && attempt.get("interrupted").and_then(Value::as_bool) == Some(false)
            }),
        Some("passed" | "invalid_result") => attempts
            .and_then(|attempts| attempts.last())
            .is_some_and(|attempt| {
                attempt.get("timed_out").and_then(Value::as_bool) == Some(false)
                    && attempt.get("interrupted").and_then(Value::as_bool) == Some(false)
                    && attempt.get("exit_code").and_then(Value::as_i64) == Some(0)
            }),
        Some(_) => false,
    }
}

fn command_artifact_manifest_current(receipt: &Value, project_root: &Path) -> bool {
    let Some(recorded) = receipt.get("artifact_manifest").and_then(Value::as_object) else {
        return false;
    };
    let Some(expected_hash) = recorded.get("hash").and_then(Value::as_str) else {
        return false;
    };
    let mut recorded_without_hash = Value::Object(recorded.clone());
    recorded_without_hash
        .as_object_mut()
        .expect("artifact manifest object")
        .remove("hash");
    if normalized_hash(&recorded_without_hash) != expected_hash {
        return false;
    }
    let Some(rows) = recorded.get("artifacts").and_then(Value::as_array) else {
        return false;
    };
    let mut seen = BTreeSet::new();
    let mut current = Vec::new();
    for row in rows {
        let Some(path) = row.get("path").and_then(Value::as_str) else {
            return false;
        };
        if !seen.insert(path.to_owned()) {
            return false;
        }
        let Ok(artifact) = artifact_receipt(project_root, path) else {
            return false;
        };
        if !artifact.exists || artifact.error.is_some() {
            return false;
        }
        current.push(serde_json::to_value(artifact).expect("artifact receipt serializes"));
    }
    current.sort_by(|left, right| left["path"].as_str().cmp(&right["path"].as_str()));
    let mut current_manifest = json!({
        "schema_version": "1.0",
        "count": current.len(),
        "artifacts": current,
    });
    current_manifest["hash"] = Value::String(normalized_hash(&current_manifest));
    Value::Object(recorded.clone()) == current_manifest
}

fn command_result_source_current(
    receipt: &Value,
    project_root: &Path,
    check: &crate::config::CheckDef,
) -> bool {
    let manifest = receipt.get("result_source_manifest");
    if check.result_protocol.is_none() {
        return manifest.is_some_and(Value::is_null);
    }
    let status = receipt.get("status").and_then(Value::as_str);
    if manifest.is_some_and(Value::is_null) {
        return receipt.get("result_source").is_none_or(Value::is_null)
            && receipt.get("result").is_none_or(Value::is_null)
            && matches!(status, Some("failed" | "timed_out" | "invalid_result"));
    }
    let Some(manifest) = manifest.and_then(Value::as_object) else {
        return false;
    };
    let Some(expected_hash) = manifest.get("hash").and_then(Value::as_str) else {
        return false;
    };
    let mut without_hash = Value::Object(manifest.clone());
    without_hash
        .as_object_mut()
        .expect("result source manifest object")
        .remove("hash");
    if normalized_hash(&without_hash) != expected_hash {
        return false;
    }
    let Some(source) = manifest.get("source") else {
        return false;
    };
    if receipt.get("result_source") != Some(source) {
        return false;
    }
    let source_current = match source.get("kind").and_then(Value::as_str) {
        Some("stdout") => {
            let Some(stdout) = receipt
                .get("attempts")
                .and_then(Value::as_array)
                .and_then(|attempts| attempts.last())
                .and_then(|attempt| attempt.get("stdout"))
                .and_then(Value::as_str)
            else {
                return false;
            };
            let hash = raw_sha256(stdout.as_bytes());
            source.get("path").is_none_or(Value::is_null)
                && source.get("size_bytes").and_then(Value::as_u64) == Some(stdout.len() as u64)
                && source.get("sha256").and_then(Value::as_str) == Some(hash.as_str())
        }
        Some("file") => {
            let Some(path) = source.get("path").and_then(Value::as_str) else {
                return false;
            };
            let Ok(resolved) = contained_process_path(project_root, path) else {
                return false;
            };
            let Ok(bytes) = fs::read(resolved) else {
                return false;
            };
            let hash = raw_sha256(&bytes);
            !bytes.is_empty()
                && source.get("size_bytes").and_then(Value::as_u64) == Some(bytes.len() as u64)
                && source.get("sha256").and_then(Value::as_str) == Some(hash.as_str())
        }
        _ => false,
    };
    source_current
        && !matches!(
            status,
            Some("timed_out" | "interrupted" | "invalid_contract")
        )
}

fn command_dynamic_path_manifest_current(
    receipt: &Value,
    project_root: &Path,
    check: &crate::config::CheckDef,
    ticket: Option<&Ticket>,
    execution: Option<&ResolvedCheckExecution>,
) -> bool {
    let Some(execution) = execution else {
        return false;
    };
    if check.dynamic_result.is_none() {
        return true;
    };
    let Some(manifest) = receipt
        .get("dynamic_path_manifest")
        .and_then(Value::as_object)
    else {
        return false;
    };
    let Some(expected_hash) = manifest.get("hash").and_then(Value::as_str) else {
        return false;
    };
    let mut without_hash = Value::Object(manifest.clone());
    without_hash
        .as_object_mut()
        .expect("dynamic path manifest is an object")
        .remove("hash");
    if normalized_hash(&without_hash) != expected_hash {
        return false;
    }
    let Some(prestate) = receipt.get("dynamic_path_prestate") else {
        return false;
    };
    let Some(prestate_hash) = prestate.get("hash").and_then(Value::as_str) else {
        return false;
    };
    let mut prestate_without_hash = prestate.clone();
    let Some(prestate_object) = prestate_without_hash.as_object_mut() else {
        return false;
    };
    prestate_object.remove("hash");
    if normalized_hash(&prestate_without_hash) != prestate_hash {
        return false;
    }
    let Some(rows) = manifest.get("paths").and_then(Value::as_array) else {
        return false;
    };
    let has_path_authority = check
        .dynamic_result
        .as_ref()
        .is_some_and(|dynamic| dynamic.result_path.is_some() || dynamic.artifacts.is_some());
    if !has_path_authority {
        return rows.is_empty() && execution.result_path.is_none();
    }
    let Some(ticket) = ticket else {
        return false;
    };
    let mut seen = BTreeSet::new();
    for row in rows {
        let (Some(path), Some(authority), Some(provenance), Some(post_sha256)) = (
            row.get("path").and_then(Value::as_str),
            row.get("authority").and_then(Value::as_str),
            row.get("provenance").and_then(Value::as_str),
            row.get("post_sha256").and_then(Value::as_str),
        ) else {
            return false;
        };
        if !seen.insert(path.to_owned()) {
            return false;
        }
        let configured = check.dynamic_result.as_ref().is_some_and(|dynamic| {
            let result_authorities = dynamic
                .result_path
                .as_ref()
                .filter(|_| execution.result_path.as_deref() == Some(path))
                .into_iter()
                .flat_map(|path| &path.path_authorities);
            let artifact_authorities = dynamic
                .artifacts
                .as_ref()
                .into_iter()
                .flat_map(|artifacts| &artifacts.path_authorities);
            result_authorities
                .chain(artifact_authorities)
                .any(|allowed| {
                    serde_json::to_value(allowed.authority)
                        .ok()
                        .and_then(|value| value.as_str().map(|value| value == authority))
                        == Some(true)
                        && serde_json::to_value(allowed.provenance)
                            .ok()
                            .and_then(|value| value.as_str().map(|value| value == provenance))
                            == Some(true)
                })
        });
        if !configured {
            return false;
        }
        let Ok(current) = artifact_receipt(project_root, path) else {
            return false;
        };
        if !current.exists
            || current.error.is_some()
            || current.hash.as_deref() != Some(post_sha256)
        {
            return false;
        }
        let pre_sha256 = row.get("pre_sha256").and_then(Value::as_str);
        match (authority, provenance) {
            ("read_paths", "read_evidence") => {
                if !path_is_covered_by_ticket_scope(path, &ticket.scope.read_paths)
                    || pre_sha256 != Some(post_sha256)
                    || path_manifest_sha256(&execution.read_path_manifest, path)
                        != Some(post_sha256)
                {
                    return false;
                }
            }
            ("write_paths", "produced_output") => {
                if !path_is_covered_by_ticket_scope(path, &ticket.scope.write_paths)
                    || pre_sha256 == Some(post_sha256)
                    || dynamic_prestate_sha256(prestate, path) != pre_sha256
                {
                    return false;
                }
            }
            _ => return false,
        }
    }
    if let Some(path) = execution.result_path.as_deref()
        && !seen.contains(path)
    {
        return false;
    }
    receipt
        .get("result_validation")
        .and_then(|validation| validation.get("dynamic_artifacts"))
        .and_then(|artifacts| artifacts.get("declared_paths"))
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
        .filter_map(Value::as_str)
        .all(|path| seen.contains(path))
}

fn validate_argv_input_bindings(
    bindings: Option<&crate::config::ArgvInputBindingsDef>,
    candidate: &Value,
    argv: &[String],
    project_root: &Path,
    variables: &BTreeMap<String, String>,
) -> Result<()> {
    let Some(bindings) = bindings else {
        return Ok(());
    };
    let inputs = lookup_dynamic_path(candidate, &bindings.from, variables)
        .and_then(Value::as_array)
        .ok_or_else(|| {
            KoniError::Action(format!(
                "argv input binding source {} is not an array",
                bindings.from
            ))
        })?;
    if bindings.require_nonempty && inputs.is_empty() {
        return Err(KoniError::Action(format!(
            "argv input binding source {} must not be empty",
            bindings.from
        )));
    }
    let canonical_root = project_root
        .canonicalize()
        .map_err(|error| io_error(project_root, error))?;
    let mut errors = Vec::new();
    for (index, input) in inputs.iter().enumerate() {
        for field in &bindings.required_fields {
            if lookup_dynamic_path(input, field, variables).is_none_or(value_is_empty) {
                errors.push(format!("argv input {index} requires field {field}"));
            }
        }
        let path = lookup_dynamic_path(input, &bindings.path_field, variables)
            .and_then(Value::as_str)
            .unwrap_or_default();
        if path.is_empty() {
            errors.push(format!(
                "argv input {index} requires string path field {}",
                bindings.path_field
            ));
            continue;
        }
        if bindings.require_project_file {
            let relative = Path::new(path);
            let joined = match contained_join(project_root, relative) {
                Ok(joined) => joined,
                Err(_) => {
                    errors.push(format!(
                        "argv input {index} escapes the project root: {path}"
                    ));
                    continue;
                }
            };
            match joined.canonicalize() {
                Ok(canonical) if canonical.starts_with(&canonical_root) && canonical.is_file() => {}
                Ok(_) => errors.push(format!("argv input {index} is not a project file: {path}")),
                Err(_) => errors.push(format!("argv input {index} path does not exist: {path}")),
            }
        }
        if bindings.require_exact_argument && !argv.iter().any(|argument| argument == path) {
            errors.push(format!(
                "argv input {index} is not bound as an exact command argument: {path}"
            ));
        }
    }
    if errors.is_empty() {
        Ok(())
    } else {
        Err(KoniError::Action(errors.join("; ")))
    }
}

