    #[test]
    fn run_authority_barrier_is_reentrant_and_keeps_one_persistent_inode() {
        let temp = tempfile::tempdir().unwrap();
        let sidecar = temp.path().canonicalize().unwrap().join("koni");
        let first = acquire_run_authority_barrier_at(&sidecar, "run-test").unwrap();
        let path = run_authority_barrier_path(&sidecar, "run-test").unwrap();
        let second = acquire_run_authority_barrier_at(&sidecar, "run-test").unwrap();
        drop(first);

        let probe = fs::OpenOptions::new()
            .read(true)
            .write(true)
            .open(&path)
            .unwrap();
        assert!(probe.try_lock_exclusive().is_err());
        drop(second);
        probe.try_lock_exclusive().unwrap();
        probe.unlock().unwrap();
        assert!(
            path.is_file(),
            "barrier rendezvous inode must never be unlinked"
        );
    }

    #[test]
    fn run_authority_barrier_serializes_both_lock_orders_without_sleep_races() {
        let temp = tempfile::tempdir().unwrap();
        let sidecar = temp.path().canonicalize().unwrap().join("koni");
        let barrier = acquire_run_authority_barrier_at(&sidecar, "run-race").unwrap();
        let path = run_authority_barrier_path(&sidecar, "run-race").unwrap();
        let probe = fs::OpenOptions::new()
            .read(true)
            .write(true)
            .open(&path)
            .unwrap();
        assert!(probe.try_lock_exclusive().is_err());
        drop(barrier);
        probe.try_lock_exclusive().unwrap();
        probe.unlock().unwrap();

        let holder_path = path.clone();
        let (held_tx, held_rx) = std::sync::mpsc::channel();
        let (release_tx, release_rx) = std::sync::mpsc::channel();
        let holder = thread::spawn(move || {
            let file = fs::OpenOptions::new()
                .read(true)
                .write(true)
                .open(holder_path)
                .unwrap();
            file.lock_exclusive().unwrap();
            held_tx.send(()).unwrap();
            release_rx.recv().unwrap();
            file.unlock().unwrap();
        });
        held_rx.recv().unwrap();
        let waiter_sidecar = sidecar.clone();
        let (attempted_tx, attempted_rx) = std::sync::mpsc::channel();
        let (acquired_tx, acquired_rx) = std::sync::mpsc::channel();
        let waiter = thread::spawn(move || {
            attempted_tx.send(()).unwrap();
            let _guard = acquire_run_authority_barrier_at(&waiter_sidecar, "run-race").unwrap();
            acquired_tx.send(()).unwrap();
        });
        attempted_rx.recv().unwrap();
        assert!(acquired_rx.try_recv().is_err());
        release_tx.send(()).unwrap();
        acquired_rx
            .recv_timeout(std::time::Duration::from_secs(2))
            .unwrap();
        holder.join().unwrap();
        waiter.join().unwrap();
        assert!(path.is_file());
    }

    #[cfg(unix)]
    #[test]
    fn run_authority_barrier_rejects_a_symlink_without_touching_its_target() {
        use std::os::unix::fs::symlink;

        let temp = tempfile::tempdir().unwrap();
        let root = temp.path().canonicalize().unwrap();
        let sidecar = root.join("koni");
        let path = run_authority_barrier_path(&sidecar, "run-link").unwrap();
        let target = root.join("sentinel");
        fs::write(&target, "untouched").unwrap();
        fs::create_dir_all(path.parent().unwrap()).unwrap();
        symlink(&target, &path).unwrap();
        let error = match acquire_run_authority_barrier_at(&sidecar, "run-link") {
            Ok(_) => panic!("a redirected rendezvous must fail closed"),
            Err(error) => error,
        };
        assert!(error.to_string().contains("redirected"));
        assert_eq!(fs::read_to_string(target).unwrap(), "untouched");
    }

