    #[test]
    fn report_publication_recovers_every_hard_crash_boundary_without_losing_events() {
        let _serial = REPORT_PUBLICATION_TEST_LOCK
            .lock()
            .unwrap_or_else(std::sync::PoisonError::into_inner);
        let (_project, engine) = report_test_engine();
        let root = engine.root.clone();
        let store = engine.store().unwrap();
        engine.render_reports().unwrap();

        let phases = [
            "after_journal",
            "after_receipt_install",
            "after_snapshot_install",
            "during_event_append",
            "after_event_append",
            "after_report_backup",
            "after_report_install",
            "after_previous_cleanup",
        ];
        for (index, phase) in phases.into_iter().enumerate() {
            let history_event = Event {
                schema_version: "1.0".to_owned(),
                id: format!("unrelated-history-{index}"),
                event_type: "compiler.unrelated.history".to_owned(),
                at: Utc
                    .with_ymd_and_hms(2025, 2, 1, 0, 0, index as u32)
                    .single()
                    .unwrap(),
                run_id: "run-report-fixture".to_owned(),
                ticket_id: None,
                actor: "compiler".to_owned(),
                data: json!({"sequence": index}),
            };
            let events_path = store.root().join("events.jsonl");
            let mut history_line = serde_json::to_vec(&history_event).unwrap();
            if phase != "during_event_append" {
                history_line.push(b'\n');
            }
            let mut events_file = fs::OpenOptions::new()
                .append(true)
                .open(&events_path)
                .unwrap();
            events_file.write_all(&history_line).unwrap();
            events_file.sync_all().unwrap();
            drop(events_file);
            let events_before = fs::read(&events_path).unwrap();
            let reports_before = report_test_tree(store.reports_dir());

            let mut manifest = store.manifest().unwrap();
            manifest.status = format!("hard-crash-generation-{index}");
            store.write_manifest(&manifest).unwrap();
            let expected = engine.prepare_report_publication().unwrap();
            let mut expected_reports = expected.report_files.clone();
            expected_reports.insert(
                PathBuf::from("report-manifest.yaml"),
                expected.manifest_bytes.clone(),
            );

            let status = Command::new(std::env::current_exe().unwrap())
                .args([
                    "--ignored",
                    "--exact",
                    "engine::tests::report_publication_hard_crash_child",
                    "--nocapture",
                ])
                .env("KONI_REPORT_HARD_CRASH_ROOT", &root)
                .env("KONI_REPORT_HARD_CRASH_PHASE", phase)
                .stdin(Stdio::null())
                .stdout(Stdio::null())
                .stderr(Stdio::null())
                .status()
                .unwrap();
            #[cfg(unix)]
            {
                use std::os::unix::process::ExitStatusExt;
                assert_eq!(status.signal(), Some(9), "phase {phase}: {status}");
            }
            #[cfg(not(unix))]
            assert!(!status.success(), "phase {phase} unexpectedly survived");

            let crashed_reports = report_test_tree(store.reports_dir());
            assert!(
                crashed_reports.is_empty()
                    || crashed_reports == reports_before
                    || crashed_reports == expected_reports,
                "phase {phase} exposed a mixed trusted report generation"
            );
            assert!(
                fs::read(&events_path).unwrap().starts_with(&events_before),
                "phase {phase} lost historical events before recovery"
            );

            let reopened = report_test_open_engine(&root);
            let recovered = reopened.render_reports().unwrap();
            assert_eq!(recovered["status"], "current", "phase {phase}");
            let reopened_store = reopened.store().unwrap();
            assert_eq!(
                report_test_tree(reopened_store.reports_dir()),
                expected_reports,
                "phase {phase} published a mixed report generation"
            );
            let events_after = fs::read(reopened_store.root().join("events.jsonl")).unwrap();
            assert!(
                events_after.starts_with(&events_before),
                "phase {phase} rewrote unrelated historical events"
            );
            let parsed_events = String::from_utf8(events_after.clone())
                .unwrap()
                .lines()
                .map(|line| serde_json::from_str::<Value>(line).unwrap())
                .collect::<Vec<_>>();
            assert_eq!(
                parsed_events
                    .iter()
                    .filter(|event| {
                        event["data"]["transaction_hash"]
                            == Value::String(expected.transaction_hash.clone())
                    })
                    .count(),
                1,
                "phase {phase} duplicated its transaction event"
            );
            assert_eq!(
                parsed_events
                    .iter()
                    .filter(|event| event["id"] == history_event.id)
                    .count(),
                1,
                "phase {phase} lost or duplicated unrelated history"
            );
            assert_eq!(
                report_test_tree(reopened_store.receipts_dir()).len(),
                index + 2,
                "phase {phase} duplicated or lost report receipts"
            );
            assert_eq!(
                report_test_tree(&reopened_store.root().join("snapshots")).len(),
                index + 2,
                "phase {phase} duplicated or lost report snapshots"
            );
            assert!(
                !report_publication_transaction_root(reopened_store.root()).exists(),
                "phase {phase} left a recovered journal behind"
            );
        }
    }

