    #[test]
    fn gate_capability_contract_uses_full_semver_and_ordered_aliases() {
        let profile = compiled_research_profile();
        let temp = tempfile::tempdir().unwrap();
        let store = StateStore::new(temp.path().join("program"));
        store.ensure_layout().unwrap();
        let cases = [
            ("1.2.3", "1.2.3", true),
            ("1.2.3", "1.2.4", false),
            ("^1.2.3", "1.9.0", true),
            ("^1.2.3", "2.0.0", false),
            ("^0.2.3", "0.2.9", true),
            ("^0.2.3", "0.3.0", false),
            ("~1.2.3", "1.2.9", true),
            ("~1.2.3", "1.3.0", false),
            ("1.*", "1.9.7", true),
            ("1.*", "2.0.0", false),
            (">=1.0.0 <2.0.0", "1.8.0", true),
            (">=1.0.0 <2.0.0", "2.0.0", false),
            ("=1.2.3", "1.2.3+build.7", true),
            (">=1.0.0 <2.0.0", "1.1.0-alpha.1", false),
            (">=1.1.0-alpha.1 <2.0.0", "1.1.0-alpha.1", true),
        ];
        for (index, (required, provided, expected)) in cases.into_iter().enumerate() {
            let gate = policy_gate(&format!("gate-{index}"), required);
            let asset = policy_asset(&format!("asset-{index}"), provided);
            let mut graph = Graph::default();
            graph.insert(gate.clone()).unwrap();
            graph.insert(asset.clone()).unwrap();
            let resolver = GraphResolver::new(&graph, &profile, &store, temp.path());
            assert_eq!(
                resolver
                    .gate_policy_compatible("research-capability-gates", &gate, &asset,)
                    .unwrap(),
                expected,
                "requirement {required:?}, provided {provided:?}"
            );
        }

        let mut malformed_gate = policy_gate("gate-malformed", "not semver");
        malformed_gate.spec["capability"]["protocol"] = json!(">=1.0.0");
        let asset = policy_asset("asset-valid", "1.2.3");
        let mut graph = Graph::default();
        graph.insert(malformed_gate.clone()).unwrap();
        graph.insert(asset.clone()).unwrap();
        let resolver = GraphResolver::new(&graph, &profile, &store, temp.path());
        let error = resolver
            .gate_policy_compatible("research-capability-gates", &malformed_gate, &asset)
            .unwrap_err();
        assert!(error.to_string().contains("malformed SemVer"), "{error}");

        let gate = policy_gate("gate-alias", ">=1.0.0");
        let mut malformed_provider = policy_asset("asset-alias", "broken");
        malformed_provider.spec["capabilities"][0]["version"] = json!("1.2.3");
        let mut graph = Graph::default();
        graph.insert(gate.clone()).unwrap();
        graph.insert(malformed_provider.clone()).unwrap();
        let resolver = GraphResolver::new(&graph, &profile, &store, temp.path());
        assert!(
            !resolver
                .gate_policy_compatible("research-capability-gates", &gate, &malformed_provider,)
                .unwrap()
        );
    }

    #[test]
    fn gate_policy_ranking_binds_every_reason_and_is_insertion_order_independent() {
        let profile = compiled_research_profile();
        let temp = tempfile::tempdir().unwrap();
        let store = StateStore::new(temp.path().join("program"));
        store.ensure_layout().unwrap();
        let gate = policy_gate("gate", ">=1.0.0 <2.0.0");
        let mut candidates = Vec::new();
        let mut contract = policy_asset("z-contract", "1.0.0");
        contract.spec["gate_contracts"] = json!({"\"gate\"": {"command": ["true"]}});
        candidates.push(contract);
        let mut passed = policy_asset("a-passed", "1.0.0");
        passed.spec["gate_results"] = json!({"gate": "failed"});
        passed.spec["spec"] = json!({"gate_results": {"gate": "failed"}});
        passed.spec["capabilities"][0]["gate_results"] = json!({" 'gate' ": "passed"});
        candidates.push(passed);
        let mut targeted = policy_asset("targeted", "1.0.0");
        targeted.spec["target_gate_id"] = json!("gate");
        candidates.push(targeted);
        let mut explicit = policy_asset("explicit", "1.0.0");
        explicit
            .edges
            .insert("validates".to_owned(), vec!["gate".to_owned()]);
        candidates.push(explicit);
        let mut any_result = policy_asset("any-result", "1.0.0");
        any_result.spec["gate_results"] = json!({"gate": "failed"});
        candidates.push(any_result);
        candidates.push(policy_asset("fallback", "1.0.0"));

        let resolve = |items: Vec<Node>| {
            let mut graph = Graph::default();
            graph.insert(gate.clone()).unwrap();
            for item in items {
                graph.insert(item).unwrap();
            }
            let resolver = GraphResolver::new(&graph, &profile, &store, temp.path());
            resolver
                .gate_policy_selection_binding("research-capability-gates", "gate")
                .unwrap()
        };
        let forward = resolve(candidates.clone());
        let reverse = resolve(candidates.into_iter().rev().collect());
        assert_eq!(forward.binding_hash, reverse.binding_hash);
        assert_eq!(forward.winner_id.as_deref(), Some("z-contract"));
        assert!(gate_policy_selection_binding_integrity_current(&forward));
        let first_ranks = forward
            .compatible_candidates
            .iter()
            .map(|candidate| (candidate.id.as_str(), candidate.first_matching_rank))
            .collect::<BTreeMap<_, _>>();
        assert_eq!(first_ranks["z-contract"], Some(0));
        assert_eq!(first_ranks["a-passed"], Some(1));
        assert_eq!(first_ranks["targeted"], Some(2));
        assert_eq!(first_ranks["explicit"], Some(3));
        assert_eq!(first_ranks["any-result"], Some(4));
        assert_eq!(first_ranks["fallback"], Some(5));
        assert!(forward.compatible_candidates.iter().all(|candidate| {
            candidate.ranks.len() == 6
                && candidate
                    .ranks
                    .iter()
                    .all(|rank| normalized_hash(&rank.observed) == rank.observed_hash)
        }));

        let mut quoted_override = policy_asset("quoted-override", "1.0.0");
        quoted_override.spec["gate_results"] = json!({"gate": "passed"});
        quoted_override.spec["spec"] = json!({"gate_results": {"\"gate\"": "failed"}});
        let binding = resolve(vec![quoted_override]);
        assert_eq!(
            binding.compatible_candidates[0].first_matching_rank,
            Some(4)
        );
    }

    #[test]
    fn exact_one_policy_distinguishes_zero_one_and_ambiguous_candidates() {
        let mut profile = compiled_research_profile();
        let policy = profile
            .gate_policies
            .get_mut("research-capability-gates")
            .unwrap();
        policy.selection.mode = GateSelectionMode::ExactlyOne;
        policy.selection.ranks.clear();
        policy.selection.tie_break = None;
        let temp = tempfile::tempdir().unwrap();
        let store = StateStore::new(temp.path().join("program"));
        store.ensure_layout().unwrap();
        for count in 0..=2 {
            let mut graph = Graph::default();
            graph.insert(policy_gate("gate", ">=1.0.0")).unwrap();
            for index in 0..count {
                graph
                    .insert(policy_asset(&format!("asset-{index}"), "1.0.0"))
                    .unwrap();
            }
            let resolver = GraphResolver::new(&graph, &profile, &store, temp.path());
            let binding = resolver
                .gate_policy_selection_binding("research-capability-gates", "gate")
                .unwrap();
            assert_eq!(binding.compatible_candidates.len(), count);
            assert_eq!(binding.winner_id.is_some(), count == 1);
            resolver.bind("target", vec!["gate".to_owned()]);
            let predicate: Predicate = serde_yaml::from_str(&format!(
                "op: gate_policy_candidate_count\ngate_policy: research-capability-gates\ngate_subject: $target\nexact: {count}\n"
            ))
            .unwrap();
            assert!(predicate.evaluate(&resolver).unwrap());
        }
    }

