    #[test]
    fn changed_scientific_input_makes_current_receipt_false_and_reopens_run_work() {
        let profile = compiled_research_profile();
        let temp = tempfile::tempdir().unwrap();
        fs::create_dir_all(temp.path().join("inputs")).unwrap();
        fs::write(
            temp.path().join("inputs/runner.py"),
            concat!(
                "import json\n",
                "print(json.dumps({'schema_version':'1.0',",
                "'protocol':'autoresearch.research-result.v1',",
                "'verdict':'supported','measurements':{'rows':1},",
                "'observations':['ok'],'artifacts':[]}))\n"
            ),
        )
        .unwrap();
        fs::write(temp.path().join("inputs/data.txt"), b"initial input").unwrap();
        let store = StateStore::new(temp.path().join("program"));
        store.ensure_layout().unwrap();
        install_active_test_run_identity(&store, temp.path(), &profile);
        let mut graph = Graph::default();
        let runtime_contract = json!({
            "command": ["python3", "inputs/runner.py", "inputs/data.txt"],
            "result_protocol": "autoresearch.research-result.v1",
            "required_measurements": ["rows"],
            "asset_entrypoints": [{"asset_id": "asset", "path": "inputs/runner.py"}],
            "scientific_inputs": [{
                "asset_id": "asset",
                "role": "dataset",
                "path": "inputs/data.txt"
            }]
        });
        let mut run = Node::new("run", "Run", json!({"runtime_contract": runtime_contract}));
        run.id = "run".to_owned();
        run.edges
            .insert("uses".to_owned(), vec!["asset".to_owned()]);
        run.extensions
            .insert("readiness".to_owned(), json!({"state": "ready"}));
        let mut asset = Node::new("asset", "Asset", json!({"revision": 1}));
        asset.id = "asset".to_owned();
        graph.insert(run).unwrap();
        graph.insert(asset).unwrap();
        let ticket = Ticket {
            schema_version: "1.0".to_owned(),
            id: "run-ticket".to_owned(),
            operation: "run-experiment".to_owned(),
            status: "closed".to_owned(),
            title: "Run".to_owned(),
            target_nodes: vec!["run".to_owned()],
            scope: Scope {
                read_nodes: BTreeSet::from(["run".to_owned(), "asset".to_owned()]),
                read_paths: BTreeSet::from(["inputs".to_owned()]),
                ..Scope::default()
            },
            source_state_key: "missing".to_owned(),
            target_state_key: "current".to_owned(),
            obligation_keys: Vec::new(),
            profile_hash: profile.hash.clone(),
            rule_id: "ticket.run-experiment".to_owned(),
            workflow: Vec::new(),
            outputs: Vec::new(),
            reviews: Vec::new(),
            blockers: Vec::new(),
            lease: None,
            change_control: TicketChangeControl::default(),
            extensions: BTreeMap::new(),
        };
        store.write_ticket(&ticket).unwrap();
        for id in ["run", "asset"] {
            graph.save_node(&store.graph_dir(), id).unwrap();
        }
        let engine = Engine {
            root: temp.path().to_path_buf(),
            profile: profile.clone(),
            store: Some(store.clone()),
            run_git_templates: None,
            run_slug: None,
            resolved_run_type: None,
            compiler_action_context: BTreeMap::new(),
            ticket_review_authorization: None,
        };
        let receipt = engine
            .run_check(&BTreeMap::from([
                ("check".to_owned(), json!("scientific-runtime")),
                ("ticket".to_owned(), json!(ticket.id)),
            ]))
            .unwrap();
        assert_eq!(receipt["status"], "passed");
        let decorated = load_receipt_rows_with_input_currentness(
            &profile,
            &store,
            temp.path(),
            &graph,
            "runtime.receipt",
        )
        .unwrap();
        assert_eq!(
            decorated[0]["_command_current"],
            true,
            "{}",
            serde_json::to_string_pretty(&decorated[0]).unwrap()
        );
        let run_rule = &profile.rules["ticket.run-experiment"];
        let resolver = GraphResolver::new(&graph, &profile, &store, temp.path());
        resolver.bind("target", vec!["run".to_owned()]);
        assert!(!run_rule.when.evaluate(&resolver).unwrap());

        fs::write(temp.path().join("inputs/data.txt"), b"changed input").unwrap();
        let resolver = GraphResolver::new(&graph, &profile, &store, temp.path());
        resolver.bind("target", vec!["run".to_owned()]);
        assert!(run_rule.when.evaluate(&resolver).unwrap());
    }

    #[test]
    fn evidence_work_waits_for_every_exact_run_in_each_claim_portfolio() {
        let profile = compiled_research_profile();
        let temp = tempfile::tempdir().unwrap();
        let store = StateStore::new(temp.path().join("program"));
        store.ensure_layout().unwrap();
        let mut graph = Graph::default();
        let mut hypothesis = Node::new("hypothesis", "Hypothesis", json!({}));
        hypothesis.id = "hypothesis".to_owned();
        hypothesis.edges.insert(
            "claims".to_owned(),
            vec!["claim-a".to_owned(), "claim-b".to_owned()],
        );
        hypothesis.edges.insert(
            "experiments".to_owned(),
            vec!["experiment-a".to_owned(), "experiment-b".to_owned()],
        );
        graph.insert(hypothesis).unwrap();
        for suffix in ["a", "b"] {
            let claim_id = format!("claim-{suffix}");
            let experiment_id = format!("experiment-{suffix}");
            let run_id = format!("run-{suffix}");
            let ablation_id = format!("ablation-{suffix}");
            let ablation_run_id = format!("ablation-run-{suffix}");
            let mut claim = Node::new("claim", format!("Claim {suffix}"), json!({}));
            claim.id = claim_id.clone();
            claim
                .edges
                .insert("tested_by".to_owned(), vec![experiment_id.clone()]);
            let mut experiment = Node::new("experiment", format!("Experiment {suffix}"), json!({}));
            experiment.id = experiment_id;
            experiment
                .edges
                .insert("target_claims".to_owned(), vec![claim_id]);
            experiment
                .edges
                .insert("runs".to_owned(), vec![run_id.clone()]);
            experiment
                .edges
                .insert("ablations".to_owned(), vec![ablation_id.clone()]);
            let mut run = Node::new("run", format!("Run {suffix}"), json!({}));
            run.id = run_id;
            let mut ablation = Node::new("ablation", format!("Ablation {suffix}"), json!({}));
            ablation.id = ablation_id;
            ablation
                .edges
                .insert("runs".to_owned(), vec![ablation_run_id.clone()]);
            let mut ablation_run = Node::new("run", format!("Ablation run {suffix}"), json!({}));
            ablation_run.id = ablation_run_id;
            for node in [claim, experiment, run, ablation, ablation_run] {
                graph.insert(node).unwrap();
            }
        }
        write_bound_runtime_fixture_receipt(
            &profile,
            temp.path(),
            &store,
            &mut graph,
            "run-a",
            "run-a-receipt",
            "2026-01-01T00:00:00Z",
        );
        write_bound_runtime_fixture_receipt(
            &profile,
            temp.path(),
            &store,
            &mut graph,
            "ablation-run-a",
            "ablation-run-a-receipt",
            "2026-01-01T00:00:01Z",
        );
        let rule = &profile.rules["ticket.synthesize-evidence"];
        let resolver = GraphResolver::new(&graph, &profile, &store, temp.path());
        resolver.bind("target", vec!["claim-a".to_owned()]);
        assert!(
            !rule.when.evaluate(&resolver).unwrap(),
            "hypothesis-wide evidence waits for claim B's experiment and ablation runs"
        );
        let resolver = GraphResolver::new(&graph, &profile, &store, temp.path());
        resolver.bind("target", vec!["claim-b".to_owned()]);
        assert!(
            !rule.when.evaluate(&resolver).unwrap(),
            "claim A's connected receipt must not emit evidence work for claim B"
        );
        write_bound_runtime_fixture_receipt(
            &profile,
            temp.path(),
            &store,
            &mut graph,
            "run-b",
            "run-b-receipt",
            "2026-01-01T00:00:02Z",
        );
        write_bound_runtime_fixture_receipt(
            &profile,
            temp.path(),
            &store,
            &mut graph,
            "ablation-run-b",
            "ablation-run-b-receipt",
            "2026-01-01T00:00:03Z",
        );
        for claim_id in ["claim-a", "claim-b"] {
            let resolver = GraphResolver::new(&graph, &profile, &store, temp.path());
            resolver.bind("target", vec![claim_id.to_owned()]);
            assert!(rule.when.evaluate(&resolver).unwrap());
        }
    }

