    #[test]
    fn later_planning_prompt_reuses_the_durable_repository_baseline() {
        let prompt = |prior: &[Value]| {
            planning_agent_prompt(
                "persona",
                Some("stage"),
                "ask questions",
                "interactive",
                "goal",
                "risk-review",
                &json!({"goal": "goal"}),
                prior,
                &[],
                false,
            )
            .unwrap()
        };

        let initial = prompt(&[]);
        assert!(
            initial.contains("may establish repository and Git baseline facts"),
            "{initial}"
        );
        assert!(!initial.contains(PLANNING_BASELINE_REUSE_BOUNDARY));

        let prior = vec![json!({
            "pass": 1,
            "title": "Architecture",
            "output": "Repository baseline established; src/parser.rs remains unresolved."
        })];
        let later = prompt(&prior);
        assert!(later.contains(PLANNING_BASELINE_REUSE_BOUNDARY));
        assert!(later.contains("unchanged pinned checkout"), "{later}");
        assert!(
            later.contains("Do not rerun generic repository inventory"),
            "{later}"
        );
        assert!(
            later.contains("specific unresolved question about that file"),
            "{later}"
        );
        assert!(
            later.contains("src/parser.rs remains unresolved"),
            "{later}"
        );
        assert!(!later.contains("may establish repository and Git baseline facts"));
    }

    fn assert_codex_multi_agent_is_disabled(args: &[String]) {
        let boundaries = args
            .windows(2)
            .filter(|pair| *pair == ["--disable", CODEX_MULTI_AGENT_FEATURE])
            .count();
        assert_eq!(
            boundaries, 1,
            "expected one single-agent boundary: {args:?}"
        );
    }

    #[test]
    fn every_primary_codex_agent_argv_disables_ambient_multi_agent() {
        let temp = tempfile::TempDir::new().unwrap();
        let scratch = ReadOnlyCodexScratch::create(&[temp.path()]).unwrap();
        let native_overrides = vec!["features.multi_agent=true".to_owned()];
        let options = CodexAgentLaunchOptions {
            model: Some("test-model"),
            reasoning_effort: Some("high"),
            native_config_overrides: &native_overrides,
        };
        let root = temp.path();
        let output = temp.path().join("output.json");
        let schema = temp.path().join("schema.json");
        let runtime_mcp = build_agent_mcp_launch_config(
            std::env::current_exe().unwrap(),
            "grant-test",
            "worker-test",
            1,
            agent_mcp_enabled_tools(None),
        )
        .unwrap();
        let permissions =
            agent_permission_assignments(&StorageConfig::default(), false, false).unwrap();
        let launches = [
            ticket_worker_agent_argv(
                root,
                "never",
                false,
                false,
                &permissions,
                options,
                &runtime_mcp,
            ),
            review_agent_argv(root, &output, &scratch, options, "review"),
            planning_agent_argv(None, root, &output, &schema, &scratch, options, "plan"),
            planning_agent_argv(
                Some("019f54e0-72c9-7bf3-a0c9-f608dd77fd81"),
                root,
                &output,
                &schema,
                &scratch,
                options,
                "resume plan",
            ),
        ];

        for args in launches {
            assert_codex_multi_agent_is_disabled(&args);
            let native_enable = args
                .iter()
                .position(|arg| arg == "features.multi_agent=true")
                .expect("test override is present");
            let enforced_disable = args
                .iter()
                .position(|arg| arg == "--disable")
                .expect("single-agent switch is present");
            assert!(
                enforced_disable > native_enable,
                "the compiler-owned boundary must take precedence: {args:?}"
            );
        }
    }

    #[test]
    fn worker_runtime_mcp_is_one_highest_layer_identity_bound_table() {
        let temp = tempfile::TempDir::new().unwrap();
        let root = temp.path().canonicalize().unwrap();
        let executable = std::env::current_exe().unwrap();
        let runtime = build_agent_mcp_launch_config(
            executable.clone(),
            "grant-019f",
            "worker-019f",
            2,
            agent_mcp_enabled_tools(None),
        )
        .unwrap();
        let hostile_override = "mcp_servers.koni_runtime.enabled_tools=[\"unbounded\"]".to_owned();
        let native_overrides = vec![hostile_override.clone()];
        let permissions =
            agent_permission_assignments(&StorageConfig::default(), false, false).unwrap();
        let args = ticket_worker_agent_argv(
            &root,
            "never",
            false,
            false,
            &permissions,
            CodexAgentLaunchOptions {
                model: None,
                reasoning_effort: None,
                native_config_overrides: &native_overrides,
            },
            &runtime,
        );
        let reserved = runtime.codex_assignment();
        assert!(
            !args.iter().any(|arg| arg == &hostile_override),
            "native MCP config must never enter a bounded Codex argv"
        );
        let reserved_index = args.iter().position(|arg| arg == &reserved).unwrap();
        assert!(reserved_index > 0);
        assert!(reserved.starts_with("mcp_servers={koni_runtime={"));
        for exact in [
            "enabled=true",
            "required=true",
            "default_tools_approval_mode=\"approve\"",
            "tool_timeout_sec=3660",
            "enabled_tools=[\"context\",\"submit_output\",\"compile\"]",
        ] {
            assert!(reserved.contains(exact), "missing {exact}: {reserved}");
        }
        assert!(!reserved.contains("ask_question"));
        assert!(
            runtime
                .server_args
                .windows(2)
                .any(|pair| pair == ["--grant", "grant-019f"])
        );
        assert!(
            runtime
                .server_args
                .windows(2)
                .any(|pair| pair == ["--agent-id", "worker-019f"])
        );
        for forbidden in [
            "--root",
            "--run",
            "--persona",
            "--ticket",
            "--step",
            "--input-hash",
            "--allow-tool",
        ] {
            assert!(
                !runtime
                    .server_args
                    .iter()
                    .any(|argument| argument == forbidden)
            );
        }
        assert!(runtime.inherited_environment.is_empty());
        assert_eq!(runtime.command, executable.canonicalize().unwrap());
    }

