    #[test]
    fn autonomous_permissions_protect_config_for_every_backend_and_all_state_catalog_paths() {
        for backend in [StorageBackend::Tracked, StorageBackend::GitCommonDir] {
            let storage = StorageConfig {
                backend,
                ..StorageConfig::default()
            };
            let filesystem = agent_permission_filesystem(&storage).unwrap();
            for path in [".codex", ".agents", ".git"] {
                assert_eq!(filesystem.get(path).map(String::as_str), Some("read"));
            }
            if backend == StorageBackend::Tracked {
                for path in compiler_owned_state_catalog(&storage).paths() {
                    assert_eq!(
                        filesystem
                            .get(&normalized_project_path(path))
                            .map(String::as_str),
                        Some("read"),
                        "missing compiler-owned state rule for {}",
                        path.display()
                    );
                }
                let state_root = storage.state_path.parent().unwrap_or(Path::new("."));
                for path in [
                    state_root.join("recovery"),
                    state_root.join("derived-state.yaml"),
                ] {
                    assert_eq!(
                        filesystem
                            .get(&normalized_project_path(&path))
                            .map(String::as_str),
                        Some("read")
                    );
                }
            }
        }
    }

    #[test]
    fn broker_safe_errors_are_actionable_and_never_echo_internal_sentinels() {
        let cases = [
            (
                KoniError::Action("payload invalid at /secret/SENTINEL with token=abc".to_owned()),
                "revise_validation",
            ),
            (
                KoniError::Action(
                    "exact runtime MCP request is already in flight SENTINEL".to_owned(),
                ),
                "in_flight_exit",
            ),
            (
                KoniError::Action("grant expired SENTINEL".to_owned()),
                "stale_stop",
            ),
        ];
        for (error, code) in cases {
            let safe = agent_mcp_safe_error(&error);
            assert_eq!(safe.code, code);
            assert!(!safe.message.contains("SENTINEL"));
            assert!(!safe.message.contains("/secret"));
            assert!(!safe.message.contains("token="));
        }
    }

