    #[test]
    fn filesystem_vendor_paths_must_be_nonignored_nonempty_inventory_members() {
        let temp = tempfile::TempDir::new().unwrap();
        let root = temp.path().join("artifacts/component");
        fs::create_dir_all(root.join("__pycache__")).unwrap();
        fs::write(root.join("main.py"), b"ready\n").unwrap();
        fs::write(root.join("__pycache__/vendor.bin"), b"ignored\n").unwrap();
        fs::write(root.join("empty.bin"), b"").unwrap();
        fs::write(root.join("vendor.bin"), b"vendored\n").unwrap();
        let definition: FilesystemManifestDef = serde_json::from_value(json!({
            "root_field": "spec.plan.root",
            "implementation_contract_field": "spec.implementation",
            "implementation_kind_field": "spec.implementation.kind",
            "implementation_entrypoints_field": "spec.implementation.entrypoints",
            "output_field": "artifact_manifest",
            "allowed_root_prefixes": ["artifacts"],
            "scan": {"ignored_path_components": ["__pycache__"], "symlinks": "reject"},
            "source": {
                "field": "spec.source_strategy",
                "external_values": ["external"],
                "vendor": {"path_fields": ["spec.vendor.paths"]}
            }
        }))
        .unwrap();
        for (path, expected) in [
            ("artifacts/component/__pycache__/vendor.bin", "invalid_path"),
            ("artifacts/component/empty.bin", "missing"),
            ("artifacts/component/missing.bin", "missing"),
            ("artifacts/component/vendor.bin", "vendored"),
        ] {
            let mut node = filesystem_manifest_test_node(json!(["artifacts/component/main.py"]));
            node.spec["source_strategy"] = json!("external");
            node.spec["vendor"] = json!({"paths": [path]});
            let manifest = derive_filesystem_manifest(&node, &definition, temp.path(), true);
            assert_eq!(manifest["vendor_status"], expected, "vendor path {path}");
            assert_eq!(
                manifest["implementation_status"],
                if expected == "vendored" {
                    "ready"
                } else {
                    "incomplete"
                }
            );
        }
    }

