    fn compiler_state_boundary_excludes_project_and_profile_files() {
        let state_root = Path::new("program");
        assert!(path_is_compiler_state(
            Path::new("program/events.jsonl"),
            state_root
        ));
        assert!(path_is_compiler_state(
            Path::new("program/journals/action.yaml"),
            state_root
        ));
        assert!(!path_is_compiler_state(Path::new("README.md"), state_root));
        assert!(!path_is_compiler_state(
            Path::new(".codex/koni/profile.yaml"),
            state_root
        ));
    }

    #[test]
    fn command_result_policy_binds_identity_and_scientific_acceptance() {
        let check: crate::config::CheckDef = serde_json::from_value(json!({
            "id": "gate-verifier",
            "kind": "command",
            "argv": ["true"],
            "result_protocol": "autoresearch.gate-result.v1",
            "result_identity_field": "gate_id",
            "result_acceptance": {"field": "verdict", "values": ["passed"]},
            "allow_nonpassing_receipt": true,
            "receipt_type": "gate.receipt"
        }))
        .expect("minimal command check deserializes");

        let mut failed = json!({
            "status": "passed",
            "result": {"gate_id": "G-1", "verdict": "failed"},
            "receipt_hash": "stale"
        });
        apply_check_result_policy(&check, &mut failed, Some("G-1"));
        assert_eq!(failed["status"], "failed");
        assert_eq!(failed["result_validation"]["acceptance_actual"], "failed");
        assert_ne!(failed["receipt_hash"], "stale");

        let mut wrong_target = json!({
            "status": "passed",
            "result": {"gate_id": "G-2", "verdict": "passed"},
            "receipt_hash": "stale"
        });
        apply_check_result_policy(&check, &mut wrong_target, Some("G-1"));
        assert_eq!(wrong_target["status"], "invalid_result");

        let mut passed = json!({
            "status": "passed",
            "result": {"gate_id": "G-1", "verdict": "passed"},
            "receipt_hash": "stale"
        });
        apply_check_result_policy(&check, &mut passed, Some("G-1"));
        assert_eq!(passed["status"], "passed");
        assert_eq!(passed["result_validation"]["identity_actual"], "G-1");
    }

