    #[test]
    fn tracked_projection_overlays_newer_checkout_worker_runtime_only() {
        let profile_root = Path::new(env!("CARGO_MANIFEST_DIR")).join("../../profiles/research");
        let profile = ProfileCompiler::compile(&profile_root).unwrap();
        let temp = tempfile::TempDir::new().unwrap();
        let mut branch_ticket = worker_projection_ticket(false);
        let lease = branch_ticket.lease.as_mut().unwrap();
        lease.worktree = temp.path().to_path_buf();
        lease.worker_pid = None;
        branch_ticket.extensions.remove("active_worker");

        let mut runtime_ticket = branch_ticket.clone();
        let runtime_lease = runtime_ticket.lease.as_mut().unwrap();
        runtime_lease.heartbeat_at += Duration::seconds(1);
        runtime_lease.worker_pid = Some(std::process::id());
        runtime_ticket.extensions.insert(
            "active_worker".to_owned(),
            json!({"persona":"worker","pid":std::process::id(),"step":"produce"}),
        );
        // Runtime projection must not replace semantic fields from the validated branch.
        runtime_ticket.title = "untrusted checkout title".to_owned();
        let store = StateStore::with_storage(
            tracked_state_root(temp.path(), &profile),
            &profile.manifest.storage,
        )
        .unwrap();
        store.ensure_layout().unwrap();
        store.write_ticket(&runtime_ticket).unwrap();

        overlay_ticket_runtime_from_worktree(&profile, &mut branch_ticket).unwrap();

        assert_eq!(branch_ticket.title, "test ticket");
        assert_eq!(
            branch_ticket.lease.as_ref().unwrap().worker_pid,
            Some(std::process::id())
        );
        assert_eq!(branch_ticket.extensions["active_worker"]["step"], "produce");
    }

    #[test]
    fn ticket_projection_rejects_changed_compiler_or_lease_identity() {
        let canonical = worker_projection_ticket(false);

        let mut changed_id = canonical.clone();
        changed_id.id = "TK-redirected".to_owned();
        assert!(ensure_ticket_projection_identity(&canonical, &changed_id, "test").is_err());

        let mut changed_profile = canonical.clone();
        changed_profile.profile_hash = "sha256:other-profile".to_owned();
        assert!(ensure_ticket_projection_identity(&canonical, &changed_profile, "test").is_err());

        let mut changed_worktree = canonical.clone();
        changed_worktree.lease.as_mut().unwrap().worktree = "/tmp/redirected".into();
        assert!(ensure_ticket_projection_identity(&canonical, &changed_worktree, "test").is_err());

        let mut changed_priority = canonical.clone();
        changed_priority
            .extensions
            .insert("dispatch_priority".to_owned(), Value::from(i64::MAX));
        assert!(ensure_ticket_projection_identity(&canonical, &changed_priority, "test").is_err());

        let mut semantic_progress = canonical.clone();
        semantic_progress.status = "review".to_owned();
        semantic_progress.title = "updated presentation".to_owned();
        assert!(ensure_ticket_projection_identity(&canonical, &semantic_progress, "test").is_ok());
    }

