    #[test]
    fn later_lead_approval_invalidates_review_and_changes_exact_approval_hash() {
        let fixture = change_control_engine_fixture();
        let proposal_id = fixture
            .engine
            .publish_upstream_change_request(&fixture.source, &fixture.output)
            .unwrap();
        let proposal = reviewed_change_control_proposal(&fixture, &proposal_id, "no-op");
        let first = finalize_reviewed_change_control_proposal(&fixture, proposal);
        let first_hash = first["approval_hash"].as_str().unwrap().to_owned();

        let manifest = fixture.store.manifest().unwrap();
        let mut second_approval = Event::new(
            &manifest.id,
            "compiler.steering.recorded",
            Some(proposal_id.clone()),
            json!({"kind": "approval", "message": "Approve again under a fresh authority boundary."}),
        );
        second_approval.id = "EV-approve-no-op-second".to_owned();
        second_approval.actor = "lead-second".to_owned();
        fixture.store.append_event(&second_approval).unwrap();
        fixture
            .engine
            .reconcile_change_control(&fixture.store, &Graph::default(), &manifest)
            .unwrap();
        let mut proposal = fixture.store.ticket(&proposal_id).unwrap();
        assert!(proposal.reviews.is_empty());
        assert!(proposal.change_control.approved_change.is_none());
        assert!(proposal.change_control.disposition.is_none());
        let OperationChangeControlDef::Proposal {
            proposal_step,
            application_operations,
        } = fixture.engine.profile.operations["lifecycle.change-request"]
            .change_control
            .clone()
        else {
            panic!("research change-request operation must be proposal typed");
        };
        let failure = fixture
            .engine
            .finalize_change_control_proposal(
                &fixture.store,
                proposal.clone(),
                &proposal_step,
                &application_operations,
            )
            .unwrap_err()
            .to_string();
        assert!(failure.contains("requires a passed review"), "{failure}");

        let approval = proposal
            .change_control
            .proposal_approval
            .as_ref()
            .unwrap()
            .clone();
        let proposal_ticket_hash = normalized_hash(&proposal);
        let proposal_output_hash = normalized_hash(&proposal.outputs);
        proposal.reviews.push(Review {
            id: "REV-no-op-second".to_owned(),
            status: "passed".to_owned(),
            notes: "Reviewed after the replacement approval".to_owned(),
            reviewed_at: approval.approved_at + Duration::seconds(1),
            ticket_hash: proposal_ticket_hash,
            output_hash: proposal_output_hash,
            agent_binding: None,
        });
        fixture.store.write_ticket(&proposal).unwrap();
        let second = finalize_reviewed_change_control_proposal(&fixture, proposal);
        let second_hash = second["approval_hash"].as_str().unwrap();
        assert_ne!(first_hash, second_hash);
        let finalized = fixture.store.ticket(&proposal_id).unwrap();
        assert_eq!(
            finalized
                .change_control
                .approved_change
                .as_ref()
                .unwrap()
                .steering_approval
                .steering_event_id,
            "EV-approve-no-op-second"
        );
    }

    #[test]
    fn lead_rejection_is_terminal_and_requeues_the_same_source_fresh() {
        let fixture = change_control_engine_fixture();
        let proposal_id = fixture
            .engine
            .publish_upstream_change_request(&fixture.source, &fixture.output)
            .unwrap();
        let manifest = fixture.store.manifest().unwrap();
        let mut rejection = Event::new(
            &manifest.id,
            "compiler.steering.recorded",
            Some(proposal_id.clone()),
            json!({"kind": "rejection", "message": "The upstream correction is not warranted."}),
        );
        rejection.id = "EV-reject".to_owned();
        fixture.store.append_event(&rejection).unwrap();
        fixture
            .engine
            .reconcile_change_control(&fixture.store, &Graph::default(), &manifest)
            .unwrap();

        let proposal = fixture.store.ticket(&proposal_id).unwrap();
        assert_eq!(
            proposal.status,
            terminal_ticket_state(&fixture.engine.profile)
        );
        assert!(matches!(
            proposal.change_control.disposition,
            Some(ChangeControlDisposition::Rejected {
                steering_event_id: Some(ref id),
                ..
            }) if id == "EV-reject"
        ));
        let source = fixture.store.ticket(&fixture.source.id).unwrap();
        assert_eq!(source.id, fixture.source.id);
        assert_eq!(source.status, initial_ticket_state(&fixture.engine.profile));
        assert!(source.outputs.is_empty());
        assert!(source.reviews.is_empty());
        assert!(source.change_control.pending_request.is_none());
        assert!(source.change_control.blocker.is_none());
        assert!(matches!(
            source
                .change_control
                .resolved
                .last()
                .map(|row| &row.disposition),
            Some(ChangeControlDisposition::Rejected { .. })
        ));
    }

    #[test]
    fn released_source_history_retires_only_when_its_deriving_gap_disappears() {
        let fixture = change_control_engine_fixture();
        let proposal_id = fixture
            .engine
            .publish_upstream_change_request(&fixture.source, &fixture.output)
            .unwrap();
        let manifest = fixture.store.manifest().unwrap();
        fixture
            .store
            .append_event(&Event::new(
                &manifest.id,
                "compiler.steering.recorded",
                Some(proposal_id),
                json!({"kind": "rejection", "message": "Reject the bounded correction."}),
            ))
            .unwrap();
        fixture
            .engine
            .reconcile_change_control(&fixture.store, &Graph::default(), &manifest)
            .unwrap();
        let released = fixture.store.ticket(&fixture.source.id).unwrap();
        assert_eq!(released.change_control.resolved.len(), 1);

        fixture
            .engine
            .retire_invalidated_initial_tickets(
                &fixture.store,
                vec![released.clone()],
                &BTreeSet::new(),
                initial_ticket_state(&fixture.engine.profile),
            )
            .unwrap();
        let retired = fixture.store.ticket(&fixture.source.id).unwrap();
        assert_eq!(
            retired.status,
            terminal_ticket_state(&fixture.engine.profile)
        );
        assert_eq!(retired.change_control.resolved.len(), 1);

        fixture.store.write_ticket(&released).unwrap();
        fixture
            .engine
            .retire_invalidated_initial_tickets(
                &fixture.store,
                vec![released],
                &BTreeSet::from([fixture.source.id.clone()]),
                initial_ticket_state(&fixture.engine.profile),
            )
            .unwrap();
        let still_derived = fixture.store.ticket(&fixture.source.id).unwrap();
        assert_eq!(
            still_derived.status,
            initial_ticket_state(&fixture.engine.profile)
        );
        assert_eq!(still_derived.change_control.resolved.len(), 1);
    }

    #[test]
    fn tracked_source_worktree_output_is_canonically_held_then_archived_on_release() {
        let mut fixture = change_control_engine_fixture();
        fixture
            .engine
            .acquire_lease(&BTreeMap::from([(
                "ticket".to_owned(),
                json!(fixture.source.id),
            )]))
            .unwrap();
        let canonical_started = fixture.store.ticket(&fixture.source.id).unwrap();
        let lease = canonical_started.lease.clone().unwrap();
        assert!(lease.worktree.is_dir());
        let integration_git = GitBackend::discover(&fixture.engine.root).unwrap();
        integration_git
            .checkpoint(&CheckpointRequest {
                subject: "test: persist started source lease".to_owned(),
                body: None,
                trailers: Vec::new(),
                excluded_paths: Vec::new(),
                tree_excluded_paths: tracked_state_tree_exclusions(
                    &fixture.engine.profile,
                    &fixture.engine.root,
                )
                .unwrap(),
                identity: Some(CommitIdentity::default()),
            })
            .unwrap();

        let runtime_store = StateStore::with_storage(
            tracked_state_root(&lease.worktree, &fixture.engine.profile),
            &fixture.engine.profile.manifest.storage,
        )
        .unwrap();
        runtime_store.ensure_layout().unwrap();
        let mut runtime_source = runtime_store.ticket(&fixture.source.id).unwrap();
        runtime_source.status = "in_progress".to_owned();
        runtime_source.lease = Some(lease.clone());
        runtime_store.write_ticket(&runtime_source).unwrap();
        let runtime_engine = Engine {
            root: lease.worktree.clone(),
            profile: fixture.engine.profile.clone(),
            store: Some(runtime_store.clone()),
            run_git_templates: None,
            run_slug: None,
            resolved_run_type: None,
            compiler_action_context: BTreeMap::new(),
            ticket_review_authorization: None,
        };
        fs::write(
            lease.worktree.join("partial-change.txt"),
            "valuable partial product work\n",
        )
        .unwrap();
        let result = runtime_engine
            .write_ticket_metadata(&BTreeMap::from([
                ("_action".to_owned(), json!("output")),
                ("ticket".to_owned(), json!(runtime_source.id)),
                ("step".to_owned(), json!(fixture.output.step_id)),
                ("persona".to_owned(), json!(fixture.output.persona)),
                (
                    "payload".to_owned(),
                    json!({
                        "files_written": ["partial-change.txt"],
                        "upstream_change_request": {
                            "target_nodes": ["hypothesis-a"],
                            "summary": "Repair the upstream hypothesis",
                            "reason": "The running worker found a bounded contradiction"
                        }
                    }),
                ),
            ]))
            .unwrap();
        let proposal_id = result["change_request_ticket_id"]
            .as_str()
            .unwrap()
            .to_owned();
        let stale_runtime = runtime_store.ticket(&fixture.source.id).unwrap();
        let admission = runtime_engine
            .ensure_change_control_admission(&stale_runtime, "output")
            .unwrap_err()
            .to_string();
        assert!(admission.contains("held by upstream change request"));

        let manifest = fixture.store.manifest().unwrap();
        fixture
            .store
            .append_event(&Event::new(
                &manifest.id,
                "compiler.steering.recorded",
                Some(proposal_id),
                json!({"kind": "rejection", "message": "Reject the proposed correction."}),
            ))
            .unwrap();
        fixture
            .engine
            .reconcile_change_control(&fixture.store, &Graph::default(), &manifest)
            .unwrap();

        assert!(!lease.worktree.exists());
        let released = fixture.store.ticket(&fixture.source.id).unwrap();
        assert_eq!(
            released.status,
            initial_ticket_state(&fixture.engine.profile)
        );
        assert!(released.lease.is_none());
        let resolution = released.change_control.resolved.last().unwrap();
        assert_eq!(
            resolution
                .stale_lease
                .as_ref()
                .map(|stale| stale.id.as_str()),
            Some(lease.id.as_str())
        );
        let archive = resolution
            .authority_archive
            .as_ref()
            .expect("removed worktree keeps auditable recovery authority");
        let archive_commit = git2::Repository::discover(&fixture.engine.root)
            .unwrap()
            .find_reference(&archive.reference)
            .unwrap()
            .peel_to_commit()
            .unwrap()
            .id()
            .to_string();
        assert_eq!(archive_commit, archive.commit);
        let repository = git2::Repository::discover(&fixture.engine.root).unwrap();
        let archived_tree = repository
            .find_commit(Oid::from_str(&archive.commit).unwrap())
            .unwrap()
            .tree()
            .unwrap();
        let archived_blob = archived_tree
            .get_path(Path::new("partial-change.txt"))
            .unwrap()
            .to_object(&repository)
            .unwrap()
            .peel_to_blob()
            .unwrap();
        assert_eq!(archived_blob.content(), b"valuable partial product work\n");

        fixture
            .engine
            .reconcile_change_control(&fixture.store, &Graph::default(), &manifest)
            .unwrap();
        assert_eq!(
            fixture
                .store
                .ticket(&fixture.source.id)
                .unwrap()
                .change_control
                .resolved
                .len(),
            1,
            "replaying release must not duplicate the resolution/archive"
        );
        fixture
            .engine
            .acquire_lease(&BTreeMap::from([(
                "ticket".to_owned(),
                json!(fixture.source.id),
            )]))
            .unwrap();
        let restarted = fixture.store.ticket(&fixture.source.id).unwrap();
        let fresh_lease = restarted.lease.unwrap();
        assert_ne!(fresh_lease.id, lease.id);
        assert_eq!(fresh_lease.worktree, lease.worktree);
        assert!(fresh_lease.worktree.is_dir());
    }

