    #[test]
    fn deletion_results_own_change_control_archives_by_selected_mode() {
        let artifact = RunDeletionArtifact {
            kind: "ticket".to_owned(),
            worktree_name: "koni-run-ticket".to_owned(),
            path: PathBuf::from("/tmp/koni-run-ticket"),
            branch_ref: Some("refs/heads/koni/run/ticket".to_owned()),
            expected_detached_head: None,
        };
        let result = |mode| {
            deletion_result_from_journal(
                &RunDeletionJournal {
                    schema_version: "1.0".to_owned(),
                    run_id: "run-change-control".to_owned(),
                    mode,
                    prior_status: "concluded".to_owned(),
                    phase: "complete".to_owned(),
                    artifacts: vec![artifact.clone()],
                    archive_refs: vec![
                        "refs/tags/koni-change-control/run-change-control/TK-source/lease"
                            .to_owned(),
                    ],
                    updated_at: Utc.with_ymd_and_hms(2026, 7, 12, 13, 0, 0).unwrap(),
                },
                false,
            )
        };

        let preserved = result(RunDeletionMode::PreserveBranches);
        assert_eq!(
            preserved.preserved_archive_refs,
            vec!["refs/tags/koni-change-control/run-change-control/TK-source/lease"]
        );
        assert!(preserved.deleted_archive_refs.is_empty());
        assert_eq!(
            preserved.preserved_branches,
            vec!["refs/heads/koni/run/ticket"]
        );

        let deleted = result(RunDeletionMode::DeleteOwnedBranches);
        assert_eq!(
            deleted.deleted_archive_refs,
            vec!["refs/tags/koni-change-control/run-change-control/TK-source/lease"]
        );
        assert!(deleted.preserved_archive_refs.is_empty());
        assert_eq!(deleted.deleted_branches, vec!["refs/heads/koni/run/ticket"]);
    }

    #[test]
