    #[test]
    fn failed_review_supersedes_only_integration_output_for_rework() {
        let mut ticket = worker_projection_ticket(true);
        ticket.scope.read_nodes.insert("candidate-node".to_owned());
        ticket.scope.write_nodes.insert("candidate-node".to_owned());
        ticket.extensions.insert(
            "active_worker".to_owned(),
            json!({"persona": "integrator", "pid": 999999, "step": "integrate"}),
        );
        ticket.outputs.push(
            serde_json::from_value(json!({
                "id": "output-2",
                "step_id": "integrate",
                "persona": "integrator",
                "context_hash": "ctx-integrate",
                "recorded_at": "2026-07-10T12:02:00Z",
                "typed": {
                    "graph_delta": {
                        "add_nodes": [{"id": "candidate-node", "type": "claim"}]
                    }
                }
            }))
            .expect("integration output deserializes"),
        );

        assert!(supersede_integration_outputs_for_rework(&mut ticket));
        assert_eq!(
            ticket
                .outputs
                .iter()
                .map(|output| output.step_id.as_str())
                .collect::<Vec<_>>(),
            vec!["produce"]
        );
        assert_eq!(
            ticket
                .extensions
                .get("superseded_outputs")
                .and_then(Value::as_array)
                .map(Vec::len),
            Some(1)
        );
        assert_eq!(
            ticket.lease.as_ref().and_then(|lease| lease.worker_pid),
            None,
            "review rework must not masquerade as a crashed worker"
        );
        assert!(!ticket.extensions.contains_key("active_worker"));
        assert!(ticket.scope.read_nodes.contains("candidate-node"));
        assert!(
            ticket.scope.write_nodes.contains("candidate-node"),
            "a failed-review candidate remains writable by its reopened owner"
        );
    }

    #[test]
    fn failed_review_reopens_configured_owner_and_transitive_dependents() {
        let mut ticket = worker_projection_ticket(true);
        ticket.workflow.insert(
            0,
            serde_json::from_value(json!({
                "id": "inspect",
                "persona": "inspector",
                "context_hash": "ctx-inspect"
            }))
            .expect("inspection step deserializes"),
        );
        ticket.workflow[1].depends_on = vec!["inspect".to_owned()];
        ticket.workflow.push(
            serde_json::from_value(json!({
                "id": "review",
                "persona": "reviewer",
                "depends_on": ["integrate"],
                "kind": "review",
                "context_hash": "ctx-review"
            }))
            .expect("review step deserializes"),
        );
        ticket.outputs.insert(
            0,
            serde_json::from_value(json!({
                "id": "output-0",
                "step_id": "inspect",
                "persona": "inspector",
                "context_hash": "ctx-inspect",
                "recorded_at": "2026-07-10T12:00:00Z"
            }))
            .expect("inspection output deserializes"),
        );
        ticket.outputs.push(
            serde_json::from_value(json!({
                "id": "output-2",
                "step_id": "integrate",
                "persona": "integrator",
                "context_hash": "ctx-integrate",
                "recorded_at": "2026-07-10T12:02:00Z"
            }))
            .expect("integration output deserializes"),
        );
        ticket.outputs.push(
            serde_json::from_value(json!({
                "id": "output-3",
                "step_id": "review",
                "persona": "reviewer",
                "context_hash": "ctx-review",
                "recorded_at": "2026-07-10T12:03:00Z"
            }))
            .expect("review output deserializes"),
        );
        ticket.extensions.insert(
            "review_failure_reopen_from".to_owned(),
            Value::String("produce".to_owned()),
        );
        ticket.extensions.insert(
            "active_worker".to_owned(),
            json!({"persona": "integrator", "pid": 999999, "step": "integrate"}),
        );

        assert!(supersede_integration_outputs_for_rework(&mut ticket));
        assert_eq!(
            ticket
                .outputs
                .iter()
                .map(|output| output.step_id.as_str())
                .collect::<Vec<_>>(),
            vec!["inspect"]
        );
        assert_eq!(
            ticket
                .extensions
                .get("superseded_outputs")
                .and_then(Value::as_array)
                .map(Vec::len),
            Some(3)
        );
        assert_eq!(
            ticket.lease.as_ref().and_then(|lease| lease.worker_pid),
            None
        );
        assert!(!ticket.extensions.contains_key("active_worker"));
    }

    #[test]
    fn receipt_labels_do_not_imply_that_a_runtime_command_ran() {
        let mut ticket = worker_projection_ticket(true);
        let output = ticket.outputs.first_mut().expect("test output exists");
        output.receipts.push("context-pack: sha256:test".to_owned());
        assert!(!output_command_ran(output));

        output
            .typed
            .insert("command_ran".to_owned(), Value::Bool(true));
        assert!(output_command_ran(output));
    }

