    fn synthetic_agent_broker_record(
        grant: &AgentBrokerGrant,
        working_directory: &Path,
        parent: &AgentProcessIdentity,
    ) -> AgentSessionRecord {
        let AgentBrokerRole::Worker {
            ticket,
            step,
            persona,
        } = &grant.role
        else {
            panic!("synthetic record requires a worker grant");
        };
        let now = Utc::now();
        AgentSessionRecord {
            schema_version: "1.0".to_owned(),
            id: grant.agent_id.clone(),
            run_id: grant.run_id.clone(),
            ticket_id: Some(ticket.clone()),
            stage_id: Some(step.clone()),
            persona: persona.clone(),
            model: None,
            reasoning_effort: None,
            status: "running".to_owned(),
            attempt: grant.attempt,
            codex_session_id: Some("session-test".to_owned()),
            pid: Some(parent.pid),
            process_identity: Some(parent.clone()),
            working_directory: Some(working_directory.to_path_buf()),
            prompt_path: None,
            stdout_path: None,
            stderr_path: None,
            output_path: None,
            output_hash: None,
            input_hash: Some(grant.input_hash.clone()),
            result: None,
            exit_code: None,
            timed_out: false,
            started_at: Some(now),
            finished_at: None,
            updated_at: now,
        }
    }

    fn synthetic_agent_broker_receipt(
        sequence: u64,
        tool: &str,
        request_hash: &str,
    ) -> AgentBrokerToolReceipt {
        let mut receipt = AgentBrokerToolReceipt {
            sequence,
            tool: tool.to_owned(),
            request_hash: request_hash.to_owned(),
            response_hash: format!("sha256:response-{sequence}"),
            response_bytes: 2,
            status: "succeeded".to_owned(),
            recorded_at: Utc::now(),
            receipt_hash: String::new(),
        };
        receipt.receipt_hash = normalized_hash(&receipt);
        receipt
    }

    fn synthetic_agent_broker_product(label: &str) -> AgentBrokerProductBinding {
        AgentBrokerProductBinding {
            head_tree: Some(format!("tree-{label}")),
            workspace_hash: format!("sha256:workspace-{label}"),
            ticket_status: "in_progress".to_owned(),
            ticket_outputs_hash: format!("sha256:outputs-{label}"),
            graph_hash: format!("sha256:graph-{label}"),
        }
    }

    #[test]
    fn broker_claim_scope_rejects_wrong_agent_attempt_checkout_and_repository() {
        let temp = tempfile::TempDir::new().unwrap();
        let root = temp.path().canonicalize().unwrap();
        let work = root.join("work");
        let other_work = root.join("other-work");
        let common = root.join("common");
        let other_common = root.join("other-common");
        for directory in [&work, &other_work, &common, &other_common] {
            fs::create_dir(directory).unwrap();
        }
        let mut grant = synthetic_agent_broker_grant();
        grant.working_directory = work.clone();

        let validates = |agent: &str, attempt, cwd: &Path, repository_common: &Path| {
            validate_agent_broker_claim_scope(
                &grant,
                agent,
                attempt,
                cwd,
                repository_common,
                &common,
            )
        };
        assert!(validates(&grant.agent_id, grant.attempt, &work, &common).is_ok());
        assert!(validates("sibling-agent", grant.attempt, &work, &common).is_err());
        assert!(validates(&grant.agent_id, grant.attempt + 1, &work, &common).is_err());
        assert!(validates(&grant.agent_id, grant.attempt, &other_work, &common).is_err());
        assert!(validates(&grant.agent_id, grant.attempt, &work, &other_common).is_err());
    }

    #[test]
    fn broker_direct_parent_binding_rejects_sibling_descendant_and_recycled_processes() {
        let mut grant = synthetic_agent_broker_grant();
        let expected = AgentProcessIdentity {
            pid: 41,
            process_group_id: 41,
            birth_marker: "expected-birth".to_owned(),
        };
        grant.expected_codex_parent = Some(expected.clone());
        assert!(validate_agent_broker_direct_parent(&grant, &expected).is_ok());

        let sibling = AgentProcessIdentity {
            pid: 42,
            process_group_id: 42,
            birth_marker: "sibling-birth".to_owned(),
        };
        assert!(validate_agent_broker_direct_parent(&grant, &sibling).is_err());
        let descendant_observed_parent = AgentProcessIdentity {
            pid: 43,
            process_group_id: 41,
            birth_marker: "intermediary-birth".to_owned(),
        };
        assert!(validate_agent_broker_direct_parent(&grant, &descendant_observed_parent).is_err());
        let recycled = AgentProcessIdentity {
            birth_marker: "recycled-birth".to_owned(),
            ..expected
        };
        assert!(validate_agent_broker_direct_parent(&grant, &recycled).is_err());
    }

    #[test]
    fn broker_executable_binding_rejects_wrong_image_and_sha() {
        let temp = tempfile::TempDir::new().unwrap();
        let root = temp.path().canonicalize().unwrap();
        let expected = root.join("expected");
        let sibling = root.join("sibling");
        fs::write(&expected, b"expected-image").unwrap();
        fs::write(&sibling, b"expected-image").unwrap();
        let expected = expected.canonicalize().unwrap();
        let sibling = sibling.canonicalize().unwrap();
        let sha = raw_sha256(b"expected-image");
        let binding = ExecutableBinding {
            requested: "expected".to_owned(),
            path_kind: "external_absolute".to_owned(),
            resolved_path: expected.to_string_lossy().into_owned(),
            size_bytes: 14,
            sha256: sha.clone(),
            mode: None,
            device: None,
            inode: None,
            modified_ns: None,
        };
        assert!(
            validate_observed_executable_binding(&binding, &expected, &sha, "test image").is_ok()
        );
        assert!(
            validate_observed_executable_binding(&binding, &sibling, &sha, "test image").is_err()
        );
        assert!(
            validate_observed_executable_binding(
                &binding,
                &expected,
                "sha256:wrong",
                "test image",
            )
            .is_err()
        );
    }

    #[test]
    fn broker_current_record_and_worker_lease_bind_every_scope_dimension() {
        let temp = tempfile::TempDir::new().unwrap();
        let root = temp.path().canonicalize().unwrap();
        let work = root.join("work");
        let other_work = root.join("other-work");
        fs::create_dir(&work).unwrap();
        fs::create_dir(&other_work).unwrap();
        let mut grant = synthetic_agent_broker_grant();
        grant.working_directory = work.clone();
        let parent = AgentProcessIdentity {
            pid: 41,
            process_group_id: 41,
            birth_marker: "parent-birth".to_owned(),
        };
        grant.expected_codex_parent = Some(parent.clone());
        let record = synthetic_agent_broker_record(&grant, &work, &parent);
        assert!(validate_agent_broker_record_binding(&grant, &record, &work).is_ok());

        let mut variants = Vec::new();
        let mut changed = record.clone();
        changed.run_id = "other-run".to_owned();
        variants.push(changed);
        let mut changed = record.clone();
        changed.id = "other-agent".to_owned();
        variants.push(changed);
        let mut changed = record.clone();
        changed.attempt += 1;
        variants.push(changed);
        let mut changed = record.clone();
        changed.input_hash = Some("sha256:other-input".to_owned());
        variants.push(changed);
        let mut changed = record.clone();
        changed.status = "paused".to_owned();
        variants.push(changed);
        let mut changed = record.clone();
        changed.working_directory = Some(other_work.clone());
        variants.push(changed);
        let mut changed = record.clone();
        changed.process_identity.as_mut().unwrap().birth_marker = "recycled-parent".to_owned();
        variants.push(changed);
        let mut changed = record.clone();
        changed.ticket_id = Some("TK-other".to_owned());
        variants.push(changed);
        let mut changed = record.clone();
        changed.stage_id = Some("review".to_owned());
        variants.push(changed);
        let mut changed = record.clone();
        changed.persona = "reviewer".to_owned();
        variants.push(changed);
        for changed in variants {
            assert!(validate_agent_broker_record_binding(&grant, &changed, &work).is_err());
        }

        let now = Utc::now();
        let lease = Lease {
            id: "lease-test".to_owned(),
            branch: "broker/test".to_owned(),
            worktree: work.clone(),
            base_commit: "deadbeef".to_owned(),
            started_at: now,
            heartbeat_at: now,
            worker_pid: record.pid,
        };
        let active_value = json!({
            "agent_id": grant.agent_id,
            "attempt": grant.attempt,
            "input_hash": grant.input_hash,
            "step": "implement",
            "persona": "implementer",
            "process_identity": parent,
        });
        let active = active_value.as_object().unwrap();
        assert!(
            validate_agent_broker_worker_lease_binding(&grant, &record, &lease, active, &work)
                .is_ok()
        );
        let mut wrong_lease = lease.clone();
        wrong_lease.worktree = other_work;
        assert!(
            validate_agent_broker_worker_lease_binding(
                &grant,
                &record,
                &wrong_lease,
                active,
                &work,
            )
            .is_err()
        );
        let mut wrong_lease = lease.clone();
        wrong_lease.worker_pid = Some(42);
        assert!(
            validate_agent_broker_worker_lease_binding(
                &grant,
                &record,
                &wrong_lease,
                active,
                &work,
            )
            .is_err()
        );
        for (key, value) in [
            ("agent_id", json!("other-agent")),
            ("attempt", json!(grant.attempt + 1)),
            ("input_hash", json!("sha256:other-input")),
            ("step", json!("review")),
            ("persona", json!("reviewer")),
            (
                "process_identity",
                json!({"pid": 41, "process_group_id": 41, "birth_marker": "other"}),
            ),
        ] {
            let mut changed = active.clone();
            changed.insert(key.to_owned(), value);
            assert!(
                validate_agent_broker_worker_lease_binding(
                    &grant, &record, &lease, &changed, &work,
                )
                .is_err()
            );
        }
    }

    #[test]
    fn composed_worker_grant_is_claimed_executes_once_replays_and_detects_terminal_drift() {
        let project = tempfile::TempDir::new().unwrap();
        let root = project.path().canonicalize().unwrap();
        let profile_source =
            PathBuf::from(env!("CARGO_MANIFEST_DIR")).join("../../profiles/research");
        let engine = Engine::open_with_profile(&root, Some(&profile_source)).unwrap();
        let profile = engine.profile().clone();
        fs::write(root.join("product.txt"), b"before").unwrap();
        ensure_repository_with_head(&root).unwrap();
        let git = GitBackend::discover(&root).unwrap();
        let base = git.head_oid().unwrap().to_string();
        let run_id = "run-composed-broker";
        let registry = ProjectRegistryStore::new(git.sidecar_root(), root.clone()).unwrap();
        let run_root = registry.run_root(run_id).unwrap();
        fs::create_dir_all(&run_root).unwrap();
        let snapshot = ConfigSnapshot::capture_project_configuration(&root, &run_root).unwrap();

        let store = StateStore::with_storage(
            tracked_state_root(&root, &profile),
            &profile.manifest.storage,
        )
        .unwrap();
        store.ensure_layout().unwrap();
        let mut manifest = RunManifest::new(
            profile.manifest.profile.id.clone(),
            profile.manifest.profile.version.clone(),
            profile.hash.clone(),
            "composed broker boundary",
            root.clone(),
        );
        manifest.id = run_id.to_owned();
        manifest.integration_branch = Some(git.branch_ref().unwrap());
        manifest.integration_worktree = Some(root.clone());
        manifest.pin_inputs(base.clone(), &snapshot);
        store.write_manifest(&manifest).unwrap();
        let now = Utc::now();
        registry
            .register_run(RunRegistration {
                id: run_id.to_owned(),
                slug: "composed-broker".to_owned(),
                goal: manifest.goal.clone(),
                profile_id: manifest.profile_id.clone(),
                profile_version: manifest.profile_version.clone(),
                profile_hash: profile.hash.clone(),
                run_type_id: None,
                run_type_title: None,
                run_type_hash: None,
                question_policy: None,
                base_commit: base,
                config_snapshot_hash: snapshot.hash.clone(),
                config_snapshot_path: snapshot.path.clone(),
                status: RunRegistrationStatus::Active,
                planning_worktree: None,
                planning_read_only: false,
                integration_branch: manifest.integration_branch.clone(),
                integration_worktree: Some(root.clone()),
                created_at: now,
                updated_at: now,
            })
            .unwrap();

        let mut owned_parent = Command::new("/bin/sleep");
        owned_parent
            .arg("60")
            .stdin(Stdio::null())
            .stdout(Stdio::null())
            .stderr(Stdio::null());
        #[cfg(unix)]
        owned_parent.process_group(0);
        let mut owned_parent = owned_parent.spawn().unwrap();
        let parent_identity = (0..100)
            .find_map(|_| {
                let identity = capture_owned_agent_process_identity(owned_parent.id());
                if identity.is_none() {
                    thread::sleep(std::time::Duration::from_millis(5));
                }
                identity
            })
            .expect("owned test process becomes observable");

        let agent_id = "worker-composed";
        let attempt = 1;
        let input_hash = "sha256:composed-input";
        let executable =
            bind_external_executable(&std::env::current_exe().unwrap(), "test").unwrap();
        let grant = issue_agent_broker_grant(
            &root,
            &root,
            run_id,
            &profile.hash,
            agent_id,
            attempt,
            input_hash,
            AgentBrokerRole::Worker {
                ticket: "TK-test".to_owned(),
                step: "produce".to_owned(),
                persona: "worker".to_owned(),
            },
            executable.clone(),
            executable,
        )
        .unwrap();
        bind_agent_broker_grant_parent(&root, &grant.id, &parent_identity).unwrap();

        let mut ticket = worker_projection_ticket(false);
        ticket.profile_hash = profile.hash.clone();
        ticket.lease = Some(Lease {
            id: "lease-composed".to_owned(),
            branch: git
                .branch_ref()
                .unwrap()
                .trim_start_matches("refs/heads/")
                .to_owned(),
            worktree: root.clone(),
            base_commit: git.head_oid().unwrap().to_string(),
            started_at: now,
            heartbeat_at: now,
            worker_pid: Some(parent_identity.pid),
        });
        ticket.extensions.insert(
            "active_worker".to_owned(),
            json!({
                "agent_id": agent_id,
                "attempt": attempt,
                "input_hash": input_hash,
                "step": "produce",
                "persona": "worker",
                "process_identity": parent_identity,
            }),
        );
        store.write_ticket(&ticket).unwrap();
        git.checkpoint(&CheckpointRequest {
            subject: "test: seed composed broker ticket".to_owned(),
            body: None,
            trailers: Vec::new(),
            excluded_paths: Vec::new(),
            tree_excluded_paths: Vec::new(),
            identity: None,
        })
        .unwrap();
        let record = synthetic_agent_broker_record(&grant, &root, &parent_identity);
        RunControlStore::new(run_root).write_agent(&record).unwrap();

        let broker_identity = capture_process_birth_identity(std::process::id()).unwrap();
        let mut ingress = claim_agent_mcp_grant_with_runtime(
            &root,
            &grant.id,
            agent_id,
            attempt,
            &root,
            broker_identity,
            parent_identity.clone(),
            |_, _| Ok(()),
        )
        .unwrap();
        let effects = std::cell::Cell::new(0_u32);
        let mut call = |tool: &str, arguments: Value, response: Value| {
            execute_agent_mcp_tool_with(
                &mut ingress,
                tool,
                arguments,
                |ingress, tool| {
                    revalidate_agent_broker_ingress_with_runtime(ingress, tool, |grant| {
                        assert!(
                            grant
                                .expected_codex_parent
                                .as_ref()
                                .is_some_and(owned_agent_process_is_alive)
                        );
                        Ok(())
                    })
                },
                |_, _, _| {
                    effects.set(effects.get() + 1);
                    Ok(response)
                },
            )
        };

        let context = json!({"document": {"ticket": "TK-test"}});
        assert_eq!(
            call("context", json!({}), context.clone()).unwrap(),
            context
        );
        assert_eq!(
            call("context", json!({}), json!({"unexpected": true})).unwrap(),
            context
        );
        assert_eq!(
            effects.get(),
            1,
            "exact context replay must not repeat its effect"
        );

        let payload = json!({"payload": {"findings": ["bounded"]}});
        assert_eq!(
            call("submit_output", payload.clone(), json!({"accepted": true})).unwrap(),
            json!({"accepted": true})
        );
        assert_eq!(
            call("submit_output", payload, json!({"unexpected": true})).unwrap(),
            json!({"accepted": true})
        );
        assert_eq!(
            effects.get(),
            2,
            "exact submit replay must not repeat its effect"
        );

        let compile = json!({"summary": "done"});
        assert_eq!(
            call("compile", compile.clone(), json!({"compiled": true})).unwrap(),
            json!({"compiled": true})
        );
        assert_eq!(
            call("compile", compile.clone(), json!({"unexpected": true})).unwrap(),
            json!({"compiled": true})
        );
        assert_eq!(
            effects.get(),
            3,
            "exact compile replay must not repeat its effect"
        );

        fs::write(root.join("product.txt"), b"after").unwrap();
        assert!(call("compile", compile, json!({"unexpected": true})).is_err());
        assert!(validate_agent_broker_terminal_product(&root, &grant.id).is_err());
        assert_eq!(
            effects.get(),
            3,
            "post-compile drift must fail before any effect"
        );

        owned_parent.kill().unwrap();
        owned_parent.wait().unwrap();
    }

    #[test]
    fn broker_receipt_matrix_covers_context_submit_compile_wait_and_lead_replay() {
        let product = synthetic_agent_broker_product("exact");
        let current = || Ok(product.clone());

        let mut worker = synthetic_agent_broker_grant();
        let context = synthetic_agent_broker_receipt(1, "context", "context-exact");
        worker.tool_receipts.insert(
            agent_broker_receipt_key("context", "context-exact"),
            context.clone(),
        );
        assert_eq!(
            validate_agent_broker_one_way_cas_with_product(
                &worker,
                "context",
                "context-exact",
                &current,
            )
            .unwrap(),
            Some(context)
        );
        assert!(
            validate_agent_broker_one_way_cas_with_product(
                &worker,
                "context",
                "context-changed",
                &current,
            )
            .unwrap()
            .is_none(),
            "read-only context calls remain repeatable"
        );

        let submit = synthetic_agent_broker_receipt(2, "submit_output", "submit-exact");
        worker.tool_receipts.insert(
            agent_broker_receipt_key("submit_output", "submit-exact"),
            submit.clone(),
        );
        worker.accepted_output_hash = Some("submit-exact".to_owned());
        worker.accepted_product_binding = Some(product.clone());
        assert_eq!(
            validate_agent_broker_one_way_cas_with_product(
                &worker,
                "submit_output",
                "submit-exact",
                &current,
            )
            .unwrap(),
            Some(submit)
        );
        assert!(
            validate_agent_broker_one_way_cas_with_product(
                &worker,
                "submit_output",
                "submit-revision",
                &current,
            )
            .unwrap()
            .is_none(),
            "a changed submission is a permitted revision until compile closes it"
        );

        let compile = synthetic_agent_broker_receipt(3, "compile", "compile-exact");
        worker.tool_receipts.insert(
            agent_broker_receipt_key("compile", "compile-exact"),
            compile.clone(),
        );
        worker.compiled_output_hash = worker.accepted_output_hash.clone();
        worker.compiled_product_binding = Some(product.clone());
        assert_eq!(
            validate_agent_broker_one_way_cas_with_product(
                &worker,
                "compile",
                "compile-exact",
                &current,
            )
            .unwrap(),
            Some(compile)
        );
        assert!(
            validate_agent_broker_one_way_cas_with_product(
                &worker,
                "compile",
                "compile-changed",
                &current,
            )
            .is_err(),
            "a successful compile is replayable only with its exact request"
        );

        let mut lead = synthetic_agent_broker_grant();
        let wait_boundary = LeadSliceBoundary::WaitWorkers {
            tickets: vec!["TK-test".to_owned()],
        };
        lead.role = AgentBrokerRole::Lead {
            generation: 1,
            boundary: wait_boundary.clone(),
        };
        lead.enabled_tools = agent_mcp_enabled_tools(Some(&wait_boundary));
        lead.enabled_tools_hash = normalized_hash(&lead.enabled_tools);
        let wait = synthetic_agent_broker_receipt(1, "wait_worker", "wait-exact");
        lead.tool_receipts.insert(
            agent_broker_receipt_key("wait_worker", "wait-exact"),
            wait.clone(),
        );
        assert_eq!(
            validate_agent_broker_one_way_cas_with_product(
                &lead,
                "wait_worker",
                "wait-exact",
                &current,
            )
            .unwrap(),
            Some(wait)
        );

        let dispatch_boundary = LeadSliceBoundary::DispatchBatch {
            tickets: vec!["TK-test".to_owned()],
        };
        lead.role = AgentBrokerRole::Lead {
            generation: 2,
            boundary: dispatch_boundary.clone(),
        };
        lead.enabled_tools = agent_mcp_enabled_tools(Some(&dispatch_boundary));
        lead.enabled_tools_hash = normalized_hash(&lead.enabled_tools);
        lead.tool_receipts.clear();
        let start = synthetic_agent_broker_receipt(1, "start", "start-exact");
        lead.tool_receipts.insert(
            agent_broker_receipt_key("start", "start-exact"),
            start.clone(),
        );
        assert_eq!(
            validate_agent_broker_one_way_cas_with_product(
                &lead,
                "start",
                "start-exact",
                &current,
            )
            .unwrap(),
            Some(start)
        );
    }

    #[test]
    fn broker_grant_rejects_corrupt_oversized_and_invalid_in_flight_receipts() {
        let mut valid = synthetic_agent_broker_grant();
        rehash_agent_broker_grant(&mut valid);
        validate_agent_broker_grant(&valid).unwrap();

        let mut corrupt = valid.clone();
        let mut corrupt_receipt = synthetic_agent_broker_receipt(1, "context", "request");
        corrupt_receipt.receipt_hash = "sha256:forged".to_owned();
        corrupt.tool_receipts.insert(
            agent_broker_receipt_key("context", "request"),
            corrupt_receipt,
        );
        rehash_agent_broker_grant(&mut corrupt);
        assert!(validate_agent_broker_grant(&corrupt).is_err());

        let mut oversized = valid.clone();
        let mut oversized_receipt = synthetic_agent_broker_receipt(1, "context", "oversized");
        oversized_receipt.response_bytes = MAX_AGENT_BROKER_TOOL_RESPONSE_BYTES as u64 + 1;
        oversized_receipt.receipt_hash.clear();
        oversized_receipt.receipt_hash = normalized_hash(&oversized_receipt);
        oversized.tool_receipts.insert(
            agent_broker_receipt_key("context", "oversized"),
            oversized_receipt,
        );
        rehash_agent_broker_grant(&mut oversized);
        assert!(validate_agent_broker_grant(&oversized).is_err());

        let mut invalid_in_flight = valid.clone();
        invalid_in_flight.in_flight = Some(AgentBrokerInFlight {
            sequence: invalid_in_flight.sequence + 2,
            tool: "context".to_owned(),
            operation_key: "context".to_owned(),
            request_hash: "sha256:request".to_owned(),
            started_at: Utc::now(),
        });
        rehash_agent_broker_grant(&mut invalid_in_flight);
        assert!(validate_agent_broker_grant(&invalid_in_flight).is_err());

        let mut duplicate_tools = valid.clone();
        duplicate_tools.enabled_tools.push("context".to_owned());
        duplicate_tools.enabled_tools_hash = normalized_hash(&duplicate_tools.enabled_tools);
        rehash_agent_broker_grant(&mut duplicate_tools);
        assert!(validate_agent_broker_grant(&duplicate_tools).is_err());

        let mut excessive = valid;
        for sequence in 1..=(MAX_AGENT_BROKER_TOOL_RECEIPTS as u64 + 1) {
            let request = format!("request-{sequence}");
            excessive.tool_receipts.insert(
                agent_broker_receipt_key("context", &request),
                synthetic_agent_broker_receipt(sequence, "context", &request),
            );
        }
        rehash_agent_broker_grant(&mut excessive);
        assert!(validate_agent_broker_grant(&excessive).is_err());
    }

    #[test]
    fn broker_grant_claim_is_single_process_birth_bound_and_idempotent_only_for_itself() {
        let mut grant = synthetic_agent_broker_grant();
        let owner = ProcessBirthIdentity {
            pid: 41,
            birth_marker: "owner-birth".to_owned(),
        };
        assert!(claim_agent_broker_state(&mut grant, &owner).unwrap());
        assert_eq!(grant.state, AgentBrokerGrantState::Claimed);
        assert!(!claim_agent_broker_state(&mut grant, &owner).unwrap());

        let sibling = ProcessBirthIdentity {
            pid: 42,
            birth_marker: "sibling-birth".to_owned(),
        };
        assert!(claim_agent_broker_state(&mut grant, &sibling).is_err());
        let recycled = ProcessBirthIdentity {
            pid: owner.pid,
            birth_marker: "recycled-birth".to_owned(),
        };
        assert!(claim_agent_broker_state(&mut grant, &recycled).is_err());
        assert_eq!(grant.claimed_broker.as_ref(), Some(&owner));
    }

    #[test]
    fn broker_revocation_marks_in_flight_pending_and_never_waits_on_operation_lock() {
        let mut grant = synthetic_agent_broker_grant();
        grant.state = AgentBrokerGrantState::Claimed;
        grant.in_flight = Some(AgentBrokerInFlight {
            sequence: 1,
            tool: "submit_output".to_owned(),
            operation_key: "submit_output".to_owned(),
            request_hash: "sha256:request".to_owned(),
            started_at: Utc::now(),
        });
        assert!(request_agent_broker_revocation(&mut grant));
        assert_eq!(grant.state, AgentBrokerGrantState::Claimed);
        assert!(grant.revoke_pending);
        assert!(grant.in_flight.is_some());

        let common = tempfile::TempDir::new().unwrap();
        let common = common.path().canonicalize().unwrap();
        let operation = acquire_agent_broker_operation_lock(&common, "grant-test").unwrap();
        let (sender, receiver) = std::sync::mpsc::channel();
        let thread_common = common.clone();
        let waiter = thread::spawn(move || {
            let lock = acquire_agent_broker_grant_lock(&thread_common, "grant-test").unwrap();
            sender.send(()).unwrap();
            drop(lock);
        });
        receiver
            .recv_timeout(std::time::Duration::from_secs(1))
            .expect("revocation grant phase must not wait for a long operation lock");
        drop(operation);
        waiter.join().unwrap();

        assert!(
            !clear_agent_broker_tool_reservation_state(
                &mut grant,
                "submit_output",
                "sha256:different-request",
            ),
            "a different failed action cannot clear the reserved operation"
        );
        assert!(clear_agent_broker_tool_reservation_state(
            &mut grant,
            "submit_output",
            "sha256:request",
        ));
        assert_eq!(grant.state, AgentBrokerGrantState::Revoked);
        assert!(!grant.revoke_pending);
        assert!(grant.in_flight.is_none());

        let mut revoked_before_reserve = synthetic_agent_broker_grant();
        revoked_before_reserve.state = AgentBrokerGrantState::Claimed;
        assert!(request_agent_broker_revocation(&mut revoked_before_reserve));
        assert_eq!(revoked_before_reserve.state, AgentBrokerGrantState::Revoked);
        assert!(
            claim_agent_broker_state(
                &mut revoked_before_reserve,
                &ProcessBirthIdentity {
                    pid: 43,
                    birth_marker: "late-claim".to_owned(),
                },
            )
            .is_err(),
            "pause/delete that wins first closes later claims"
        );

        let mut completed_before_delete = synthetic_agent_broker_grant();
        completed_before_delete.state = AgentBrokerGrantState::Consumed;
        assert!(!request_agent_broker_revocation(
            &mut completed_before_delete
        ));
        assert_eq!(
            completed_before_delete.state,
            AgentBrokerGrantState::Consumed
        );
    }

    #[test]
    fn lead_slice_bearer_rejects_stale_forged_and_unowned_ingress() {
        let state = bounded_test_lead_slice(LeadSliceBoundary::Recover);
        let exact = LeadIngressCapability::LegacyToken {
            token: "secret".to_owned(),
            generation: 1,
        };
        let forged = LeadIngressCapability::LegacyToken {
            token: "forged".to_owned(),
            generation: 1,
        };
        let stale = LeadIngressCapability::LegacyToken {
            token: "secret".to_owned(),
            generation: 2,
        };
        assert!(validate_lead_slice_ingress(&state, &exact, true).is_ok());
        assert!(validate_lead_slice_ingress(&state, &forged, true).is_err());
        assert!(validate_lead_slice_ingress(&state, &stale, true).is_err());
        assert!(validate_lead_slice_ingress(&state, &exact, false).is_err());

        let broker = LeadIngressCapability::BrokerGrant {
            grant_id: "grant-test".to_owned(),
            agent_id: "worker-first".to_owned(),
            generation: 1,
        };
        assert!(validate_lead_slice_ingress(&state, &broker, true).is_ok());

        let mut yielded = state;
        yielded.status = LeadSliceStatus::Yielded;
        assert!(validate_lead_slice_ingress(&yielded, &exact, true).is_err());
    }

    #[test]
    fn dispatch_slice_enforces_one_complete_capacity_sized_boundary() {
        let mut state = bounded_test_lead_slice(LeadSliceBoundary::DispatchBatch {
            tickets: vec!["TK-a".to_owned(), "TK-b".to_owned()],
        });
        assert!(authorize_lead_slice_operation(&mut state, "start", Some("TK-b")).is_err());
        assert!(authorize_lead_slice_operation(&mut state, "spawn-worker", Some("TK-a")).is_err());
        authorize_lead_slice_operation(&mut state, "start", Some("TK-a")).unwrap();
        assert!(authorize_lead_slice_operation(&mut state, "start", Some("TK-b")).is_err());
        authorize_lead_slice_operation(&mut state, "spawn-worker", Some("TK-a")).unwrap();
        assert_eq!(state.boundaries_completed, 0);
        authorize_lead_slice_operation(&mut state, "start", Some("TK-b")).unwrap();
        authorize_lead_slice_operation(&mut state, "spawn-worker", Some("TK-b")).unwrap();
        assert_eq!(state.boundaries_completed, 1);
        assert!(authorize_lead_slice_operation(&mut state, "recover", None).is_err());
        assert!(authorize_lead_slice_operation(&mut state, "spawn-worker", Some("TK-c")).is_err());
    }

    #[test]
    fn broker_lead_commit_sequence_uses_exact_dispatch_and_yield_authority() {
        let mut state = bounded_test_lead_slice(LeadSliceBoundary::DispatchBatch {
            tickets: vec!["TK-a".to_owned(), "TK-b".to_owned()],
        });
        assert!(
            validate_lead_yield_reason(&state, "boundary-complete", true, false).is_err(),
            "a Lead cannot yield before completing the compiler-issued boundary"
        );
        assert!(authorize_lead_slice_operation(&mut state, "start", Some("TK-b")).is_err());
        assert!(authorize_lead_slice_operation(&mut state, "spawn-worker", Some("TK-a")).is_err());

        for ticket in ["TK-a", "TK-b"] {
            authorize_lead_slice_operation(&mut state, "start", Some(ticket)).unwrap();
            authorize_lead_slice_operation(&mut state, "spawn-worker", Some(ticket)).unwrap();
        }
        assert_eq!(state.boundaries_completed, 1);
        validate_lead_yield_reason(&state, "boundary-complete", true, false).unwrap();
        assert!(authorize_lead_slice_operation(&mut state, "start", Some("TK-a")).is_err());
        assert!(validate_lead_yield_reason(&state, "paused", true, false).is_err());
        assert!(validate_lead_yield_reason(&state, "question", true, true).is_err());
    }

    #[test]
    fn pause_question_and_boundary_yields_cannot_masquerade_for_each_other() {
        let mut state = bounded_test_lead_slice(LeadSliceBoundary::Recover);
        assert!(validate_lead_yield_reason(&state, "boundary-complete", true, false).is_err());
        assert!(validate_lead_yield_reason(&state, "paused", true, false).is_err());
        assert!(validate_lead_yield_reason(&state, "paused", false, false).is_ok());
        assert!(validate_lead_yield_reason(&state, "question", true, false).is_err());
        assert!(validate_lead_yield_reason(&state, "question", true, true).is_err());
        state.boundaries_completed = 1;
        assert!(validate_lead_yield_reason(&state, "boundary-complete", true, false).is_ok());
    }

    #[test]
    fn supervisor_respawn_requires_matching_yield_and_zero_exit() {
        let mut state = bounded_test_lead_slice(LeadSliceBoundary::Recover);
        let success = bounded_test_raw_agent("completed", Some(0));
        let failure = bounded_test_raw_agent("failed", Some(1));
        assert!(!lead_slice_exit_allows_respawn(&state, Some(&success)));
        state.status = LeadSliceStatus::Yielded;
        assert!(lead_slice_exit_allows_respawn(&state, Some(&success)));
        assert!(!lead_slice_exit_allows_respawn(&state, Some(&failure)));
        assert!(!lead_slice_exit_allows_respawn(&state, None));
    }

    #[test]
    fn lead_slice_history_preserves_fresh_generations_and_session_bindings() {
        let temp = tempfile::tempdir().unwrap();
        let control = RunControlStore::new(temp.path().to_path_buf());
        let mut first = bounded_test_lead_slice(LeadSliceBoundary::Recover);
        first.status = LeadSliceStatus::Yielded;
        first.yield_reason = Some("boundary-complete".to_owned());
        first.boundaries_completed = 1;
        control.write_lead_slice(&first).unwrap();

        let mut second = bounded_test_lead_slice(LeadSliceBoundary::WaitWorkers {
            tickets: vec!["TK-a".to_owned()],
        });
        second.generation = 2;
        second.raw_agent_id = Some("worker-second".to_owned());
        second.token_hash = normalized_hash(&"different-secret");
        control.write_lead_slice(&second).unwrap();

        let history = control.lead_slices().unwrap();
        assert_eq!(
            history
                .iter()
                .map(|slice| slice.generation)
                .collect::<Vec<_>>(),
            [1, 2]
        );
        assert_ne!(history[0].raw_agent_id, history[1].raw_agent_id);
        assert_ne!(history[0].token_hash, history[1].token_hash);
        assert_eq!(control.lead_slice().unwrap(), Some(second));
    }

