    #[test]
    fn compact_worker_boundaries_follow_configured_workflow_without_internal_ids() {
        let completed = worker_projection_ticket(true);
        let completed_progress = ticket_workflow_progress(&completed, &[], None);
        let outcome =
            completed_worker_wait_outcome(&completed.id, &completed, &completed_progress, "done");
        assert_eq!(outcome.state, WorkerWaitState::StepCompleted);
        assert_eq!(outcome.next, WorkerNextBoundary::RecoverThenStartWorker);
        assert!(outcome.message.contains("koni recover --root ."));
        assert!(outcome.message.contains("no ticket argument"));

        let failed = worker_projection_ticket(false);
        let failed_progress = ticket_workflow_progress(&failed, &[], None);
        let outcome = completed_worker_wait_outcome(&failed.id, &failed, &failed_progress, "done");
        assert_eq!(outcome.state, WorkerWaitState::ExitedBeforeOutput);
        assert_eq!(outcome.next, WorkerNextBoundary::RecoverThenRetryWorker);
        assert!(outcome.message.contains("koni recover --root ."));

        let serialized = serde_json::to_string(&outcome).unwrap();
        assert!(!serialized.contains("999999"));
        assert!(!serialized.contains("produce"));
        assert!(!serialized.contains("worker_pid"));
        assert!(serialized.contains("TK-test"));
    }

    #[test]
    fn compact_worker_boundaries_distinguish_review_finish_and_blocked() {
        let mut ticket = worker_projection_ticket(true);
        ticket.lease.as_mut().unwrap().worker_pid = None;
        ticket.extensions.remove("active_worker");
        ticket.outputs.push(
            serde_json::from_value(json!({
                "id": "output-2",
                "step_id": "integrate",
                "persona": "integrator",
                "context_hash": "ctx-integrate",
                "recorded_at": "2026-07-10T12:02:00Z"
            }))
            .unwrap(),
        );
        ticket.workflow.push(
            serde_json::from_value(json!({
                "id": "review",
                "persona": "reviewer",
                "depends_on": ["integrate"],
                "kind": "review",
                "context_hash": "ctx-review"
            }))
            .unwrap(),
        );
        let progress = ticket_workflow_progress(&ticket, &[], None);
        let review = idle_ticket_wait_outcome(&ticket.id, &ticket, &progress, "done");
        assert_eq!(review.state, WorkerWaitState::ReviewReady);
        assert_eq!(review.next, WorkerNextBoundary::Review);

        let reviewed_output_hash = normalized_hash(&ticket.outputs);
        ticket.reviews.push(Review {
            id: "review-record".to_owned(),
            status: "passed".to_owned(),
            notes: "Current evidence passed.".to_owned(),
            reviewed_at: Utc::now(),
            ticket_hash: "sha256:ticket".to_owned(),
            output_hash: reviewed_output_hash,
            agent_binding: Some(ReviewAgentBinding {
                agent_id: "review-agent".to_owned(),
                step_id: "review".to_owned(),
                persona: "reviewer".to_owned(),
                input_hash: "sha256:input".to_owned(),
                output_hash: "sha256:review-output".to_owned(),
                findings: vec!["No blocking findings.".to_owned()],
                evidence_pointers: vec!["ticket output".to_owned()],
                review_effects_hash: None,
                review_effects: None,
                post_effect_graph_hash: None,
            }),
        });
        let progress = ticket_workflow_progress(&ticket, &[], None);
        let finish = idle_ticket_wait_outcome(&ticket.id, &ticket, &progress, "done");
        assert_eq!(finish.state, WorkerWaitState::FinishReady);
        assert_eq!(finish.next, WorkerNextBoundary::Finish);

        ticket.blockers.push(Blocker {
            kind: "test".to_owned(),
            message: "Needs a decision.".to_owned(),
            created_at: Utc::now(),
            related_ticket: None,
        });
        let blocked = idle_ticket_wait_outcome(&ticket.id, &ticket, &progress, "done");
        assert_eq!(blocked.state, WorkerWaitState::Blocked);
        assert_eq!(blocked.next, WorkerNextBoundary::Stop);
    }

    fn worker_projection_ticket(with_output: bool) -> Ticket {
        let outputs = if with_output {
            json!([{
                "id": "output-1",
                "step_id": "produce",
                "persona": "worker",
                "context_hash": "ctx-produce",
                "recorded_at": "2026-07-10T12:01:00Z"
            }])
        } else {
            json!([])
        };
        serde_json::from_value(json!({
            "schema_version": "1.0",
            "id": "TK-test",
            "operation": "test",
            "status": "in_progress",
            "title": "test ticket",
            "source_state_key": "before",
            "target_state_key": "after",
            "profile_hash": "sha256:test",
            "rule_id": "test.rule",
            "workflow": [
                {
                    "id": "produce",
                    "persona": "worker",
                    "context_hash": "ctx-produce"
                },
                {
                    "id": "integrate",
                    "persona": "integrator",
                    "depends_on": ["produce"],
                    "kind": "integration",
                    "context_hash": "ctx-integrate"
                }
            ],
            "outputs": outputs,
            "lease": {
                "id": "lease-1",
                "branch": "koni/ticket/TK-test",
                "worktree": "/tmp/nonexistent-ticket-worktree",
                "base_commit": "0000000000000000000000000000000000000000",
                "started_at": "2026-07-10T12:00:00Z",
                "heartbeat_at": "2026-07-10T12:00:00Z",
                "worker_pid": 999999
            },
            "extensions": {
                "active_worker": {
                    "persona": "worker",
                    "pid": 999999,
                    "step": "produce"
                }
            }
        }))
        .expect("test ticket deserializes")
    }

