    #[cfg(unix)]
    #[test]
    fn question_resume_waiter_reaps_child_and_persists_exit() {
        let temp = tempfile::TempDir::new().unwrap();
        let control = RunControlStore::new(temp.path().join("control"));
        let mut command = Command::new("sh");
        command.args(["-c", "sleep 0.2; exit 7"]);
        isolate_agent_process_group(&mut command);
        let child = command.spawn().unwrap();
        let pid = child.id();
        let identity = capture_owned_agent_process_identity(pid).unwrap();
        let now = Utc::now();
        control
            .write_agent(&AgentSessionRecord {
                schema_version: "1.0".to_owned(),
                id: "question-resume-test".to_owned(),
                run_id: "run-test".to_owned(),
                ticket_id: None,
                stage_id: None,
                persona: "question-resume".to_owned(),
                model: None,
                reasoning_effort: None,
                status: "running".to_owned(),
                attempt: 1,
                codex_session_id: Some("session-test".to_owned()),
                pid: Some(pid),
                process_identity: Some(identity.clone()),
                working_directory: None,
                prompt_path: None,
                stdout_path: None,
                stderr_path: None,
                output_path: None,
                output_hash: None,
                input_hash: Some("sha256:test".to_owned()),
                result: Some(json!({"question_id": "question-test"})),
                exit_code: None,
                timed_out: false,
                started_at: Some(now),
                finished_at: None,
                updated_at: now,
            })
            .unwrap();

        reap_question_resume_process(
            child,
            control.clone(),
            "question-resume-test".to_owned(),
            1,
            identity,
            None,
        );

        let deadline = std::time::Instant::now() + std::time::Duration::from_secs(2);
        let finished = loop {
            let agent = control.agent("question-resume-test").unwrap().unwrap();
            if agent.status != "running" {
                break agent;
            }
            assert!(
                std::time::Instant::now() < deadline,
                "waiter did not finish"
            );
            std::thread::sleep(std::time::Duration::from_millis(10));
        };
        assert_eq!(finished.status, "failed");
        assert_eq!(finished.exit_code, Some(7));
        assert_eq!(finished.result.unwrap()["exit_code"], 7);
        assert!(finished.finished_at.is_some());
        assert!(capture_owned_agent_process_identity(pid).is_none());
    }

