    #[test]
    fn runtime_cleanup_preserves_product_logs_and_unrelated_staging() {
        let temp = tempfile::TempDir::new().unwrap();
        let root = temp.path();
        let repository = git2::Repository::init(root).unwrap();
        let runtime_log = Path::new("program/work/tickets/TK-test/worker.log");
        let product_log = Path::new("tickets/customer/worker.log");
        let staged_source = Path::new("src/lib.rs");
        for path in [runtime_log, product_log, staged_source] {
            fs::create_dir_all(root.join(path).parent().unwrap()).unwrap();
        }
        fs::write(root.join(runtime_log), "runtime\n").unwrap();
        fs::write(root.join(product_log), "product evidence\n").unwrap();
        fs::write(root.join(staged_source), "pub const VALUE: u8 = 1;\n").unwrap();

        let mut index = repository.index().unwrap();
        index
            .add_all(["*"], git2::IndexAddOption::DEFAULT, None)
            .unwrap();
        index.write().unwrap();
        let tree_id = index.write_tree().unwrap();
        let tree = repository.find_tree(tree_id).unwrap();
        let signature = git2::Signature::now("Koni Test", "koni-test@example.local").unwrap();
        repository
            .commit(Some("HEAD"), &signature, &signature, "initial", &tree, &[])
            .unwrap();
        drop(tree);

        fs::write(root.join(staged_source), "pub const VALUE: u8 = 2;\n").unwrap();
        let mut index = repository.index().unwrap();
        index.add_path(staged_source).unwrap();
        index.write().unwrap();
        let staged_source_oid = index.get_path(staged_source, 0).unwrap().id;

        let git = GitBackend::discover(root).unwrap();
        let exclude_path = git.common_dir().join("info/exclude");
        fs::write(
            &exclude_path,
            format!("{AGENT_RUNTIME_EXCLUDE_MARKER}\n**/worker.log\n**/worker.pid\n"),
        )
        .unwrap();
        let runtime_repo_path =
            agent_runtime_repo_path(&git, &root.join("program/work/tickets")).unwrap();
        assert_eq!(runtime_repo_path, Path::new("program/work/tickets"));
        ensure_agent_runtime_excludes(&git, Some(&runtime_repo_path)).unwrap();
        let (removed, cleanup_commit, _) =
            cleanup_agent_runtime_artifacts(&repository, Some(&runtime_repo_path)).unwrap();

        assert_eq!(removed, vec![runtime_log.to_path_buf()]);
        assert!(cleanup_commit.is_some());
        let head = repository.head().unwrap().peel_to_commit().unwrap();
        let head_tree = head.tree().unwrap();
        assert!(head_tree.get_path(runtime_log).is_err());
        assert!(head_tree.get_path(product_log).is_ok());

        let index = repository.index().unwrap();
        assert_eq!(
            index.get_path(staged_source, 0).unwrap().id,
            staged_source_oid,
            "recovery must preserve an unrelated staged edit"
        );
        assert!(index.get_path(product_log, 0).is_some());
        assert!(index.get_path(runtime_log, 0).is_none());
        assert_ne!(
            head_tree.get_path(staged_source).unwrap().id(),
            staged_source_oid,
            "the preserved edit must remain staged relative to the cleanup commit"
        );
        assert!(
            repository
                .status_file(staged_source)
                .unwrap()
                .contains(git2::Status::INDEX_MODIFIED)
        );

        let excludes = fs::read_to_string(exclude_path).unwrap();
        assert!(!excludes.lines().any(|line| line == "**/worker.log"));
        assert!(!excludes.lines().any(|line| line == "**/worker.pid"));
        assert!(
            excludes
                .lines()
                .any(|line| line == "/program/work/tickets/**/worker.log")
        );

        let untracked_product_log = Path::new("tickets/new/worker.log");
        fs::create_dir_all(root.join(untracked_product_log).parent().unwrap()).unwrap();
        fs::write(root.join(untracked_product_log), "visible product log\n").unwrap();
        let mut options = git2::StatusOptions::new();
        options.include_untracked(true).recurse_untracked_dirs(true);
        let statuses = repository.statuses(Some(&mut options)).unwrap();
        assert!(statuses.iter().any(|entry| {
            entry.path().ok() == untracked_product_log.to_str()
                && entry.status().contains(git2::Status::WT_NEW)
        }));
    }

    #[test]
    fn engine_repair_request_helpers_are_idempotent_and_reconcile_changed_head() {
        const BASE: &str = "1111111111111111111111111111111111111111";
        const CHANGED: &str = "2222222222222222222222222222222222222222";
        let at = |second| {
            Utc.with_ymd_and_hms(2026, 7, 10, 12, 0, 0).unwrap() + Duration::seconds(second)
        };
        let config = ExternalLoopConfig::from_yaml(
            r#"
schema_version: "1.0"
id: review
github:
  repository: owner/repo
  base_branch: main
  pull_request: 42
ci:
  required_checks: [test]
repair: {}
iterations:
  max_iterations: 3
  max_repairs_per_iteration: 2
timeouts:
  total_seconds: 600
  prepare_seconds: 30
  publish_seconds: 30
  wait_seconds: 120
  collect_seconds: 30
  repair_seconds: 120
  verify_seconds: 30
  poll_interval_seconds: 10
"#,
        )
        .unwrap();
        let mut state = ExternalLoopState::new("review", &config, at(0)).unwrap();
        state
            .advance(&config, ExternalLoopPhase::Publish, "prepared", at(1))
            .unwrap();
        state
            .record_publication(
                &config,
                crate::external_loop::GitHubPublication {
                    head_sha: BASE.to_owned(),
                    pull_request: 42,
                    url: "https://example.test/pr/42".to_owned(),
                    published_at: at(2),
                },
            )
            .unwrap();
        state
            .advance(&config, ExternalLoopPhase::Wait, "published", at(3))
            .unwrap();
        state
            .advance(&config, ExternalLoopPhase::Collect, "ready", at(4))
            .unwrap();
        state
            .record_collection(
                &config,
                crate::external_loop::ExternalCollection {
                    head_sha: BASE.to_owned(),
                    checks: crate::external_loop::parse_gh_check_buckets(
                        r#"[{"name":"test","bucket":"fail","state":"FAILURE"}]"#,
                    )
                    .unwrap(),
                    greptile: None,
                    collected_at: at(5),
                },
            )
            .unwrap();
        state
            .advance(&config, ExternalLoopPhase::Repair, "test failed", at(6))
            .unwrap();

        let temp = tempfile::tempdir().unwrap();
        let control = RunControlStore::new(temp.path().to_path_buf());
        let (request, created) =
            ensure_external_repair_request(&control, "run-1", &config, &state, at(7)).unwrap();
        assert!(created);
        let (same, created) =
            ensure_external_repair_request(&control, "run-1", &config, &state, at(8)).unwrap();
        assert!(!created);
        assert_eq!(same.id, request.id);

        state
            .record_repair(
                &config,
                crate::external_loop::ExternalRepairRecord {
                    base_head_sha: BASE.to_owned(),
                    result_head_sha: CHANGED.to_owned(),
                    change_hash: normalized_hash(&(BASE, CHANGED)),
                    summary: "repair committed".to_owned(),
                    repaired_at: at(9),
                },
            )
            .unwrap();
        state
            .advance(&config, ExternalLoopPhase::Republish, "repair ready", at(9))
            .unwrap();
        let reconciled = reconcile_external_repair_request(&control, &state)
            .unwrap()
            .unwrap();
        assert_eq!(
            reconciled.status,
            crate::external_loop::ExternalRepairRequestStatus::HeadChanged
        );
        assert_eq!(reconciled.result_head_sha.as_deref(), Some(CHANGED));
        assert_eq!(
            control
                .external_repair_request("review", &request.id)
                .unwrap(),
            reconciled
        );
    }
